INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'An investor buys a stock at $50, receives a dividend of $2, and sells at $55. The holding period return is closest to:', '14.00%', '10.00%', '4.00%', 'A', 'HPR = (P1 - P0 + D) / P0 = (55 - 50 + 2) / 50 = 14.00%', 2, 'qbank');
