INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'Which return measure is most appropriate for evaluating the performance of a fund manager?', 'Time-weighted return', 'Money-weighted return', 'Arithmetic mean return', 'A', 'Time-weighted return removes the effect of cash flow timing, making it appropriate for evaluating manager performance.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'The money-weighted rate of return is equivalent to:', 'The internal rate of return on the investment', 'The geometric mean of periodic returns', 'The arithmetic mean of periodic returns', 'A', 'The money-weighted return is the IRR that equates the present value of cash inflows with outflows.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'Which return measure gives greater weight to periods with larger amounts invested?', 'Money-weighted return', 'Time-weighted return', 'Geometric mean return', 'A', 'Money-weighted return is affected by the timing and amount of cash flows.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'Gross return differs from net return by the amount of:', 'Management and administrative fees', 'Taxes only', 'Inflation adjustment', 'A', 'Net return = Gross return minus management fees, administrative costs, and other expenses.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'A bank quotes a rate of 6% compounded monthly. The effective annual rate is closest to:', '6.17%', '6.00%', '6.50%', 'A', 'EAR = (1 + 0.06/12)^12 - 1 = 6.17%', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'Which measure of return best reflects the compound rate of growth of an investment over time?', 'Geometric mean return', 'Arithmetic mean return', 'Harmonic mean return', 'A', 'The geometric mean captures the compound growth effect over multiple periods.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'The discount rate that makes the net present value of all cash flows equal to zero is the:', 'Money-weighted rate of return', 'Time-weighted rate of return', 'Risk-free rate', 'A', 'By definition, the money-weighted return (IRR) sets NPV of all cash flows to zero.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'A quoted annual rate of 8% with quarterly compounding gives an effective annual rate closest to:', '8.24%', '8.00%', '8.16%', 'A', 'EAR = (1 + 0.08/4)^4 - 1 = 8.24%', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'When comparing mutual fund managers, which return metric is most appropriate?', 'Time-weighted return', 'Dollar-weighted return', 'Holding period return', 'A', 'Time-weighted return neutralizes the impact of external cash flows that the manager cannot control.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'A leveraged return is calculated by:', 'Adjusting the return for the proportion of borrowed funds', 'Dividing the return by the leverage ratio', 'Multiplying gross return by the debt-to-equity ratio', 'A', 'Leveraged return accounts for the amplification effect of using borrowed capital.', 3, 'qbank');
