INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'An investment earns 10% over 9 months. The effective annualized return is closest to:', '13.55%', '13.33%', '13.33%', 'A', 'EAR = (1 + 0.1)^(12/9) - 1 = 13.55%', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'An investment has returns of 15%, -3%, and 10% over three years. The geometric mean return is closest to:', '7.06%', '7.33%', '7.20%', 'A', 'Geometric mean = [(1+0.15)*(1+-0.03)*(1+0.1)]^(1/3) - 1 = 7.06%', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'If the holding period return is 9%, the equivalent continuously compounded return is closest to:', '8.62%', '8.55%', '9.45%', 'A', 'Continuously compounded return = ln(1 + 0.09) = 8.62%', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'An investment earns a nominal return of 9% when inflation is 4%. The real return is closest to:', '4.81%', '5.0%', '8.65%', 'A', 'Real return = (1+0.09)/(1+0.04) - 1 = 4.81%', 2, 'mock');
