INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'Which measure of return best reflects the compound rate of growth of an investment over time?', 'Geometric mean return', 'Arithmetic mean return', 'Harmonic mean return', 'A', 'The geometric mean captures the compound growth effect over multiple periods.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (1, 'An investor buys a stock at $150, receives a dividend of $6, and sells at $162. The holding period return is closest to:', '12.00%', '8.00%', '4.00%', 'A', 'HPR = (P1 - P0 + D) / P0 = (162 - 150 + 6) / 150 = 12.00%', 2, 'mock');
