INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'An annuity due differs from an ordinary annuity in that payments are made:', 'At the beginning of each period', 'At the end of each period', 'At the midpoint of each period', 'A', 'Annuity due payments occur at the start of each period, ordinary annuity at the end.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'All else equal, as the compounding frequency increases, the effective annual rate:', 'Increases', 'Decreases', 'Remains unchanged', 'A', 'More frequent compounding increases the EAR for a given stated annual rate.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'The present value of a growing perpetuity with payment C, growth rate g, and discount rate r is:', 'C / (r - g)', 'C / r', 'C × (1+g) / r', 'A', 'PV of growing perpetuity = C / (r - g), where r > g.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'If interest rates decrease, the present value of a fixed future cash flow will:', 'Increase', 'Decrease', 'Remain unchanged', 'A', 'Lower discount rates increase the present value of future cash flows.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'The future value of an annuity due is equal to the future value of an ordinary annuity multiplied by:', '(1 + r)', 'r', '(1 - r)', 'A', 'FV annuity due = FV ordinary annuity × (1 + r), because each payment compounds one extra period.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'Which type of cash flow stream has no definite end?', 'Perpetuity', 'Annuity', 'Lump sum', 'A', 'A perpetuity is an infinite series of equal periodic payments.', 1, 'qbank');
