INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'Which of the following is most accurate? an annuity due differs from an ordinary annuity in that payments are made:', 'At the end of each period', 'At the midpoint of each period', 'At the beginning of each period', 'C', 'Annuity due payments occur at the start of each period, ordinary annuity at the end.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'An analyst is evaluating a scenario. all else equal, as the compounding frequency increases, the effective annual rate:', 'Remains unchanged', 'Increases', 'Decreases', 'B', 'More frequent compounding increases the EAR for a given stated annual rate.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'According to CFA curriculum, the present value of a growing perpetuity with payment C, growth rate g, and discount rate r is:', 'C / r', 'C / (r - g)', 'C × (1+g) / r', 'B', 'PV of growing perpetuity = C / (r - g), where r > g.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'In the context of CFA Level I, if interest rates decrease, the present value of a fixed future cash flow will:', 'Remain unchanged', 'Increase', 'Decrease', 'B', 'Lower discount rates increase the present value of future cash flows.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'A financial analyst needs to determine: the future value of an annuity due is equal to the future value of an ordinary annuity multiplied by:', '(1 - r)', 'r', '(1 + r)', 'C', 'FV annuity due = FV ordinary annuity × (1 + r), because each payment compounds one extra period.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'Which of the following is most accurate? which type of cash flow stream has no definite end?', 'Lump sum', 'Perpetuity', 'Annuity', 'B', 'A perpetuity is an infinite series of equal periodic payments.', 2, 'qbank');
