INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'The present value of $7,000 to be received in 4 years at a discount rate of 11% is closest to:', '$4,611.12', '$4,861.11', '$3,920.00', 'A', 'PV = FV / (1+r)^n = 7000 / (1+0.11)^4 = $4,611.12', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'The future value of $2,000 invested at 6% compounded annually for 3 years is closest to:', '$2,382.03', '$2,360.00', '$6,360.00', 'A', 'FV = PV × (1+r)^n = 2000 × (1+0.06)^3 = $2,382.03', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'An ordinary annuity pays $3,000 per year for 7 years. At a discount rate of 5%, the present value is closest to:', '$17,359.12', '$21,000.00', '$20,000.00', 'A', 'PV annuity = PMT × [(1-(1+r)^-n)/r] = 3000 × [(1-(1+0.05)^-7)/0.05] = $17,359.12', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'Which type of cash flow stream has no definite end?', 'Perpetuity', 'Annuity', 'Lump sum', 'A', 'A perpetuity is an infinite series of equal periodic payments.', 1, 'mock');
