INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'An analyst is evaluating a scenario. an ordinary annuity pays $800 per year for 25 years. At a discount rate of 3%, the present value is closest to:', '$19,417.48', '$20,000.00', '$13,930.52', 'C', 'PV annuity = PMT × [(1-(1+r)^-n)/r] = 800 × [(1-(1+0.03)^-25)/0.03] = $13,930.52', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'According to CFA curriculum, an ordinary annuity pays $300 per year for 30 years. At a discount rate of 4%, the present value is closest to:', '$8,653.85', '$9,000.00', '$5,187.61', 'C', 'PV annuity = PMT × [(1-(1+r)^-n)/r] = 300 × [(1-(1+0.04)^-30)/0.04] = $5,187.61', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'In the context of CFA Level I, a stated rate of 12% compounded monthly is equivalent to a monthly rate of:', '0.12%', '1.00%', '1.12%', 'B', 'Monthly rate = 12% / 12 = 1.00%.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'A financial analyst needs to determine: an ordinary annuity pays $500 per year for 20 years. At a discount rate of 8%, the present value is closest to:', '$9,259.26', '$4,909.07', '$10,000.00', 'B', 'PV annuity = PMT × [(1-(1+r)^-n)/r] = 500 × [(1-(1+0.08)^-20)/0.08] = $4,909.07', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'Which of the following is most accurate? a perpetuity pays $50 per year. If the required return is 2%, the present value is closest to:', '$2,625.00', '$1,666.67', '$2,500.00', 'C', 'PV perpetuity = PMT / r = 50 / 0.02 = $2,500.00', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'An analyst is evaluating a scenario. the present value of $15,000 to be received in 6 years at a discount rate of 9% is closest to:', '$6,900.00', '$9,740.26', '$8,944.01', 'C', 'PV = FV / (1+r)^n = 15000 / (1+0.09)^6 = $8,944.01', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'According to CFA curriculum, if interest rates decrease, the present value of a fixed future cash flow will:', 'Decrease', 'Remain unchanged', 'Increase', 'C', 'Lower discount rates increase the present value of future cash flows.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'In the context of CFA Level I, the future value of $500 invested at 10% compounded annually for 7 years is closest to:', '$974.36', '$3,850.00', '$850.00', 'A', 'FV = PV × (1+r)^n = 500 × (1+0.1)^7 = $974.36', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'A financial analyst needs to determine: the present value of $20,000 to be received in 15 years at a discount rate of 4% is closest to:', '$12,500.00', '$8,000.00', '$11,105.29', 'C', 'PV = FV / (1+r)^n = 20000 / (1+0.04)^15 = $11,105.29', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'Which of the following is most accurate? the present value of $25,000 to be received in 10 years at a discount rate of 6% is closest to:', '$13,959.87', '$15,625.00', '$10,000.00', 'A', 'PV = FV / (1+r)^n = 25000 / (1+0.06)^10 = $13,959.87', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'An analyst is evaluating a scenario. the present value of $8,000 to be received in 12 years at a discount rate of 3% is closest to:', '$5,120.00', '$5,611.04', '$5,882.35', 'B', 'PV = FV / (1+r)^n = 8000 / (1+0.03)^12 = $5,611.04', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'According to CFA curriculum, the future value of an annuity due is equal to the future value of an ordinary annuity multiplied by:', '(1 + r)', 'r', '(1 - r)', 'A', 'FV annuity due = FV ordinary annuity × (1 + r), because each payment compounds one extra period.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'In the context of CFA Level I, a perpetuity pays $100 per year. If the required return is 5%, the present value is closest to:', '$1,666.67', '$2,100.00', '$2,000.00', 'C', 'PV perpetuity = PMT / r = 100 / 0.05 = $2,000.00', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (2, 'A financial analyst needs to determine: all else equal, as the compounding frequency increases, the effective annual rate:', 'Increases', 'Decreases', 'Remains unchanged', 'A', 'More frequent compounding increases the EAR for a given stated annual rate.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'The arithmetic mean of 10%, -5%, and 15% is closest to:', '6.67%', '6.25%', '7.00%', 'A', 'Arithmetic mean = (10 + (-5) + 15) / 3 = 20/3 = 6.67%', 1, 'qbank');
