INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'Chebyshev''s inequality states that for any distribution, at least 75% of observations lie within:', '2 standard deviations of the mean', '1 standard deviation of the mean', '3 standard deviations of the mean', 'A', 'Chebyshev: at least 1 - 1/k^2 = 1 - 1/4 = 75% within 2 std devs.', 2, 'qbank');
