INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'In the context of CFA Level I, the weighted mean assigns:', 'Different weights to different observations', 'Zero weight to outliers', 'Equal weights to all observations', 'A', 'Weighted mean: each observation is multiplied by its weight.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'A financial analyst needs to determine: downside deviation measures:', 'Upside potential', 'Dispersion of returns below a target', 'Total variance', 'B', 'Downside deviation focuses only on negative deviations from a minimum threshold.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'Which of the following is most accurate? for a normal distribution, approximately 95% of observations fall within:', '1 standard deviation of the mean', '3 standard deviations of the mean', '1.96 standard deviations of the mean', 'C', 'The 95% confidence interval for a normal distribution is approximately +/- 1.96 sigma.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'An analyst is evaluating a scenario. the geometric mean is always:', 'Greater than the arithmetic mean', 'Less than or equal to the arithmetic mean', 'Equal to the arithmetic mean', 'B', 'By the AM-GM inequality, the geometric mean <= arithmetic mean, with equality only when all values are identical.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'According to CFA curriculum, the arithmetic mean of 10%, -5%, and 15% is closest to:', '6.25%', '6.67%', '7.00%', 'B', 'Arithmetic mean = (10 + (-5) + 15) / 3 = 20/3 = 6.67%', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'In the context of CFA Level I, the median of the dataset {3, 7, 1, 9, 5} is:', '3', '7', '5', 'C', 'Sorted: {1, 3, 5, 7, 9}. The middle value is 5.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'A financial analyst needs to determine: which measure of central tendency is most affected by extreme values?', 'Median', 'Arithmetic mean', 'Mode', 'B', 'The arithmetic mean is influenced by all values including outliers.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'Which of the following is most accurate? a distribution with a longer right tail has:', 'Zero skewness', 'Positive skewness', 'Negative skewness', 'B', 'A right-skewed distribution has a longer right tail and positive skewness.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'An analyst is evaluating a scenario. kurtosis measures:', 'The asymmetry of a distribution', 'The peakedness and tail weight of a distribution', 'The central tendency', 'B', 'Kurtosis captures the shape of the tails and peak relative to a normal distribution.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'According to CFA curriculum, excess kurtosis of a normal distribution is:', '0', '1', '3', 'A', 'Normal distribution has kurtosis of 3, so excess kurtosis = 3 - 3 = 0.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'In the context of CFA Level I, a leptokurtic distribution has:', 'Fatter tails than normal', 'Thinner tails than normal', 'The same tails as normal', 'A', 'Leptokurtic: excess kurtosis > 0, meaning fatter tails and more peaked.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'A financial analyst needs to determine: the coefficient of variation is calculated as:', 'Standard deviation / Mean', 'Mean / Standard deviation', 'Variance / Mean', 'A', 'CV = s / x-bar, measuring relative dispersion.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'Which of the following is most accurate? which measure is preferred when comparing dispersion of datasets with different units?', 'Variance', 'Coefficient of variation', 'Standard deviation', 'B', 'CV is unitless and allows comparison across different scales.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'An analyst is evaluating a scenario. the range is calculated as:', 'Maximum - Minimum', 'Mean - Median', 'Q3 - Q1', 'A', 'Range = Maximum value - Minimum value.', 1, 'qbank');
