INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'In the context of CFA Level I, the median of the dataset {12, 15, 11, 18, 14} is:', '14', '11', '18', 'A', 'Sorted: [11, 12, 14, 15, 18]. Median = 14', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'A financial analyst needs to determine: which measure is preferred when comparing dispersion of datasets with different units?', 'Coefficient of variation', 'Standard deviation', 'Variance', 'A', 'CV is unitless and allows comparison across different scales.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'Which of the following is most accurate? for a negatively skewed distribution, the relationship between mean, median, and mode is typically:', 'Mean > Median > Mode', 'Mean = Median = Mode', 'Mean < Median < Mode', 'C', 'In a negatively skewed distribution, the mean is pulled left by the long left tail.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'An analyst is evaluating a scenario. chebyshev''s inequality states that for any distribution, at least 75% of observations lie within:', '1 standard deviation of the mean', '2 standard deviations of the mean', '3 standard deviations of the mean', 'B', 'Chebyshev: at least 1 - 1/k^2 = 1 - 1/4 = 75% within 2 std devs.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'According to CFA curriculum, the sample standard deviation of {3, 3, 3, 3, 3} is closest to:', '0.00', '0.00', '0.00', 'A', 'Mean=3.0, Variance=0.00, Std Dev=0.00', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (3, 'In the context of CFA Level I, excess kurtosis of a normal distribution is:', '0', '1', '3', 'A', 'Normal distribution has kurtosis of 3, so excess kurtosis = 3 - 3 = 0.', 2, 'mock');
