INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'If P(A) = 0.3 and P(B) = 0.5, and A and B are independent, then P(A and B) is:', '0.15', '0.80', '0.20', 'A', 'P(A∩B) = P(A)×P(B) = 0.3×0.5 = 0.15 for independent events.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Bayes'' formula is used to:', 'Update probabilities given new information', 'Calculate joint probabilities', 'Determine independence', 'A', 'Bayes'' theorem revises prior probabilities using new evidence.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'The expected value of a random variable is:', 'The probability-weighted average of possible outcomes', 'The most likely outcome', 'The median outcome', 'A', 'E(X) = sum of [xi × P(xi)].', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'If P(A|B) = P(A), then events A and B are:', 'Independent', 'Mutually exclusive', 'Exhaustive', 'A', 'When conditioning on B doesn''t change A''s probability, they are independent.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Two events are mutually exclusive if:', 'They cannot occur simultaneously', 'They are independent', 'Their probabilities sum to 1', 'A', 'Mutually exclusive: P(A∩B) = 0.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'The total probability rule states that P(A) equals:', 'The sum of P(A|Bi)×P(Bi) for all mutually exclusive Bi', 'P(A|B) × P(B)', '1 - P(A complement)', 'A', 'Total probability: P(A) = Σ P(A|Bi)P(Bi) over all partitions.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'In a probability tree, each branch represents:', 'A conditional probability', 'A marginal probability', 'A joint probability', 'A', 'Branches show conditional probabilities; multiplying along paths gives joint probabilities.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'If P(A) = 0.6 and P(B|A) = 0.4, then P(A and B) is:', '0.24', '1.00', '0.40', 'A', 'P(A∩B) = P(B|A)×P(A) = 0.4×0.6 = 0.24.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'The complement of event A has probability:', '1 - P(A)', 'P(A)', 'P(A)²', 'A', 'P(A'') = 1 - P(A).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'A conditional expectation is:', 'The expected value given that a specific event has occurred', 'The unconditional mean', 'The variance of conditional outcomes', 'A', 'E(X|Y) conditions the expectation on Y having occurred.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'P(A or B) for non-mutually exclusive events equals:', 'P(A) + P(B) - P(A and B)', 'P(A) + P(B)', 'P(A) × P(B)', 'A', 'Addition rule: P(A∪B) = P(A) + P(B) - P(A∩B).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'If a portfolio has a 60% chance of earning 10% and 40% chance of earning -5%, the expected return is:', '4.0%', '5.0%', '2.5%', 'A', 'E(R) = 0.6×10% + 0.4×(-5%) = 6% - 2% = 4.0%.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'The covariance of a random variable with itself is:', 'Its variance', 'Its standard deviation', 'Zero', 'A', 'Cov(X,X) = Var(X).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'If the correlation between two assets is -1, the portfolio:', 'Can have zero risk if properly weighted', 'Has maximum risk', 'Has undefined risk', 'A', 'Perfect negative correlation allows complete diversification of risk.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'The variance of expected returns can be calculated as:', 'E(X²) - [E(X)]²', 'E(X)² - E(X²)', '[E(X)]²', 'A', 'Var(X) = E(X²) - [E(X)]².', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'A Bernoulli trial has:', 'Two possible outcomes', 'Multiple outcomes', 'A continuous distribution', 'A', 'Bernoulli: success or failure, with probability p and (1-p).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Given P(A) = 0.4, P(B) = 0.5, P(A|B) = 0.6, P(A and B) is:', '0.30', '0.20', '0.24', 'A', 'P(A∩B) = P(A|B)×P(B) = 0.6×0.5 = 0.30.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'The expected value operator is:', 'Linear', 'Non-linear', 'Undefined for discrete variables', 'A', 'E(aX+b) = aE(X)+b, demonstrating linearity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'If two events are exhaustive, their probabilities:', 'Sum to 1', 'Are equal', 'Sum to 0', 'A', 'Exhaustive events cover the entire sample space, so probabilities sum to 1.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'A joint probability table shows:', 'Probabilities of combinations of two events', 'Marginal probabilities only', 'Conditional probabilities only', 'A', 'Joint probability tables display P(A∩B) for all combinations.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Which of the following is most accurate? if P(A) = 0.3 and P(B) = 0.5, and A and B are independent, then P(A and B) is:', '0.20', '0.80', '0.15', 'C', 'P(A∩B) = P(A)×P(B) = 0.3×0.5 = 0.15 for independent events.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'An analyst is evaluating a scenario. bayes'' formula is used to:', 'Update probabilities given new information', 'Determine independence', 'Calculate joint probabilities', 'A', 'Bayes'' theorem revises prior probabilities using new evidence.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'According to CFA curriculum, the expected value of a random variable is:', 'The probability-weighted average of possible outcomes', 'The most likely outcome', 'The median outcome', 'A', 'E(X) = sum of [xi × P(xi)].', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'In the context of CFA Level I, if P(A|B) = P(A), then events A and B are:', 'Exhaustive', 'Mutually exclusive', 'Independent', 'C', 'When conditioning on B doesn''t change A''s probability, they are independent.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'A financial analyst needs to determine: two events are mutually exclusive if:', 'Their probabilities sum to 1', 'They are independent', 'They cannot occur simultaneously', 'C', 'Mutually exclusive: P(A∩B) = 0.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Which of the following is most accurate? the total probability rule states that P(A) equals:', 'The sum of P(A|Bi)×P(Bi) for all mutually exclusive Bi', '1 - P(A complement)', 'P(A|B) × P(B)', 'A', 'Total probability: P(A) = Σ P(A|Bi)P(Bi) over all partitions.', 4, 'qbank');
