INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'A financial analyst needs to determine: a joint probability table shows:', 'Marginal probabilities only', 'Conditional probabilities only', 'Probabilities of combinations of two events', 'C', 'Joint probability tables display P(A∩B) for all combinations.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Which of the following is most accurate? if P(A) = 0.3 and P(B) = 0.5, and A and B are independent, then P(A and B) is:', '0.80', '0.15', '0.20', 'B', 'P(A∩B) = P(A)×P(B) = 0.3×0.5 = 0.15 for independent events.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'An analyst is evaluating a scenario. bayes'' formula is used to:', 'Update probabilities given new information', 'Calculate joint probabilities', 'Determine independence', 'A', 'Bayes'' theorem revises prior probabilities using new evidence.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'According to CFA curriculum, the expected value of a random variable is:', 'The probability-weighted average of possible outcomes', 'The median outcome', 'The most likely outcome', 'A', 'E(X) = sum of [xi × P(xi)].', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'In the context of CFA Level I, if P(A|B) = P(A), then events A and B are:', 'Mutually exclusive', 'Exhaustive', 'Independent', 'C', 'When conditioning on B doesn''t change A''s probability, they are independent.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'A financial analyst needs to determine: two events are mutually exclusive if:', 'Their probabilities sum to 1', 'They cannot occur simultaneously', 'They are independent', 'B', 'Mutually exclusive: P(A∩B) = 0.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Which of the following is most accurate? the total probability rule states that P(A) equals:', 'P(A|B) × P(B)', '1 - P(A complement)', 'The sum of P(A|Bi)×P(Bi) for all mutually exclusive Bi', 'C', 'Total probability: P(A) = Σ P(A|Bi)P(Bi) over all partitions.', 4, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'An analyst is evaluating a scenario. in a probability tree, each branch represents:', 'A marginal probability', 'A conditional probability', 'A joint probability', 'B', 'Branches show conditional probabilities; multiplying along paths gives joint probabilities.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'According to CFA curriculum, if P(A) = 0.6 and P(B|A) = 0.4, then P(A and B) is:', '1.00', '0.24', '0.40', 'B', 'P(A∩B) = P(B|A)×P(A) = 0.4×0.6 = 0.24.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'In the context of CFA Level I, the complement of event A has probability:', '1 - P(A)', 'P(A)²', 'P(A)', 'A', 'P(A'') = 1 - P(A).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'A financial analyst needs to determine: a conditional expectation is:', 'The expected value given that a specific event has occurred', 'The variance of conditional outcomes', 'The unconditional mean', 'A', 'E(X|Y) conditions the expectation on Y having occurred.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Which of the following is most accurate? p(A or B) for non-mutually exclusive events equals:', 'P(A) × P(B)', 'P(A) + P(B)', 'P(A) + P(B) - P(A and B)', 'C', 'Addition rule: P(A∪B) = P(A) + P(B) - P(A∩B).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'An analyst is evaluating a scenario. if a portfolio has a 60% chance of earning 10% and 40% chance of earning -5%, the expected return is:', '2.5%', '5.0%', '4.0%', 'C', 'E(R) = 0.6×10% + 0.4×(-5%) = 6% - 2% = 4.0%.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'According to CFA curriculum, the covariance of a random variable with itself is:', 'Zero', 'Its variance', 'Its standard deviation', 'B', 'Cov(X,X) = Var(X).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'In the context of CFA Level I, if the correlation between two assets is -1, the portfolio:', 'Has maximum risk', 'Has undefined risk', 'Can have zero risk if properly weighted', 'C', 'Perfect negative correlation allows complete diversification of risk.', 2, 'qbank');
