INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'According to CFA curriculum, two events are mutually exclusive if:', 'Their probabilities sum to 1', 'They cannot occur simultaneously', 'They are independent', 'B', 'Mutually exclusive: P(A∩B) = 0.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'In the context of CFA Level I, if a portfolio has a 60% chance of earning 10% and 40% chance of earning -5%, the expected return is:', '4.0%', '5.0%', '2.5%', 'A', 'E(R) = 0.6×10% + 0.4×(-5%) = 6% - 2% = 4.0%.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'A financial analyst needs to determine: a conditional expectation is:', 'The unconditional mean', 'The expected value given that a specific event has occurred', 'The variance of conditional outcomes', 'B', 'E(X|Y) conditions the expectation on Y having occurred.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Which of the following is most accurate? a joint probability table shows:', 'Marginal probabilities only', 'Conditional probabilities only', 'Probabilities of combinations of two events', 'C', 'Joint probability tables display P(A∩B) for all combinations.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'An analyst is evaluating a scenario. the total probability rule states that P(A) equals:', 'The sum of P(A|Bi)×P(Bi) for all mutually exclusive Bi', '1 - P(A complement)', 'P(A|B) × P(B)', 'A', 'Total probability: P(A) = Σ P(A|Bi)P(Bi) over all partitions.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'According to CFA curriculum, if P(A) = 0.6 and P(B|A) = 0.4, then P(A and B) is:', '0.24', '1.00', '0.40', 'A', 'P(A∩B) = P(B|A)×P(A) = 0.4×0.6 = 0.24.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'In the context of CFA Level I, p(A or B) for non-mutually exclusive events equals:', 'P(A) + P(B) - P(A and B)', 'P(A) + P(B)', 'P(A) × P(B)', 'A', 'Addition rule: P(A∪B) = P(A) + P(B) - P(A∩B).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'A financial analyst needs to determine: the covariance of a random variable with itself is:', 'Zero', 'Its variance', 'Its standard deviation', 'B', 'Cov(X,X) = Var(X).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Which of the following is most accurate? the expected value of a random variable is:', 'The probability-weighted average of possible outcomes', 'The most likely outcome', 'The median outcome', 'A', 'E(X) = sum of [xi × P(xi)].', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'An analyst is evaluating a scenario. if two events are exhaustive, their probabilities:', 'Are equal', 'Sum to 1', 'Sum to 0', 'B', 'Exhaustive events cover the entire sample space, so probabilities sum to 1.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'According to CFA curriculum, the variance of expected returns can be calculated as:', 'E(X)² - E(X²)', 'E(X²) - [E(X)]²', '[E(X)]²', 'B', 'Var(X) = E(X²) - [E(X)]².', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'In the context of CFA Level I, bayes'' formula is used to:', 'Update probabilities given new information', 'Determine independence', 'Calculate joint probabilities', 'A', 'Bayes'' theorem revises prior probabilities using new evidence.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'A financial analyst needs to determine: the expected value operator is:', 'Linear', 'Non-linear', 'Undefined for discrete variables', 'A', 'E(aX+b) = aE(X)+b, demonstrating linearity.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'Which of the following is most accurate? if the correlation between two assets is -1, the portfolio:', 'Can have zero risk if properly weighted', 'Has maximum risk', 'Has undefined risk', 'A', 'Perfect negative correlation allows complete diversification of risk.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (4, 'An analyst is evaluating a scenario. given P(A) = 0.4, P(B) = 0.5, P(A|B) = 0.6, P(A and B) is:', '0.30', '0.24', '0.20', 'A', 'P(A∩B) = P(A|B)×P(B) = 0.6×0.5 = 0.30.', 2, 'mock');
