INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The expected return of a two-asset portfolio is:', 'The weighted average of the individual expected returns', 'The product of individual returns', 'The simple average of returns', 'A', 'E(Rp) = w1×E(R1) + w2×E(R2).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Portfolio variance depends on:', 'Individual variances, covariances, and weights', 'Only individual variances', 'Only covariances', 'A', 'σ²p = w1²σ1² + w2²σ2² + 2w1w2Cov(R1,R2).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Diversification benefits are greatest when the correlation between assets is:', 'Negative', 'Positive', 'Zero', 'A', 'Lower correlation = greater risk reduction from diversification.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'If correlation between two assets is +1, the portfolio standard deviation is:', 'The weighted average of individual standard deviations', 'Less than the weighted average', 'Zero', 'A', 'With perfect positive correlation, σp = w1σ1 + w2σ2.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Covariance can range from:', 'Negative infinity to positive infinity', '0 to 1', '-1 to +1', 'A', 'Covariance is unbounded, unlike correlation which is bounded [-1, +1].', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The correlation coefficient is calculated as:', 'Covariance divided by the product of standard deviations', 'Covariance times variance', 'Standard deviation divided by mean', 'A', 'ρ = Cov(X,Y) / (σx × σy).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'For an equally-weighted portfolio of n assets, as n increases, portfolio variance approaches:', 'The average covariance', 'Zero', 'The average variance', 'A', 'As n→∞, portfolio variance → average covariance (systematic risk).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A portfolio with 60% in Asset A (E(R)=10%) and 40% in Asset B (E(R)=5%) has an expected return of:', '8.0%', '7.5%', '7.0%', 'A', 'E(Rp) = 0.6×10% + 0.4×5% = 8.0%.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The minimum variance portfolio is the portfolio with:', 'The lowest possible variance for given assets', 'Zero return', 'Equal weights in all assets', 'A', 'The minimum variance portfolio minimizes risk regardless of return.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Adding a risk-free asset to a risky portfolio creates:', 'The Capital Allocation Line', 'The Security Market Line', 'The efficient frontier', 'A', 'Combining risk-free and risky assets produces the CAL.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Shortfall risk is the probability that:', 'Portfolio return falls below a minimum threshold', 'Portfolio value exceeds a maximum', 'Returns are normally distributed', 'A', 'Shortfall risk = P(Rp < Rtarget).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Roy''s safety-first criterion maximizes:', '(Expected return - Threshold return) / Standard deviation', 'Expected return only', 'Sharpe ratio', 'A', 'SFRatio = [E(Rp) - RL] / σp.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The Sharpe ratio measures:', 'Excess return per unit of total risk', 'Excess return per unit of systematic risk', 'Total return per unit of risk', 'A', 'Sharpe = (Rp - Rf) / σp.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'If the covariance between two assets is zero, they are:', 'Uncorrelated', 'Perfectly correlated', 'Mutually exclusive', 'A', 'Zero covariance implies zero correlation (uncorrelated).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The variance of a three-asset portfolio has how many covariance terms?', '3', '6', '9', 'A', 'For 3 assets: 3 unique pairs, each counted twice = 6, but 3 unique covariance terms in the formula.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Systematic risk is:', 'Non-diversifiable risk', 'Diversifiable risk', 'Total risk', 'A', 'Systematic risk affects all securities and cannot be diversified away.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The efficient frontier represents:', 'Portfolios with maximum return for each level of risk', 'All possible portfolios', 'Only minimum risk portfolios', 'A', 'Efficient frontier = set of optimal portfolios offering highest return per risk level.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A risk-averse investor prefers:', 'Lower risk for a given level of return', 'Higher risk for higher returns', 'Risk-neutral investments only', 'A', 'Risk-averse investors prefer the certainty equivalent and require risk premiums.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The portfolio variance of two uncorrelated assets (w1=0.5, σ1=10%, w2=0.5, σ2=20%) is closest to:', '1.25%', '2.50%', '0.50%', 'A', 'σ²p = (0.5)²(0.10)² + (0.5)²(0.20)² = 0.0025 + 0.01 = 0.0125 = 1.25%.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Increasing the number of assets in a portfolio reduces:', 'Unsystematic risk', 'Systematic risk', 'Total expected return', 'A', 'Diversification eliminates unsystematic (firm-specific) risk.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Which of the following is most accurate? the expected return of a two-asset portfolio is:', 'The simple average of returns', 'The product of individual returns', 'The weighted average of the individual expected returns', 'C', 'E(Rp) = w1×E(R1) + w2×E(R2).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'An analyst is evaluating a scenario. portfolio variance depends on:', 'Individual variances, covariances, and weights', 'Only covariances', 'Only individual variances', 'A', 'σ²p = w1²σ1² + w2²σ2² + 2w1w2Cov(R1,R2).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'According to CFA curriculum, diversification benefits are greatest when the correlation between assets is:', 'Positive', 'Zero', 'Negative', 'C', 'Lower correlation = greater risk reduction from diversification.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'In the context of CFA Level I, if correlation between two assets is +1, the portfolio standard deviation is:', 'Less than the weighted average', 'The weighted average of individual standard deviations', 'Zero', 'B', 'With perfect positive correlation, σp = w1σ1 + w2σ2.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A financial analyst needs to determine: covariance can range from:', 'Negative infinity to positive infinity', '-1 to +1', '0 to 1', 'A', 'Covariance is unbounded, unlike correlation which is bounded [-1, +1].', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Which of the following is most accurate? the correlation coefficient is calculated as:', 'Covariance divided by the product of standard deviations', 'Standard deviation divided by mean', 'Covariance times variance', 'A', 'ρ = Cov(X,Y) / (σx × σy).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'An analyst is evaluating a scenario. for an equally-weighted portfolio of n assets, as n increases, portfolio variance approaches:', 'Zero', 'The average covariance', 'The average variance', 'B', 'As n→∞, portfolio variance → average covariance (systematic risk).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'According to CFA curriculum, a portfolio with 60% in Asset A (E(R)=10%) and 40% in Asset B (E(R)=5%) has an expected return of:', '7.0%', '8.0%', '7.5%', 'B', 'E(Rp) = 0.6×10% + 0.4×5% = 8.0%.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'In the context of CFA Level I, the minimum variance portfolio is the portfolio with:', 'Zero return', 'Equal weights in all assets', 'The lowest possible variance for given assets', 'C', 'The minimum variance portfolio minimizes risk regardless of return.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A financial analyst needs to determine: adding a risk-free asset to a risky portfolio creates:', 'The Capital Allocation Line', 'The Security Market Line', 'The efficient frontier', 'A', 'Combining risk-free and risky assets produces the CAL.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Which of the following is most accurate? shortfall risk is the probability that:', 'Portfolio value exceeds a maximum', 'Returns are normally distributed', 'Portfolio return falls below a minimum threshold', 'C', 'Shortfall risk = P(Rp < Rtarget).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'An analyst is evaluating a scenario. roy''s safety-first criterion maximizes:', '(Expected return - Threshold return) / Standard deviation', 'Expected return only', 'Sharpe ratio', 'A', 'SFRatio = [E(Rp) - RL] / σp.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'According to CFA curriculum, the Sharpe ratio measures:', 'Excess return per unit of systematic risk', 'Total return per unit of risk', 'Excess return per unit of total risk', 'C', 'Sharpe = (Rp - Rf) / σp.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'In the context of CFA Level I, if the covariance between two assets is zero, they are:', 'Mutually exclusive', 'Uncorrelated', 'Perfectly correlated', 'B', 'Zero covariance implies zero correlation (uncorrelated).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A financial analyst needs to determine: the variance of a three-asset portfolio has how many covariance terms?', '6', '3', '9', 'B', 'For 3 assets: 3 unique pairs, each counted twice = 6, but 3 unique covariance terms in the formula.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Which of the following is most accurate? systematic risk is:', 'Total risk', 'Non-diversifiable risk', 'Diversifiable risk', 'B', 'Systematic risk affects all securities and cannot be diversified away.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'An analyst is evaluating a scenario. the efficient frontier represents:', 'Only minimum risk portfolios', 'All possible portfolios', 'Portfolios with maximum return for each level of risk', 'C', 'Efficient frontier = set of optimal portfolios offering highest return per risk level.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'According to CFA curriculum, a risk-averse investor prefers:', 'Higher risk for higher returns', 'Lower risk for a given level of return', 'Risk-neutral investments only', 'B', 'Risk-averse investors prefer the certainty equivalent and require risk premiums.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'In the context of CFA Level I, the portfolio variance of two uncorrelated assets (w1=0.5, σ1=10%, w2=0.5, σ2=20%) is closest to:', '0.50%', '1.25%', '2.50%', 'B', 'σ²p = (0.5)²(0.10)² + (0.5)²(0.20)² = 0.0025 + 0.01 = 0.0125 = 1.25%.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A financial analyst needs to determine: increasing the number of assets in a portfolio reduces:', 'Systematic risk', 'Unsystematic risk', 'Total expected return', 'B', 'Diversification eliminates unsystematic (firm-specific) risk.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Which of the following is most accurate? the expected return of a two-asset portfolio is:', 'The simple average of returns', 'The product of individual returns', 'The weighted average of the individual expected returns', 'C', 'E(Rp) = w1×E(R1) + w2×E(R2).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'An analyst is evaluating a scenario. portfolio variance depends on:', 'Only covariances', 'Only individual variances', 'Individual variances, covariances, and weights', 'C', 'σ²p = w1²σ1² + w2²σ2² + 2w1w2Cov(R1,R2).', 2, 'qbank');
