INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'In the context of CFA Level I, the portfolio variance of two uncorrelated assets (w1=0.5, σ1=10%, w2=0.5, σ2=20%) is closest to:', '1.25%', '0.50%', '2.50%', 'A', 'σ²p = (0.5)²(0.10)² + (0.5)²(0.20)² = 0.0025 + 0.01 = 0.0125 = 1.25%.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A financial analyst needs to determine: increasing the number of assets in a portfolio reduces:', 'Unsystematic risk', 'Total expected return', 'Systematic risk', 'A', 'Diversification eliminates unsystematic (firm-specific) risk.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The portfolio variance of two uncorrelated assets (w1=0.5, σ1=10%, w2=0.5, σ2=20%) is closest to:', '1.25%', '2.50%', '0.50%', 'A', 'σ²p = (0.5)²(0.10)² + (0.5)²(0.20)² = 0.0025 + 0.01 = 0.0125 = 1.25%.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The expected return of a two-asset portfolio is:', 'The weighted average of the individual expected returns', 'The product of individual returns', 'The simple average of returns', 'A', 'E(Rp) = w1×E(R1) + w2×E(R2).', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The minimum variance portfolio is the portfolio with:', 'The lowest possible variance for given assets', 'Zero return', 'Equal weights in all assets', 'A', 'The minimum variance portfolio minimizes risk regardless of return.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'If the covariance between two assets is zero, they are:', 'Uncorrelated', 'Perfectly correlated', 'Mutually exclusive', 'A', 'Zero covariance implies zero correlation (uncorrelated).', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The correlation coefficient is calculated as:', 'Covariance divided by the product of standard deviations', 'Covariance times variance', 'Standard deviation divided by mean', 'A', 'ρ = Cov(X,Y) / (σx × σy).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Increasing the number of assets in a portfolio reduces:', 'Unsystematic risk', 'Systematic risk', 'Total expected return', 'A', 'Diversification eliminates unsystematic (firm-specific) risk.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The efficient frontier represents:', 'Portfolios with maximum return for each level of risk', 'All possible portfolios', 'Only minimum risk portfolios', 'A', 'Efficient frontier = set of optimal portfolios offering highest return per risk level.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'If correlation between two assets is +1, the portfolio standard deviation is:', 'The weighted average of individual standard deviations', 'Less than the weighted average', 'Zero', 'A', 'With perfect positive correlation, σp = w1σ1 + w2σ2.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A portfolio with 60% in Asset A (E(R)=10%) and 40% in Asset B (E(R)=5%) has an expected return of:', '8.0%', '7.5%', '7.0%', 'A', 'E(Rp) = 0.6×10% + 0.4×5% = 8.0%.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Portfolio variance depends on:', 'Individual variances, covariances, and weights', 'Only individual variances', 'Only covariances', 'A', 'σ²p = w1²σ1² + w2²σ2² + 2w1w2Cov(R1,R2).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The variance of a three-asset portfolio has how many covariance terms?', '3', '6', '9', 'A', 'For 3 assets: 3 unique pairs, each counted twice = 6, but 3 unique covariance terms in the formula.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Diversification benefits are greatest when the correlation between assets is:', 'Negative', 'Positive', 'Zero', 'A', 'Lower correlation = greater risk reduction from diversification.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Systematic risk is:', 'Non-diversifiable risk', 'Diversifiable risk', 'Total risk', 'A', 'Systematic risk affects all securities and cannot be diversified away.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'The Sharpe ratio measures:', 'Excess return per unit of total risk', 'Excess return per unit of systematic risk', 'Total return per unit of risk', 'A', 'Sharpe = (Rp - Rf) / σp.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Roy''s safety-first criterion maximizes:', '(Expected return - Threshold return) / Standard deviation', 'Expected return only', 'Sharpe ratio', 'A', 'SFRatio = [E(Rp) - RL] / σp.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'For an equally-weighted portfolio of n assets, as n increases, portfolio variance approaches:', 'The average covariance', 'Zero', 'The average variance', 'A', 'As n→∞, portfolio variance → average covariance (systematic risk).', 3, 'mock');
