INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'According to CFA curriculum, systematic risk is:', 'Diversifiable risk', 'Non-diversifiable risk', 'Total risk', 'B', 'Systematic risk affects all securities and cannot be diversified away.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'In the context of CFA Level I, the Sharpe ratio measures:', 'Total return per unit of risk', 'Excess return per unit of systematic risk', 'Excess return per unit of total risk', 'C', 'Sharpe = (Rp - Rf) / σp.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A financial analyst needs to determine: roy''s safety-first criterion maximizes:', 'Sharpe ratio', 'Expected return only', '(Expected return - Threshold return) / Standard deviation', 'C', 'SFRatio = [E(Rp) - RL] / σp.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Which of the following is most accurate? for an equally-weighted portfolio of n assets, as n increases, portfolio variance approaches:', 'The average covariance', 'Zero', 'The average variance', 'A', 'As n→∞, portfolio variance → average covariance (systematic risk).', 4, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'An analyst is evaluating a scenario. adding a risk-free asset to a risky portfolio creates:', 'The efficient frontier', 'The Security Market Line', 'The Capital Allocation Line', 'C', 'Combining risk-free and risky assets produces the CAL.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'According to CFA curriculum, covariance can range from:', '0 to 1', 'Negative infinity to positive infinity', '-1 to +1', 'B', 'Covariance is unbounded, unlike correlation which is bounded [-1, +1].', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'In the context of CFA Level I, shortfall risk is the probability that:', 'Portfolio return falls below a minimum threshold', 'Portfolio value exceeds a maximum', 'Returns are normally distributed', 'A', 'Shortfall risk = P(Rp < Rtarget).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A financial analyst needs to determine: a risk-averse investor prefers:', 'Lower risk for a given level of return', 'Risk-neutral investments only', 'Higher risk for higher returns', 'A', 'Risk-averse investors prefer the certainty equivalent and require risk premiums.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Which of the following is most accurate? the portfolio variance of two uncorrelated assets (w1=0.5, σ1=10%, w2=0.5, σ2=20%) is closest to:', '2.50%', '0.50%', '1.25%', 'C', 'σ²p = (0.5)²(0.10)² + (0.5)²(0.20)² = 0.0025 + 0.01 = 0.0125 = 1.25%.', 4, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'An analyst is evaluating a scenario. the expected return of a two-asset portfolio is:', 'The weighted average of the individual expected returns', 'The simple average of returns', 'The product of individual returns', 'A', 'E(Rp) = w1×E(R1) + w2×E(R2).', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'According to CFA curriculum, the minimum variance portfolio is the portfolio with:', 'Zero return', 'Equal weights in all assets', 'The lowest possible variance for given assets', 'C', 'The minimum variance portfolio minimizes risk regardless of return.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'In the context of CFA Level I, if the covariance between two assets is zero, they are:', 'Perfectly correlated', 'Mutually exclusive', 'Uncorrelated', 'C', 'Zero covariance implies zero correlation (uncorrelated).', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A financial analyst needs to determine: the correlation coefficient is calculated as:', 'Covariance times variance', 'Standard deviation divided by mean', 'Covariance divided by the product of standard deviations', 'C', 'ρ = Cov(X,Y) / (σx × σy).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Which of the following is most accurate? increasing the number of assets in a portfolio reduces:', 'Systematic risk', 'Unsystematic risk', 'Total expected return', 'B', 'Diversification eliminates unsystematic (firm-specific) risk.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'An analyst is evaluating a scenario. the efficient frontier represents:', 'All possible portfolios', 'Only minimum risk portfolios', 'Portfolios with maximum return for each level of risk', 'C', 'Efficient frontier = set of optimal portfolios offering highest return per risk level.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'According to CFA curriculum, if correlation between two assets is +1, the portfolio standard deviation is:', 'The weighted average of individual standard deviations', 'Zero', 'Less than the weighted average', 'A', 'With perfect positive correlation, σp = w1σ1 + w2σ2.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'In the context of CFA Level I, a portfolio with 60% in Asset A (E(R)=10%) and 40% in Asset B (E(R)=5%) has an expected return of:', '7.5%', '7.0%', '8.0%', 'C', 'E(Rp) = 0.6×10% + 0.4×5% = 8.0%.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'A financial analyst needs to determine: portfolio variance depends on:', 'Individual variances, covariances, and weights', 'Only individual variances', 'Only covariances', 'A', 'σ²p = w1²σ1² + w2²σ2² + 2w1w2Cov(R1,R2).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'Which of the following is most accurate? the variance of a three-asset portfolio has how many covariance terms?', '6', '9', '3', 'C', 'For 3 assets: 3 unique pairs, each counted twice = 6, but 3 unique covariance terms in the formula.', 4, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (5, 'An analyst is evaluating a scenario. diversification benefits are greatest when the correlation between assets is:', 'Positive', 'Negative', 'Zero', 'B', 'Lower correlation = greater risk reduction from diversification.', 2, 'mock');
