INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Monte Carlo simulation is best described as:', 'A technique that uses random sampling to model uncertainty', 'A deterministic optimization method', 'A regression analysis technique', 'A', 'Monte Carlo simulation generates random scenarios to estimate distributions of outcomes.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A key advantage of Monte Carlo simulation is that it:', 'Can model complex interactions and non-linear relationships', 'Always provides exact solutions', 'Eliminates the need for assumptions', 'A', 'Monte Carlo handles complex, multi-variable problems that analytical methods cannot.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Historical simulation uses:', 'Actual past data to simulate future scenarios', 'Random numbers from a theoretical distribution', 'Only the most recent data point', 'A', 'Historical simulation resamples from actual historical returns.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'The number of trials in a Monte Carlo simulation should be:', 'Large enough to achieve stable results', 'Exactly 100', 'Equal to the number of variables', 'A', 'More trials improve accuracy; typically thousands or millions are used.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A limitation of Monte Carlo simulation is:', 'It depends on the quality of input assumptions', 'It cannot model correlations', 'It only works for normally distributed data', 'A', 'Garbage in, garbage out — results are only as good as the distributional assumptions.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Bootstrap resampling involves:', 'Drawing random samples with replacement from historical data', 'Drawing samples without replacement', 'Using theoretical distributions only', 'A', 'Bootstrapping resamples with replacement to estimate sampling distributions.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'In simulation, pseudo-random numbers are:', 'Generated by algorithms that appear random', 'Truly random', 'Always uniformly distributed', 'A', 'Computer-generated numbers are deterministic but mimic randomness.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'To simulate a lognormal stock price, you would:', 'Simulate normal returns and exponentiate', 'Simulate uniform returns', 'Use actual historical prices directly', 'A', 'If ln(S) is normal, then S = exp(normal) is lognormal.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'The accuracy of a Monte Carlo estimate increases with:', 'The square root of the number of simulations', 'The number of simulations linearly', 'The square of the number of simulations', 'A', 'Standard error decreases as 1/√n, so accuracy improves with √n.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Scenario analysis differs from simulation in that it:', 'Uses a limited number of discrete scenarios', 'Uses thousands of random scenarios', 'Is always more accurate', 'A', 'Scenario analysis examines specific what-if cases, while simulation generates many random paths.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Variance reduction techniques in simulation include:', 'Antithetic variates and control variates', 'Increasing the number of variables', 'Reducing the number of trials', 'A', 'These techniques reduce sampling error without increasing computational cost.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A stress test typically:', 'Examines portfolio performance under extreme scenarios', 'Uses random normal scenarios', 'Optimizes the portfolio weights', 'A', 'Stress tests apply extreme but plausible shocks to evaluate vulnerability.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'In a Monte Carlo VaR calculation, the 5% VaR is:', 'The 5th percentile of simulated losses', 'The average of all simulated losses', 'The maximum simulated loss', 'A', 'VaR at 95% confidence = the loss at the 5th percentile of the simulated distribution.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Which distribution is commonly used to simulate asset returns?', 'Normal distribution', 'Uniform distribution', 'Poisson distribution', 'A', 'Normal (or lognormal) distributions are standard for modeling returns.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Convergence in Monte Carlo simulation means:', 'Results stabilize as the number of trials increases', 'The simulation runs faster', 'Fewer variables are needed', 'A', 'Convergence = the estimate approaches the true value with more iterations.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Latin Hypercube Sampling:', 'Stratifies the probability distribution for better coverage', 'Uses only historical data', 'Requires fewer than 10 trials', 'A', 'LHS ensures the full range of each variable is sampled, improving efficiency.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A random walk model assumes:', 'Future changes are independent of past changes', 'Prices follow a deterministic trend', 'Returns are perfectly predictable', 'A', 'Random walk: price changes are independent and identically distributed.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'The seed value in a simulation:', 'Ensures reproducibility of pseudo-random numbers', 'Determines the number of trials', 'Sets the confidence level', 'A', 'Same seed = same sequence of pseudo-random numbers.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'When modeling correlated assets in simulation, one typically uses:', 'Cholesky decomposition', 'Simple random sampling', 'Only marginal distributions', 'A', 'Cholesky decomposition transforms independent random variables into correlated ones.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A disadvantage of historical simulation is:', 'It assumes the future will resemble the past', 'It requires distributional assumptions', 'It cannot handle multiple assets', 'A', 'Historical simulation is limited by the range and relevance of past data.', 2, 'qbank');
