INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A financial analyst needs to determine: scenario analysis differs from simulation in that it:', 'Uses a limited number of discrete scenarios', 'Is always more accurate', 'Uses thousands of random scenarios', 'A', 'Scenario analysis examines specific what-if cases, while simulation generates many random paths.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Which of the following is most accurate? variance reduction techniques in simulation include:', 'Reducing the number of trials', 'Antithetic variates and control variates', 'Increasing the number of variables', 'B', 'These techniques reduce sampling error without increasing computational cost.', 4, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'An analyst is evaluating a scenario. a stress test typically:', 'Examines portfolio performance under extreme scenarios', 'Uses random normal scenarios', 'Optimizes the portfolio weights', 'A', 'Stress tests apply extreme but plausible shocks to evaluate vulnerability.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'According to CFA curriculum, in a Monte Carlo VaR calculation, the 5% VaR is:', 'The average of all simulated losses', 'The maximum simulated loss', 'The 5th percentile of simulated losses', 'C', 'VaR at 95% confidence = the loss at the 5th percentile of the simulated distribution.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'In the context of CFA Level I, which distribution is commonly used to simulate asset returns?', 'Normal distribution', 'Uniform distribution', 'Poisson distribution', 'A', 'Normal (or lognormal) distributions are standard for modeling returns.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A financial analyst needs to determine: convergence in Monte Carlo simulation means:', 'Results stabilize as the number of trials increases', 'Fewer variables are needed', 'The simulation runs faster', 'A', 'Convergence = the estimate approaches the true value with more iterations.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Which of the following is most accurate? latin Hypercube Sampling:', 'Stratifies the probability distribution for better coverage', 'Uses only historical data', 'Requires fewer than 10 trials', 'A', 'LHS ensures the full range of each variable is sampled, improving efficiency.', 4, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'An analyst is evaluating a scenario. a random walk model assumes:', 'Future changes are independent of past changes', 'Returns are perfectly predictable', 'Prices follow a deterministic trend', 'A', 'Random walk: price changes are independent and identically distributed.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'According to CFA curriculum, the seed value in a simulation:', 'Determines the number of trials', 'Sets the confidence level', 'Ensures reproducibility of pseudo-random numbers', 'C', 'Same seed = same sequence of pseudo-random numbers.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'In the context of CFA Level I, when modeling correlated assets in simulation, one typically uses:', 'Only marginal distributions', 'Cholesky decomposition', 'Simple random sampling', 'B', 'Cholesky decomposition transforms independent random variables into correlated ones.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A financial analyst needs to determine: a disadvantage of historical simulation is:', 'It requires distributional assumptions', 'It cannot handle multiple assets', 'It assumes the future will resemble the past', 'C', 'Historical simulation is limited by the range and relevance of past data.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Which of the following is most accurate? monte Carlo simulation is best described as:', 'A technique that uses random sampling to model uncertainty', 'A deterministic optimization method', 'A regression analysis technique', 'A', 'Monte Carlo simulation generates random scenarios to estimate distributions of outcomes.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'An analyst is evaluating a scenario. a key advantage of Monte Carlo simulation is that it:', 'Eliminates the need for assumptions', 'Can model complex interactions and non-linear relationships', 'Always provides exact solutions', 'B', 'Monte Carlo handles complex, multi-variable problems that analytical methods cannot.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'According to CFA curriculum, historical simulation uses:', 'Only the most recent data point', 'Random numbers from a theoretical distribution', 'Actual past data to simulate future scenarios', 'C', 'Historical simulation resamples from actual historical returns.', 2, 'qbank');
