INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'An analyst is evaluating a scenario. the number of trials in a Monte Carlo simulation should be:', 'Equal to the number of variables', 'Large enough to achieve stable results', 'Exactly 100', 'B', 'More trials improve accuracy; typically thousands or millions are used.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'According to CFA curriculum, when modeling correlated assets in simulation, one typically uses:', 'Only marginal distributions', 'Simple random sampling', 'Cholesky decomposition', 'C', 'Cholesky decomposition transforms independent random variables into correlated ones.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'In the context of CFA Level I, the accuracy of a Monte Carlo estimate increases with:', 'The number of simulations linearly', 'The square of the number of simulations', 'The square root of the number of simulations', 'C', 'Standard error decreases as 1/√n, so accuracy improves with √n.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A financial analyst needs to determine: to simulate a lognormal stock price, you would:', 'Use actual historical prices directly', 'Simulate uniform returns', 'Simulate normal returns and exponentiate', 'C', 'If ln(S) is normal, then S = exp(normal) is lognormal.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Which of the following is most accurate? bootstrap resampling involves:', 'Using theoretical distributions only', 'Drawing samples without replacement', 'Drawing random samples with replacement from historical data', 'C', 'Bootstrapping resamples with replacement to estimate sampling distributions.', 4, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'An analyst is evaluating a scenario. a key advantage of Monte Carlo simulation is that it:', 'Eliminates the need for assumptions', 'Can model complex interactions and non-linear relationships', 'Always provides exact solutions', 'B', 'Monte Carlo handles complex, multi-variable problems that analytical methods cannot.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'According to CFA curriculum, the seed value in a simulation:', 'Sets the confidence level', 'Determines the number of trials', 'Ensures reproducibility of pseudo-random numbers', 'C', 'Same seed = same sequence of pseudo-random numbers.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'In the context of CFA Level I, latin Hypercube Sampling:', 'Stratifies the probability distribution for better coverage', 'Requires fewer than 10 trials', 'Uses only historical data', 'A', 'LHS ensures the full range of each variable is sampled, improving efficiency.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A financial analyst needs to determine: a stress test typically:', 'Optimizes the portfolio weights', 'Examines portfolio performance under extreme scenarios', 'Uses random normal scenarios', 'B', 'Stress tests apply extreme but plausible shocks to evaluate vulnerability.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Which of the following is most accurate? a disadvantage of historical simulation is:', 'It cannot handle multiple assets', 'It requires distributional assumptions', 'It assumes the future will resemble the past', 'C', 'Historical simulation is limited by the range and relevance of past data.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'An analyst is evaluating a scenario. scenario analysis differs from simulation in that it:', 'Uses thousands of random scenarios', 'Is always more accurate', 'Uses a limited number of discrete scenarios', 'C', 'Scenario analysis examines specific what-if cases, while simulation generates many random paths.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'According to CFA curriculum, a limitation of Monte Carlo simulation is:', 'It only works for normally distributed data', 'It cannot model correlations', 'It depends on the quality of input assumptions', 'C', 'Garbage in, garbage out — results are only as good as the distributional assumptions.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'In the context of CFA Level I, in simulation, pseudo-random numbers are:', 'Truly random', 'Generated by algorithms that appear random', 'Always uniformly distributed', 'B', 'Computer-generated numbers are deterministic but mimic randomness.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'A financial analyst needs to determine: historical simulation uses:', 'Only the most recent data point', 'Actual past data to simulate future scenarios', 'Random numbers from a theoretical distribution', 'B', 'Historical simulation resamples from actual historical returns.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'Which of the following is most accurate? monte Carlo simulation is best described as:', 'A regression analysis technique', 'A technique that uses random sampling to model uncertainty', 'A deterministic optimization method', 'B', 'Monte Carlo simulation generates random scenarios to estimate distributions of outcomes.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (6, 'An analyst is evaluating a scenario. convergence in Monte Carlo simulation means:', 'Results stabilize as the number of trials increases', 'The simulation runs faster', 'Fewer variables are needed', 'A', 'Convergence = the estimate approaches the true value with more iterations.', 2, 'mock');
