INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A point estimate is:', 'A single value used to estimate a population parameter', 'A range of values', 'The population parameter itself', 'A', 'A point estimate is a single statistic used as the best guess for a parameter.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A confidence interval provides:', 'A range likely to contain the population parameter', 'An exact value of the parameter', 'The probability of a specific outcome', 'A', 'CI = point estimate ± (critical value × standard error).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'The standard error of the sample mean is:', 'Population standard deviation divided by the square root of n', 'The sample standard deviation', 'The variance divided by n', 'A', 'SE = σ/√n.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'As sample size increases, the standard error:', 'Decreases', 'Increases', 'Remains the same', 'A', 'SE = σ/√n, so larger n reduces SE.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'The t-distribution is used instead of the z-distribution when:', 'The population variance is unknown and sample size is small', 'The population is not normal', 'The sample size is very large', 'A', 'With unknown σ and small n, use the t-distribution.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'Degrees of freedom for a single sample t-test are:', 'n - 1', 'n', 'n + 1', 'A', 'df = n - 1 for a single sample.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'As degrees of freedom increase, the t-distribution:', 'Approaches the standard normal distribution', 'Becomes more spread out', 'Shifts to the right', 'A', 'With more df, t-distribution → z-distribution.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A 95% confidence interval means:', 'In repeated sampling, 95% of such intervals would contain the true parameter', 'There is a 95% probability the parameter is in the interval', 'The sample mean is 95% accurate', 'A', 'Frequentist interpretation: 95% of all possible CIs contain the true value.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'An unbiased estimator has:', 'An expected value equal to the population parameter', 'Zero variance', 'The smallest possible variance', 'A', 'E(θ-hat) = θ for an unbiased estimator.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'An efficient estimator has:', 'The smallest variance among all unbiased estimators', 'Zero bias', 'A larger sample size', 'A', 'Efficiency = minimum variance among unbiased estimators (MVUE).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A consistent estimator:', 'Converges to the true parameter as sample size increases', 'Is always unbiased', 'Has zero standard error', 'A', 'Consistency: as n→∞, the estimator → the parameter in probability.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'The Central Limit Theorem states that:', 'The distribution of sample means approaches normal as n increases', 'All populations are normally distributed', 'Sample variance equals population variance', 'A', 'CLT: for large n, X-bar is approximately normal regardless of population shape.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'The z-critical value for a 95% confidence interval is approximately:', '1.96', '1.645', '2.576', 'A', '95% CI → z = 1.96 (two-tailed).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'To halve the width of a confidence interval, the sample size must:', 'Quadruple', 'Double', 'Increase by 50%', 'A', 'CI width ∝ 1/√n, so halving width requires 4× the sample.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'The z-critical value for a 99% confidence interval is approximately:', '2.576', '1.96', '1.645', 'A', '99% CI → z = 2.576 (two-tailed).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'Sampling error is:', 'The difference between sample statistic and population parameter', 'A mistake in data collection', 'Bias in the estimator', 'A', 'Sampling error arises naturally from using a subset of the population.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A Type I error occurs when:', 'A true null hypothesis is rejected', 'A false null hypothesis is not rejected', 'The sample size is too small', 'A', 'Type I error = false positive (rejecting H0 when it''s true).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A Type II error occurs when:', 'A false null hypothesis is not rejected', 'A true null hypothesis is rejected', 'The confidence level is too high', 'A', 'Type II error = false negative (failing to reject a false H0).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'The power of a test is:', 'The probability of correctly rejecting a false null hypothesis', 'The probability of a Type I error', '1 minus the significance level', 'A', 'Power = 1 - P(Type II error) = P(reject H0 | H0 is false).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'Increasing the significance level:', 'Increases the probability of a Type I error', 'Decreases the probability of a Type I error', 'Has no effect on error probabilities', 'A', 'Higher α = more likely to reject H0 = more Type I errors.', 2, 'qbank');
