INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A financial analyst needs to determine: increasing the significance level:', 'Increases the probability of a Type I error', 'Has no effect on error probabilities', 'Decreases the probability of a Type I error', 'A', 'Higher α = more likely to reject H0 = more Type I errors.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'Which of the following is most accurate? a point estimate is:', 'A single value used to estimate a population parameter', 'A range of values', 'The population parameter itself', 'A', 'A point estimate is a single statistic used as the best guess for a parameter.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'An analyst is evaluating a scenario. a confidence interval provides:', 'An exact value of the parameter', 'A range likely to contain the population parameter', 'The probability of a specific outcome', 'B', 'CI = point estimate ± (critical value × standard error).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'According to CFA curriculum, the standard error of the sample mean is:', 'The sample standard deviation', 'Population standard deviation divided by the square root of n', 'The variance divided by n', 'B', 'SE = σ/√n.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'In the context of CFA Level I, as sample size increases, the standard error:', 'Decreases', 'Remains the same', 'Increases', 'A', 'SE = σ/√n, so larger n reduces SE.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A financial analyst needs to determine: the t-distribution is used instead of the z-distribution when:', 'The population is not normal', 'The population variance is unknown and sample size is small', 'The sample size is very large', 'B', 'With unknown σ and small n, use the t-distribution.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'Which of the following is most accurate? degrees of freedom for a single sample t-test are:', 'n + 1', 'n', 'n - 1', 'C', 'df = n - 1 for a single sample.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'An analyst is evaluating a scenario. as degrees of freedom increase, the t-distribution:', 'Approaches the standard normal distribution', 'Shifts to the right', 'Becomes more spread out', 'A', 'With more df, t-distribution → z-distribution.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'According to CFA curriculum, a 95% confidence interval means:', 'The sample mean is 95% accurate', 'There is a 95% probability the parameter is in the interval', 'In repeated sampling, 95% of such intervals would contain the true parameter', 'C', 'Frequentist interpretation: 95% of all possible CIs contain the true value.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'In the context of CFA Level I, an unbiased estimator has:', 'The smallest possible variance', 'An expected value equal to the population parameter', 'Zero variance', 'B', 'E(θ-hat) = θ for an unbiased estimator.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A financial analyst needs to determine: an efficient estimator has:', 'Zero bias', 'The smallest variance among all unbiased estimators', 'A larger sample size', 'B', 'Efficiency = minimum variance among unbiased estimators (MVUE).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'Which of the following is most accurate? a consistent estimator:', 'Converges to the true parameter as sample size increases', 'Has zero standard error', 'Is always unbiased', 'A', 'Consistency: as n→∞, the estimator → the parameter in probability.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'An analyst is evaluating a scenario. the Central Limit Theorem states that:', 'The distribution of sample means approaches normal as n increases', 'Sample variance equals population variance', 'All populations are normally distributed', 'A', 'CLT: for large n, X-bar is approximately normal regardless of population shape.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'According to CFA curriculum, the z-critical value for a 95% confidence interval is approximately:', '1.645', '2.576', '1.96', 'C', '95% CI → z = 1.96 (two-tailed).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'In the context of CFA Level I, to halve the width of a confidence interval, the sample size must:', 'Increase by 50%', 'Quadruple', 'Double', 'B', 'CI width ∝ 1/√n, so halving width requires 4× the sample.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A financial analyst needs to determine: the z-critical value for a 99% confidence interval is approximately:', '1.645', '1.96', '2.576', 'C', '99% CI → z = 2.576 (two-tailed).', 1, 'qbank');
