INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'An analyst is evaluating a scenario. a 95% confidence interval means:', 'The sample mean is 95% accurate', 'There is a 95% probability the parameter is in the interval', 'In repeated sampling, 95% of such intervals would contain the true parameter', 'C', 'Frequentist interpretation: 95% of all possible CIs contain the true value.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'According to CFA curriculum, the standard error of the sample mean is:', 'The variance divided by n', 'The sample standard deviation', 'Population standard deviation divided by the square root of n', 'C', 'SE = σ/√n.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'In the context of CFA Level I, degrees of freedom for a single sample t-test are:', 'n - 1', 'n', 'n + 1', 'A', 'df = n - 1 for a single sample.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A financial analyst needs to determine: the power of a test is:', 'The probability of correctly rejecting a false null hypothesis', '1 minus the significance level', 'The probability of a Type I error', 'A', 'Power = 1 - P(Type II error) = P(reject H0 | H0 is false).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'Which of the following is most accurate? as degrees of freedom increase, the t-distribution:', 'Becomes more spread out', 'Approaches the standard normal distribution', 'Shifts to the right', 'B', 'With more df, t-distribution → z-distribution.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'An analyst is evaluating a scenario. sampling error is:', 'A mistake in data collection', 'The difference between sample statistic and population parameter', 'Bias in the estimator', 'B', 'Sampling error arises naturally from using a subset of the population.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'According to CFA curriculum, as sample size increases, the standard error:', 'Increases', 'Remains the same', 'Decreases', 'C', 'SE = σ/√n, so larger n reduces SE.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'In the context of CFA Level I, a Type I error occurs when:', 'A true null hypothesis is rejected', 'A false null hypothesis is not rejected', 'The sample size is too small', 'A', 'Type I error = false positive (rejecting H0 when it''s true).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A financial analyst needs to determine: a confidence interval provides:', 'A range likely to contain the population parameter', 'The probability of a specific outcome', 'An exact value of the parameter', 'A', 'CI = point estimate ± (critical value × standard error).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'Which of the following is most accurate? the z-critical value for a 95% confidence interval is approximately:', '1.96', '2.576', '1.645', 'A', '95% CI → z = 1.96 (two-tailed).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'An analyst is evaluating a scenario. to halve the width of a confidence interval, the sample size must:', 'Double', 'Increase by 50%', 'Quadruple', 'C', 'CI width ∝ 1/√n, so halving width requires 4× the sample.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'According to CFA curriculum, a point estimate is:', 'A range of values', 'The population parameter itself', 'A single value used to estimate a population parameter', 'C', 'A point estimate is a single statistic used as the best guess for a parameter.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'In the context of CFA Level I, an efficient estimator has:', 'The smallest variance among all unbiased estimators', 'Zero bias', 'A larger sample size', 'A', 'Efficiency = minimum variance among unbiased estimators (MVUE).', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A financial analyst needs to determine: the Central Limit Theorem states that:', 'Sample variance equals population variance', 'All populations are normally distributed', 'The distribution of sample means approaches normal as n increases', 'C', 'CLT: for large n, X-bar is approximately normal regardless of population shape.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'Which of the following is most accurate? an unbiased estimator has:', 'Zero variance', 'An expected value equal to the population parameter', 'The smallest possible variance', 'B', 'E(θ-hat) = θ for an unbiased estimator.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'An analyst is evaluating a scenario. a Type II error occurs when:', 'The confidence level is too high', 'A false null hypothesis is not rejected', 'A true null hypothesis is rejected', 'B', 'Type II error = false negative (failing to reject a false H0).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'According to CFA curriculum, increasing the significance level:', 'Has no effect on error probabilities', 'Decreases the probability of a Type I error', 'Increases the probability of a Type I error', 'C', 'Higher α = more likely to reject H0 = more Type I errors.', 2, 'mock');
