INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (7, 'A financial analyst needs to determine: the power of a test is:', 'The probability of a Type I error', '1 minus the significance level', 'The probability of correctly rejecting a false null hypothesis', 'C', 'Power = 1 - P(Type II error) = P(reject H0 | H0 is false).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'The null hypothesis typically represents:', 'The status quo or no effect', 'The alternative claim', 'The desired outcome', 'A', 'H0 states no difference, no effect, or no relationship.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A two-tailed test is appropriate when:', 'We are testing for a difference in either direction', 'We expect only an increase', 'We expect only a decrease', 'A', 'Two-tailed: H1: μ ≠ μ0 (reject for either direction).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'The p-value is:', 'The smallest significance level at which H0 would be rejected', 'The probability that H0 is true', 'The probability of a Type II error', 'A', 'p-value = probability of observing the test statistic or more extreme, given H0.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'If the p-value is less than alpha, we:', 'Reject the null hypothesis', 'Fail to reject the null hypothesis', 'Accept the null hypothesis', 'A', 'p-value < α → reject H0.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A test statistic falls in the rejection region. This means:', 'We reject the null hypothesis', 'We accept the null hypothesis', 'The test is inconclusive', 'A', 'Test stat in rejection region → reject H0.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'The significance level (alpha) is:', 'The probability of rejecting a true null hypothesis', 'The probability of accepting a false null hypothesis', 'The power of the test', 'A', 'α = P(Type I error) = P(reject H0 | H0 true).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'For a one-tailed test at 5% significance with z-distribution, the critical value is:', '1.645', '1.96', '2.576', 'A', 'One-tailed 5% → z = 1.645.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'When testing a hypothesis about the mean with known population variance:', 'Use the z-test', 'Use the t-test', 'Use the chi-square test', 'A', 'Known σ → z-test.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'The chi-square test is used for:', 'Testing hypotheses about variance', 'Testing hypotheses about the mean', 'Testing correlation', 'A', 'Chi-square tests variance: χ² = (n-1)s²/σ0².', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'The F-test is used to:', 'Compare two population variances', 'Compare two population means', 'Test normality', 'A', 'F = s1²/s2², comparing two sample variances.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Rejecting H0 when it is false is a:', 'Correct decision', 'Type I error', 'Type II error', 'A', 'Correctly rejecting a false null = desirable outcome (power).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A test with high power has a:', 'Low probability of Type II error', 'High probability of Type I error', 'Large sample variance', 'A', 'Power = 1 - β; high power means low Type II error.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Economic significance differs from statistical significance because:', 'A statistically significant result may not be meaningful in practice', 'They always agree', 'Economic significance requires larger samples', 'A', 'Statistical significance doesn''t imply practical importance.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'With a larger sample size, a test becomes:', 'More likely to detect small effects', 'Less likely to detect effects', 'Less reliable', 'A', 'Larger n increases power → smaller effects become detectable.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A parametric test assumes:', 'The population follows a specific distribution', 'No distributional assumptions', 'Only nominal data', 'A', 'Parametric tests assume a known distribution (e.g., normality).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'The t-test for paired observations is used when:', 'Samples are dependent', 'Samples are independent', 'Population variance is known', 'A', 'Paired t-test: same subjects measured twice or matched pairs.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'When testing H0: μ = 50 vs H1: μ > 50, this is a:', 'One-tailed test (right-tailed)', 'Two-tailed test', 'One-tailed test (left-tailed)', 'A', 'H1: μ > 50 is a right-tailed test.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'If we cannot reject H0, we should say:', 'We fail to reject H0', 'We accept H0', 'H0 is proven true', 'A', 'Never ''accept'' H0; we simply fail to find sufficient evidence against it.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'The test statistic for a z-test is:', '(Sample mean - Hypothesized mean) / Standard error', 'Sample mean / Population mean', 'Standard error / Sample mean', 'A', 'z = (x-bar - μ0) / (σ/√n).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Multiple testing correction is needed when:', 'Conducting many simultaneous tests', 'Using a single test', 'The sample is very large', 'A', 'Multiple comparisons inflate the probability of at least one Type I error.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Which of the following is most accurate? the null hypothesis typically represents:', 'The desired outcome', 'The alternative claim', 'The status quo or no effect', 'C', 'H0 states no difference, no effect, or no relationship.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'An analyst is evaluating a scenario. a two-tailed test is appropriate when:', 'We are testing for a difference in either direction', 'We expect only a decrease', 'We expect only an increase', 'A', 'Two-tailed: H1: μ ≠ μ0 (reject for either direction).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'According to CFA curriculum, the p-value is:', 'The probability of a Type II error', 'The probability that H0 is true', 'The smallest significance level at which H0 would be rejected', 'C', 'p-value = probability of observing the test statistic or more extreme, given H0.', 2, 'qbank');
