INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'An analyst is evaluating a scenario. for a one-tailed test at 5% significance with z-distribution, the critical value is:', '1.96', '2.576', '1.645', 'C', 'One-tailed 5% → z = 1.645.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'According to CFA curriculum, when testing a hypothesis about the mean with known population variance:', 'Use the t-test', 'Use the chi-square test', 'Use the z-test', 'C', 'Known σ → z-test.', 1, 'qbank');
