INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'An analyst is evaluating a scenario. a test with high power has a:', 'Large sample variance', 'High probability of Type I error', 'Low probability of Type II error', 'C', 'Power = 1 - β; high power means low Type II error.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'According to CFA curriculum, economic significance differs from statistical significance because:', 'They always agree', 'A statistically significant result may not be meaningful in practice', 'Economic significance requires larger samples', 'B', 'Statistical significance doesn''t imply practical importance.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'In the context of CFA Level I, with a larger sample size, a test becomes:', 'More likely to detect small effects', 'Less likely to detect effects', 'Less reliable', 'A', 'Larger n increases power → smaller effects become detectable.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A financial analyst needs to determine: a parametric test assumes:', 'The population follows a specific distribution', 'No distributional assumptions', 'Only nominal data', 'A', 'Parametric tests assume a known distribution (e.g., normality).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Which of the following is most accurate? the t-test for paired observations is used when:', 'Samples are dependent', 'Samples are independent', 'Population variance is known', 'A', 'Paired t-test: same subjects measured twice or matched pairs.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'An analyst is evaluating a scenario. when testing H0: μ = 50 vs H1: μ > 50, this is a:', 'One-tailed test (left-tailed)', 'One-tailed test (right-tailed)', 'Two-tailed test', 'B', 'H1: μ > 50 is a right-tailed test.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'According to CFA curriculum, if we cannot reject H0, we should say:', 'H0 is proven true', 'We fail to reject H0', 'We accept H0', 'B', 'Never ''accept'' H0; we simply fail to find sufficient evidence against it.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'In the context of CFA Level I, the test statistic for a z-test is:', '(Sample mean - Hypothesized mean) / Standard error', 'Standard error / Sample mean', 'Sample mean / Population mean', 'A', 'z = (x-bar - μ0) / (σ/√n).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A financial analyst needs to determine: multiple testing correction is needed when:', 'Conducting many simultaneous tests', 'Using a single test', 'The sample is very large', 'A', 'Multiple comparisons inflate the probability of at least one Type I error.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Which of the following is most accurate? the null hypothesis typically represents:', 'The alternative claim', 'The desired outcome', 'The status quo or no effect', 'C', 'H0 states no difference, no effect, or no relationship.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'An analyst is evaluating a scenario. a two-tailed test is appropriate when:', 'We expect only a decrease', 'We expect only an increase', 'We are testing for a difference in either direction', 'C', 'Two-tailed: H1: μ ≠ μ0 (reject for either direction).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'According to CFA curriculum, the p-value is:', 'The smallest significance level at which H0 would be rejected', 'The probability of a Type II error', 'The probability that H0 is true', 'A', 'p-value = probability of observing the test statistic or more extreme, given H0.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'In the context of CFA Level I, if the p-value is less than alpha, we:', 'Accept the null hypothesis', 'Fail to reject the null hypothesis', 'Reject the null hypothesis', 'C', 'p-value < α → reject H0.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A financial analyst needs to determine: a test statistic falls in the rejection region. This means:', 'The test is inconclusive', 'We reject the null hypothesis', 'We accept the null hypothesis', 'B', 'Test stat in rejection region → reject H0.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Which of the following is most accurate? the significance level (alpha) is:', 'The probability of accepting a false null hypothesis', 'The power of the test', 'The probability of rejecting a true null hypothesis', 'C', 'α = P(Type I error) = P(reject H0 | H0 true).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'An analyst is evaluating a scenario. for a one-tailed test at 5% significance with z-distribution, the critical value is:', '2.576', '1.96', '1.645', 'C', 'One-tailed 5% → z = 1.645.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'According to CFA curriculum, when testing a hypothesis about the mean with known population variance:', 'Use the t-test', 'Use the z-test', 'Use the chi-square test', 'B', 'Known σ → z-test.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'In the context of CFA Level I, the chi-square test is used for:', 'Testing hypotheses about the mean', 'Testing correlation', 'Testing hypotheses about variance', 'C', 'Chi-square tests variance: χ² = (n-1)s²/σ0².', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A financial analyst needs to determine: the F-test is used to:', 'Compare two population means', 'Test normality', 'Compare two population variances', 'C', 'F = s1²/s2², comparing two sample variances.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Which of the following is most accurate? rejecting H0 when it is false is a:', 'Type I error', 'Correct decision', 'Type II error', 'B', 'Correctly rejecting a false null = desirable outcome (power).', 2, 'qbank');
