INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'When testing a hypothesis about the mean with known population variance:', 'Use the z-test', 'Use the t-test', 'Use the chi-square test', 'A', 'Known σ → z-test.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'For a one-tailed test at 5% significance with z-distribution, the critical value is:', '1.645', '1.96', '2.576', 'A', 'One-tailed 5% → z = 1.645.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'The chi-square test is used for:', 'Testing hypotheses about variance', 'Testing hypotheses about the mean', 'Testing correlation', 'A', 'Chi-square tests variance: χ² = (n-1)s²/σ0².', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Economic significance differs from statistical significance because:', 'A statistically significant result may not be meaningful in practice', 'They always agree', 'Economic significance requires larger samples', 'A', 'Statistical significance doesn''t imply practical importance.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'With a larger sample size, a test becomes:', 'More likely to detect small effects', 'Less likely to detect effects', 'Less reliable', 'A', 'Larger n increases power → smaller effects become detectable.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'If we cannot reject H0, we should say:', 'We fail to reject H0', 'We accept H0', 'H0 is proven true', 'A', 'Never ''accept'' H0; we simply fail to find sufficient evidence against it.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A test with high power has a:', 'Low probability of Type II error', 'High probability of Type I error', 'Large sample variance', 'A', 'Power = 1 - β; high power means low Type II error.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'The p-value is:', 'The smallest significance level at which H0 would be rejected', 'The probability that H0 is true', 'The probability of a Type II error', 'A', 'p-value = probability of observing the test statistic or more extreme, given H0.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'The significance level (alpha) is:', 'The probability of rejecting a true null hypothesis', 'The probability of accepting a false null hypothesis', 'The power of the test', 'A', 'α = P(Type I error) = P(reject H0 | H0 true).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'If the p-value is less than alpha, we:', 'Reject the null hypothesis', 'Fail to reject the null hypothesis', 'Accept the null hypothesis', 'A', 'p-value < α → reject H0.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A two-tailed test is appropriate when:', 'We are testing for a difference in either direction', 'We expect only an increase', 'We expect only a decrease', 'A', 'Two-tailed: H1: μ ≠ μ0 (reject for either direction).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Which of the following is most accurate? a parametric test assumes:', 'Only nominal data', 'The population follows a specific distribution', 'No distributional assumptions', 'B', 'Parametric tests assume a known distribution (e.g., normality).', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'An analyst is evaluating a scenario. multiple testing correction is needed when:', 'Conducting many simultaneous tests', 'The sample is very large', 'Using a single test', 'A', 'Multiple comparisons inflate the probability of at least one Type I error.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'According to CFA curriculum, the null hypothesis typically represents:', 'The alternative claim', 'The desired outcome', 'The status quo or no effect', 'C', 'H0 states no difference, no effect, or no relationship.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'In the context of CFA Level I, the test statistic for a z-test is:', 'Standard error / Sample mean', 'Sample mean / Population mean', '(Sample mean - Hypothesized mean) / Standard error', 'C', 'z = (x-bar - μ0) / (σ/√n).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A financial analyst needs to determine: when testing H0: μ = 50 vs H1: μ > 50, this is a:', 'Two-tailed test', 'One-tailed test (left-tailed)', 'One-tailed test (right-tailed)', 'C', 'H1: μ > 50 is a right-tailed test.', 1, 'mock');
