INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'An analyst is evaluating a scenario. the t-test for paired observations is used when:', 'Samples are dependent', 'Samples are independent', 'Population variance is known', 'A', 'Paired t-test: same subjects measured twice or matched pairs.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'According to CFA curriculum, the F-test is used to:', 'Compare two population variances', 'Compare two population means', 'Test normality', 'A', 'F = s1²/s2², comparing two sample variances.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'In the context of CFA Level I, rejecting H0 when it is false is a:', 'Type I error', 'Type II error', 'Correct decision', 'C', 'Correctly rejecting a false null = desirable outcome (power).', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A financial analyst needs to determine: when testing a hypothesis about the mean with known population variance:', 'Use the z-test', 'Use the t-test', 'Use the chi-square test', 'A', 'Known σ → z-test.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Which of the following is most accurate? for a one-tailed test at 5% significance with z-distribution, the critical value is:', '1.645', '2.576', '1.96', 'A', 'One-tailed 5% → z = 1.645.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'An analyst is evaluating a scenario. the chi-square test is used for:', 'Testing hypotheses about variance', 'Testing correlation', 'Testing hypotheses about the mean', 'A', 'Chi-square tests variance: χ² = (n-1)s²/σ0².', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'According to CFA curriculum, economic significance differs from statistical significance because:', 'A statistically significant result may not be meaningful in practice', 'Economic significance requires larger samples', 'They always agree', 'A', 'Statistical significance doesn''t imply practical importance.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'In the context of CFA Level I, with a larger sample size, a test becomes:', 'Less likely to detect effects', 'More likely to detect small effects', 'Less reliable', 'B', 'Larger n increases power → smaller effects become detectable.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A financial analyst needs to determine: if we cannot reject H0, we should say:', 'We fail to reject H0', 'We accept H0', 'H0 is proven true', 'A', 'Never ''accept'' H0; we simply fail to find sufficient evidence against it.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'Which of the following is most accurate? a test with high power has a:', 'High probability of Type I error', 'Low probability of Type II error', 'Large sample variance', 'B', 'Power = 1 - β; high power means low Type II error.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'An analyst is evaluating a scenario. the p-value is:', 'The probability that H0 is true', 'The probability of a Type II error', 'The smallest significance level at which H0 would be rejected', 'C', 'p-value = probability of observing the test statistic or more extreme, given H0.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'According to CFA curriculum, the significance level (alpha) is:', 'The power of the test', 'The probability of rejecting a true null hypothesis', 'The probability of accepting a false null hypothesis', 'B', 'α = P(Type I error) = P(reject H0 | H0 true).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'In the context of CFA Level I, if the p-value is less than alpha, we:', 'Reject the null hypothesis', 'Accept the null hypothesis', 'Fail to reject the null hypothesis', 'A', 'p-value < α → reject H0.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (8, 'A financial analyst needs to determine: a two-tailed test is appropriate when:', 'We are testing for a difference in either direction', 'We expect only a decrease', 'We expect only an increase', 'A', 'Two-tailed: H1: μ ≠ μ0 (reject for either direction).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'Non-parametric tests are preferred when:', 'Data do not meet the assumptions of parametric tests', 'The sample size is very large', 'The population is normally distributed', 'A', 'Non-parametric tests make fewer distributional assumptions.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'The Spearman rank correlation measures:', 'The monotonic relationship between ranked variables', 'The linear relationship between variables', 'Causation between variables', 'A', 'Spearman uses ranks to assess monotonic (not necessarily linear) association.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'The Mann-Whitney U test is a non-parametric alternative to:', 'The independent samples t-test', 'The paired t-test', 'The chi-square test', 'A', 'Mann-Whitney compares two independent groups without assuming normality.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'The Wilcoxon signed-rank test is a non-parametric alternative to:', 'The paired t-test', 'The independent t-test', 'The F-test', 'A', 'Wilcoxon signed-rank tests paired differences without normality assumption.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'The Kruskal-Wallis test extends the Mann-Whitney U test to:', 'More than two groups', 'Paired samples', 'Time series data', 'A', 'Kruskal-Wallis is the non-parametric ANOVA equivalent for k groups.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'A sign test evaluates:', 'Whether the median differs from a hypothesized value', 'Whether the mean equals zero', 'The variance of a sample', 'A', 'The sign test counts positive and negative deviations from the hypothesized median.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'Chi-square goodness-of-fit test determines:', 'Whether observed frequencies differ from expected frequencies', 'Whether two means are equal', 'The correlation between variables', 'A', 'χ² GOF compares observed vs. expected category frequencies.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'A parametric test for the equality of two variances is the:', 'F-test', 't-test', 'z-test', 'A', 'F = s1²/s2² tests H0: σ1² = σ2².', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'The runs test is used to determine:', 'Whether a sequence of observations is random', 'Whether data is normally distributed', 'The mean of a population', 'A', 'The runs test checks for randomness in a binary sequence.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'An advantage of non-parametric tests is:', 'They can be used with ordinal data', 'They are always more powerful', 'They require larger samples', 'A', 'Non-parametric tests work with ordinal and non-normal data.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'A disadvantage of non-parametric tests is:', 'They generally have less statistical power', 'They require normality', 'They cannot handle outliers', 'A', 'Non-parametric tests are less powerful when parametric assumptions hold.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'The chi-square test of independence determines:', 'Whether two categorical variables are related', 'Whether a mean equals a specific value', 'The variance of a dataset', 'A', 'χ² independence test evaluates association between two categorical variables.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'Rank correlation is robust to:', 'Outliers', 'Large samples', 'Missing data', 'A', 'Ranking data makes correlation measures resistant to extreme values.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'The Jarque-Bera test evaluates:', 'Whether data is normally distributed', 'Whether two variances are equal', 'Whether a mean equals zero', 'A', 'JB test checks normality using skewness and kurtosis.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'For small samples from non-normal populations:', 'Non-parametric tests are more appropriate', 'Parametric tests are always valid', 'No test can be used', 'A', 'Parametric tests may be unreliable for small non-normal samples.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'The Kolmogorov-Smirnov test:', 'Compares a sample distribution with a reference distribution', 'Tests for equal variances', 'Calculates correlation', 'A', 'KS test measures maximum distance between empirical and theoretical CDFs.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'When data are ordinal, the appropriate measure of central tendency is:', 'Median', 'Mean', 'Standard deviation', 'A', 'Median is appropriate for ordinal data; mean requires interval/ratio scale.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'A contingency table is used with:', 'Chi-square test of independence', 't-test', 'F-test', 'A', 'Contingency tables organize data for chi-square independence tests.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'The test statistic for a chi-square GOF test is:', 'Sum of (Observed-Expected)²/Expected', '(X-bar - μ)²/σ²', 's1²/s2²', 'A', 'χ² = Σ(O-E)²/E.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'Bootstrapping is a:', 'Resampling technique that does not assume a specific distribution', 'Parametric method', 'Method requiring normality', 'A', 'Bootstrapping resamples with replacement from the data itself.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'Which of the following is most accurate? non-parametric tests are preferred when:', 'The population is normally distributed', 'Data do not meet the assumptions of parametric tests', 'The sample size is very large', 'B', 'Non-parametric tests make fewer distributional assumptions.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'An analyst is evaluating a scenario. the Spearman rank correlation measures:', 'Causation between variables', 'The monotonic relationship between ranked variables', 'The linear relationship between variables', 'B', 'Spearman uses ranks to assess monotonic (not necessarily linear) association.', 2, 'qbank');
