INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'A financial analyst needs to determine: the Kruskal-Wallis test extends the Mann-Whitney U test to:', 'Time series data', 'Paired samples', 'More than two groups', 'C', 'Kruskal-Wallis is the non-parametric ANOVA equivalent for k groups.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'Which of the following is most accurate? a sign test evaluates:', 'The variance of a sample', 'Whether the median differs from a hypothesized value', 'Whether the mean equals zero', 'B', 'The sign test counts positive and negative deviations from the hypothesized median.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'An analyst is evaluating a scenario. chi-square goodness-of-fit test determines:', 'The correlation between variables', 'Whether two means are equal', 'Whether observed frequencies differ from expected frequencies', 'C', 'χ² GOF compares observed vs. expected category frequencies.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'According to CFA curriculum, a parametric test for the equality of two variances is the:', 'F-test', 't-test', 'z-test', 'A', 'F = s1²/s2² tests H0: σ1² = σ2².', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'In the context of CFA Level I, the runs test is used to determine:', 'Whether a sequence of observations is random', 'Whether data is normally distributed', 'The mean of a population', 'A', 'The runs test checks for randomness in a binary sequence.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'A financial analyst needs to determine: an advantage of non-parametric tests is:', 'They require larger samples', 'They are always more powerful', 'They can be used with ordinal data', 'C', 'Non-parametric tests work with ordinal and non-normal data.', 2, 'qbank');
