INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'According to CFA curriculum, the runs test is used to determine:', 'Whether data is normally distributed', 'Whether a sequence of observations is random', 'The mean of a population', 'B', 'The runs test checks for randomness in a binary sequence.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'In the context of CFA Level I, the Spearman rank correlation measures:', 'The linear relationship between variables', 'Causation between variables', 'The monotonic relationship between ranked variables', 'C', 'Spearman uses ranks to assess monotonic (not necessarily linear) association.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'A financial analyst needs to determine: a sign test evaluates:', 'Whether the mean equals zero', 'Whether the median differs from a hypothesized value', 'The variance of a sample', 'B', 'The sign test counts positive and negative deviations from the hypothesized median.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'Which of the following is most accurate? the Mann-Whitney U test is a non-parametric alternative to:', 'The paired t-test', 'The independent samples t-test', 'The chi-square test', 'B', 'Mann-Whitney compares two independent groups without assuming normality.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'An analyst is evaluating a scenario. the test statistic for a chi-square GOF test is:', 's1²/s2²', '(X-bar - μ)²/σ²', 'Sum of (Observed-Expected)²/Expected', 'C', 'χ² = Σ(O-E)²/E.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'According to CFA curriculum, a contingency table is used with:', 'Chi-square test of independence', 'F-test', 't-test', 'A', 'Contingency tables organize data for chi-square independence tests.', 2, 'mock');
