INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'A financial analyst needs to determine: a parametric test for the equality of two variances is the:', 't-test', 'F-test', 'z-test', 'B', 'F = s1²/s2² tests H0: σ1² = σ2².', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'Which of the following is most accurate? bootstrapping is a:', 'Parametric method', 'Method requiring normality', 'Resampling technique that does not assume a specific distribution', 'C', 'Bootstrapping resamples with replacement from the data itself.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (9, 'An analyst is evaluating a scenario. the Kruskal-Wallis test extends the Mann-Whitney U test to:', 'Time series data', 'More than two groups', 'Paired samples', 'B', 'Kruskal-Wallis is the non-parametric ANOVA equivalent for k groups.', 3, 'mock');
