INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'In simple linear regression, the dependent variable is:', 'The variable being predicted', 'The predictor variable', 'A constant', 'A', 'Y (dependent) is predicted from X (independent).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The R-squared value represents:', 'The proportion of variance in Y explained by X', 'The slope of the regression line', 'The p-value of the test', 'A', 'R² = explained variation / total variation.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The slope coefficient in regression measures:', 'The change in Y for a one-unit change in X', 'The intercept value', 'The correlation coefficient', 'A', 'b1 = ΔY/ΔX.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'If R² = 0.64, the correlation coefficient is:', '0.80 or -0.80', '0.64', '0.36', 'A', 'r = ±√R² = ±√0.64 = ±0.80.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The standard error of estimate (SEE) measures:', 'The dispersion of observations around the regression line', 'The slope''s significance', 'The intercept value', 'A', 'SEE is the standard deviation of residuals.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Heteroscedasticity means:', 'Residual variance is not constant', 'Residuals are normally distributed', 'Variables are independent', 'A', 'Heteroscedasticity: non-constant variance of error terms.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Serial correlation in residuals violates the assumption of:', 'Independent errors', 'Normal errors', 'Constant variance', 'A', 'Autocorrelated residuals violate the independence assumption.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The intercept (b0) represents:', 'The predicted Y when X equals zero', 'The slope of the line', 'The R-squared value', 'A', 'b0 = Y-hat when X = 0.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A residual is:', 'The difference between observed and predicted Y', 'The predicted value of Y', 'The slope coefficient', 'A', 'Residual = Yi - Y-hat_i.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The t-statistic for a slope coefficient tests:', 'Whether the slope is significantly different from zero', 'Whether R² is significant', 'Whether residuals are normal', 'A', 't = b1/SE(b1); tests H0: β1 = 0.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'An F-test in simple regression tests:', 'The overall significance of the model', 'Individual coefficient significance', 'Normality of residuals', 'A', 'F-test: H0: all slope coefficients = 0 (model has no explanatory power).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Multicollinearity is a concern in:', 'Multiple regression, not simple regression', 'Simple regression', 'Non-parametric tests', 'A', 'Multicollinearity involves correlation among independent variables (multiple regression only).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The coefficient of determination can range from:', '0 to 1', '-1 to 1', 'Negative infinity to positive infinity', 'A', 'R² is between 0 (no fit) and 1 (perfect fit).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Regression assumptions include:', 'Linearity, independence, homoscedasticity, and normality of errors', 'Errors must be correlated', 'X must be normally distributed', 'A', 'LINE: Linearity, Independence, Normality, Equal variance.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The predicted value of Y is denoted:', 'Y-hat', 'Y-bar', 'Y*', 'A', 'Y-hat = b0 + b1×X.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'If b1 = 2.5, a one-unit increase in X leads to:', 'A 2.5-unit increase in predicted Y', 'A 2.5% increase in Y', 'No change in Y', 'A', 'Slope of 2.5 means Y increases by 2.5 for each unit increase in X.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The Durbin-Watson statistic tests for:', 'Autocorrelation in residuals', 'Heteroscedasticity', 'Normality', 'A', 'DW ≈ 2 means no autocorrelation; DW < 2 → positive autocorrelation.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A high R² with insignificant coefficients may indicate:', 'Overfitting or multicollinearity', 'A perfect model', 'Normally distributed errors', 'A', 'This pattern can signal multicollinearity in multiple regression or overfitting.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Confidence interval for a predicted Y value is:', 'Narrower at the mean of X', 'Wider at the mean of X', 'Constant for all X', 'A', 'Prediction intervals widen as X moves away from X-bar.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The method of ordinary least squares minimizes:', 'The sum of squared residuals', 'The sum of absolute residuals', 'The sum of residuals', 'A', 'OLS minimizes Σ(Yi - Y-hat_i)².', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Which of the following is most accurate? in simple linear regression, the dependent variable is:', 'The predictor variable', 'A constant', 'The variable being predicted', 'C', 'Y (dependent) is predicted from X (independent).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'An analyst is evaluating a scenario. the R-squared value represents:', 'The slope of the regression line', 'The p-value of the test', 'The proportion of variance in Y explained by X', 'C', 'R² = explained variation / total variation.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'According to CFA curriculum, the slope coefficient in regression measures:', 'The correlation coefficient', 'The intercept value', 'The change in Y for a one-unit change in X', 'C', 'b1 = ΔY/ΔX.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'In the context of CFA Level I, if R² = 0.64, the correlation coefficient is:', '0.64', '0.80 or -0.80', '0.36', 'B', 'r = ±√R² = ±√0.64 = ±0.80.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A financial analyst needs to determine: the standard error of estimate (SEE) measures:', 'The dispersion of observations around the regression line', 'The intercept value', 'The slope''s significance', 'A', 'SEE is the standard deviation of residuals.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Which of the following is most accurate? heteroscedasticity means:', 'Residuals are normally distributed', 'Variables are independent', 'Residual variance is not constant', 'C', 'Heteroscedasticity: non-constant variance of error terms.', 4, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'An analyst is evaluating a scenario. serial correlation in residuals violates the assumption of:', 'Independent errors', 'Normal errors', 'Constant variance', 'A', 'Autocorrelated residuals violate the independence assumption.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'According to CFA curriculum, the intercept (b0) represents:', 'The R-squared value', 'The predicted Y when X equals zero', 'The slope of the line', 'B', 'b0 = Y-hat when X = 0.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'In the context of CFA Level I, a residual is:', 'The difference between observed and predicted Y', 'The slope coefficient', 'The predicted value of Y', 'A', 'Residual = Yi - Y-hat_i.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A financial analyst needs to determine: the t-statistic for a slope coefficient tests:', 'Whether R² is significant', 'Whether the slope is significantly different from zero', 'Whether residuals are normal', 'B', 't = b1/SE(b1); tests H0: β1 = 0.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Which of the following is most accurate? an F-test in simple regression tests:', 'Individual coefficient significance', 'The overall significance of the model', 'Normality of residuals', 'B', 'F-test: H0: all slope coefficients = 0 (model has no explanatory power).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'An analyst is evaluating a scenario. multicollinearity is a concern in:', 'Multiple regression, not simple regression', 'Simple regression', 'Non-parametric tests', 'A', 'Multicollinearity involves correlation among independent variables (multiple regression only).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'According to CFA curriculum, the coefficient of determination can range from:', 'Negative infinity to positive infinity', '-1 to 1', '0 to 1', 'C', 'R² is between 0 (no fit) and 1 (perfect fit).', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'In the context of CFA Level I, regression assumptions include:', 'Errors must be correlated', 'Linearity, independence, homoscedasticity, and normality of errors', 'X must be normally distributed', 'B', 'LINE: Linearity, Independence, Normality, Equal variance.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A financial analyst needs to determine: the predicted value of Y is denoted:', 'Y*', 'Y-hat', 'Y-bar', 'B', 'Y-hat = b0 + b1×X.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Which of the following is most accurate? if b1 = 2.5, a one-unit increase in X leads to:', 'No change in Y', 'A 2.5% increase in Y', 'A 2.5-unit increase in predicted Y', 'C', 'Slope of 2.5 means Y increases by 2.5 for each unit increase in X.', 2, 'qbank');
