INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'According to CFA curriculum, a high R² with insignificant coefficients may indicate:', 'Overfitting or multicollinearity', 'A perfect model', 'Normally distributed errors', 'A', 'This pattern can signal multicollinearity in multiple regression or overfitting.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'In the context of CFA Level I, confidence interval for a predicted Y value is:', 'Narrower at the mean of X', 'Wider at the mean of X', 'Constant for all X', 'A', 'Prediction intervals widen as X moves away from X-bar.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A financial analyst needs to determine: the method of ordinary least squares minimizes:', 'The sum of squared residuals', 'The sum of absolute residuals', 'The sum of residuals', 'A', 'OLS minimizes Σ(Yi - Y-hat_i)².', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Heteroscedasticity means:', 'Residual variance is not constant', 'Residuals are normally distributed', 'Variables are independent', 'A', 'Heteroscedasticity: non-constant variance of error terms.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The t-statistic for a slope coefficient tests:', 'Whether the slope is significantly different from zero', 'Whether R² is significant', 'Whether residuals are normal', 'A', 't = b1/SE(b1); tests H0: β1 = 0.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A residual is:', 'The difference between observed and predicted Y', 'The predicted value of Y', 'The slope coefficient', 'A', 'Residual = Yi - Y-hat_i.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The intercept (b0) represents:', 'The predicted Y when X equals zero', 'The slope of the line', 'The R-squared value', 'A', 'b0 = Y-hat when X = 0.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The method of ordinary least squares minimizes:', 'The sum of squared residuals', 'The sum of absolute residuals', 'The sum of residuals', 'A', 'OLS minimizes Σ(Yi - Y-hat_i)².', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Regression assumptions include:', 'Linearity, independence, homoscedasticity, and normality of errors', 'Errors must be correlated', 'X must be normally distributed', 'A', 'LINE: Linearity, Independence, Normality, Equal variance.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Serial correlation in residuals violates the assumption of:', 'Independent errors', 'Normal errors', 'Constant variance', 'A', 'Autocorrelated residuals violate the independence assumption.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The R-squared value represents:', 'The proportion of variance in Y explained by X', 'The slope of the regression line', 'The p-value of the test', 'A', 'R² = explained variation / total variation.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'The Durbin-Watson statistic tests for:', 'Autocorrelation in residuals', 'Heteroscedasticity', 'Normality', 'A', 'DW ≈ 2 means no autocorrelation; DW < 2 → positive autocorrelation.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A high R² with insignificant coefficients may indicate:', 'Overfitting or multicollinearity', 'A perfect model', 'Normally distributed errors', 'A', 'This pattern can signal multicollinearity in multiple regression or overfitting.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Multicollinearity is a concern in:', 'Multiple regression, not simple regression', 'Simple regression', 'Non-parametric tests', 'A', 'Multicollinearity involves correlation among independent variables (multiple regression only).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'If R² = 0.64, the correlation coefficient is:', '0.80 or -0.80', '0.64', '0.36', 'A', 'r = ±√R² = ±√0.64 = ±0.80.', 2, 'mock');
