INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Which of the following is most accurate? the coefficient of determination can range from:', '-1 to 1', 'Negative infinity to positive infinity', '0 to 1', 'C', 'R² is between 0 (no fit) and 1 (perfect fit).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'An analyst is evaluating a scenario. the standard error of estimate (SEE) measures:', 'The slope''s significance', 'The dispersion of observations around the regression line', 'The intercept value', 'B', 'SEE is the standard deviation of residuals.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'According to CFA curriculum, the slope coefficient in regression measures:', 'The change in Y for a one-unit change in X', 'The intercept value', 'The correlation coefficient', 'A', 'b1 = ΔY/ΔX.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'In the context of CFA Level I, the predicted value of Y is denoted:', 'Y*', 'Y-hat', 'Y-bar', 'B', 'Y-hat = b0 + b1×X.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A financial analyst needs to determine: if b1 = 2.5, a one-unit increase in X leads to:', 'No change in Y', 'A 2.5% increase in Y', 'A 2.5-unit increase in predicted Y', 'C', 'Slope of 2.5 means Y increases by 2.5 for each unit increase in X.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Which of the following is most accurate? heteroscedasticity means:', 'Residual variance is not constant', 'Residuals are normally distributed', 'Variables are independent', 'A', 'Heteroscedasticity: non-constant variance of error terms.', 4, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'An analyst is evaluating a scenario. the t-statistic for a slope coefficient tests:', 'Whether residuals are normal', 'Whether the slope is significantly different from zero', 'Whether R² is significant', 'B', 't = b1/SE(b1); tests H0: β1 = 0.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'According to CFA curriculum, a residual is:', 'The predicted value of Y', 'The difference between observed and predicted Y', 'The slope coefficient', 'B', 'Residual = Yi - Y-hat_i.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'In the context of CFA Level I, the intercept (b0) represents:', 'The R-squared value', 'The slope of the line', 'The predicted Y when X equals zero', 'C', 'b0 = Y-hat when X = 0.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A financial analyst needs to determine: the method of ordinary least squares minimizes:', 'The sum of residuals', 'The sum of squared residuals', 'The sum of absolute residuals', 'B', 'OLS minimizes Σ(Yi - Y-hat_i)².', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Which of the following is most accurate? regression assumptions include:', 'X must be normally distributed', 'Errors must be correlated', 'Linearity, independence, homoscedasticity, and normality of errors', 'C', 'LINE: Linearity, Independence, Normality, Equal variance.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'An analyst is evaluating a scenario. serial correlation in residuals violates the assumption of:', 'Normal errors', 'Independent errors', 'Constant variance', 'B', 'Autocorrelated residuals violate the independence assumption.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'According to CFA curriculum, the R-squared value represents:', 'The proportion of variance in Y explained by X', 'The p-value of the test', 'The slope of the regression line', 'A', 'R² = explained variation / total variation.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'In the context of CFA Level I, the Durbin-Watson statistic tests for:', 'Autocorrelation in residuals', 'Normality', 'Heteroscedasticity', 'A', 'DW ≈ 2 means no autocorrelation; DW < 2 → positive autocorrelation.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'A financial analyst needs to determine: a high R² with insignificant coefficients may indicate:', 'A perfect model', 'Normally distributed errors', 'Overfitting or multicollinearity', 'C', 'This pattern can signal multicollinearity in multiple regression or overfitting.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'Which of the following is most accurate? multicollinearity is a concern in:', 'Multiple regression, not simple regression', 'Simple regression', 'Non-parametric tests', 'A', 'Multicollinearity involves correlation among independent variables (multiple regression only).', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'An analyst is evaluating a scenario. if R² = 0.64, the correlation coefficient is:', '0.80 or -0.80', '0.64', '0.36', 'A', 'r = ±√R² = ±√0.64 = ±0.80.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (10, 'According to CFA curriculum, an F-test in simple regression tests:', 'The overall significance of the model', 'Normality of residuals', 'Individual coefficient significance', 'A', 'F-test: H0: all slope coefficients = 0 (model has no explanatory power).', 2, 'mock');
