INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'Big data is characterized by:', 'Volume, velocity, variety, and veracity', 'Only large datasets', 'Structured data exclusively', 'A', 'The 4 V''s define big data characteristics.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'Machine learning differs from traditional statistics in that it:', 'Emphasizes prediction over inference', 'Requires smaller datasets', 'Only uses linear models', 'A', 'ML focuses on predictive accuracy; statistics focuses on parameter estimation and inference.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'Overfitting occurs when:', 'A model fits training data too closely and performs poorly on new data', 'A model is too simple', 'Training error is high', 'A', 'Overfitting: low training error but high test error due to modeling noise.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'Cross-validation is used to:', 'Assess model performance on unseen data', 'Increase sample size', 'Eliminate outliers', 'A', 'k-fold cross-validation estimates out-of-sample performance.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'A decision tree:', 'Splits data recursively based on feature values', 'Is always a linear model', 'Requires normally distributed data', 'A', 'Decision trees partition the feature space using if-then rules.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'Random forests improve on decision trees by:', 'Combining many trees to reduce variance', 'Using a single deeper tree', 'Eliminating all features', 'A', 'Bagging multiple trees (random forests) reduces overfitting.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'Regularization in machine learning:', 'Penalizes model complexity to prevent overfitting', 'Increases the number of features', 'Removes all constraints', 'A', 'Regularization (L1/L2) adds a penalty term to the loss function.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'LASSO regression performs:', 'Feature selection by shrinking some coefficients to zero', 'Ridge regression', 'Standard OLS', 'A', 'LASSO (L1 penalty) can set coefficients exactly to zero, performing variable selection.', 3, 'qbank');
