INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'A financial analyst needs to determine: text analytics in finance can:', 'Assess sentiment from news articles and reports', 'Only process structured data', 'Replace fundamental analysis entirely', 'A', 'Sentiment analysis from text provides alternative data for investment decisions.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'Which of the following is most accurate? k-means clustering:', 'Partitions data into k groups based on similarity', 'Is a supervised learning algorithm', 'Requires labeled data', 'A', 'K-means is unsupervised, grouping observations by minimizing within-cluster variance.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'An analyst is evaluating a scenario. natural language processing (NLP) is used to:', 'Perform linear regression', 'Process only numerical data', 'Analyze and extract information from text data', 'C', 'NLP applies ML techniques to human language text.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'According to CFA curriculum, feature engineering involves:', 'Creating new input variables from existing data', 'Running the model without features', 'Deleting all variables', 'A', 'Feature engineering transforms raw data into informative model inputs.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'In the context of CFA Level I, overfitting occurs when:', 'A model fits training data too closely and performs poorly on new data', 'Training error is high', 'A model is too simple', 'A', 'Overfitting: low training error but high test error due to modeling noise.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'A financial analyst needs to determine: regularization in machine learning:', 'Removes all constraints', 'Penalizes model complexity to prevent overfitting', 'Increases the number of features', 'B', 'Regularization (L1/L2) adds a penalty term to the loss function.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'Which of the following is most accurate? cross-validation is used to:', 'Assess model performance on unseen data', 'Eliminate outliers', 'Increase sample size', 'A', 'k-fold cross-validation estimates out-of-sample performance.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'An analyst is evaluating a scenario. deep learning uses:', 'Neural networks with many hidden layers', 'Only one layer', 'Simple linear models', 'A', 'Deep learning = neural networks with multiple hidden layers.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (11, 'According to CFA curriculum, structured data is:', 'Always big data', 'Organized in a predefined format like tables', 'Unorganized text or images', 'B', 'Structured data fits rows/columns; unstructured includes text, images, video.', 1, 'mock');
