INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'A bond''s par value is also known as its:', 'Face value or principal', 'Market price', 'Coupon rate', 'A', 'Par value = face value = the amount repaid at maturity.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'A coupon rate is the:', 'Annual interest rate paid on a bond''s face value', 'Yield to maturity', 'Current yield', 'A', 'Coupon rate determines the periodic interest payment.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'A zero-coupon bond:', 'Pays no periodic interest and is sold at a discount', 'Pays interest monthly', 'Has a floating rate', 'A', 'Zero-coupon bonds provide return solely through price appreciation.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'The indenture of a bond is:', 'The legal contract between issuer and bondholders', 'The coupon payment schedule', 'The credit rating', 'A', 'The indenture specifies all terms and covenants of the bond.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'An embedded option in a bond refers to:', 'A provision that gives the issuer or bondholder certain rights', 'The bond''s credit rating', 'The bond''s tax treatment', 'A', 'Embedded options include call, put, and conversion features.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'A callable bond can be:', 'Redeemed by the issuer before maturity', 'Sold by the bondholder back to the issuer', 'Converted to equity', 'A', 'A call option benefits the issuer by allowing early redemption.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'A putable bond can be:', 'Sold back to the issuer by the bondholder before maturity', 'Called by the issuer', 'Converted to a floating rate', 'A', 'A put option benefits the bondholder by allowing early sale.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'Covenants in a bond indenture are:', 'Restrictions placed on the issuer to protect bondholders', 'Payment schedules', 'Tax provisions', 'A', 'Covenants limit issuer actions (negative) or require actions (affirmative).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'An affirmative covenant requires the issuer to:', 'Take specific actions like maintaining insurance', 'Refrain from certain actions', 'Pay higher coupons', 'A', 'Affirmative covenants specify what the issuer must do.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'A negative covenant restricts the issuer from:', 'Taking certain actions like issuing additional debt', 'Making coupon payments', 'Reporting financial results', 'A', 'Negative covenants limit issuer actions that could harm bondholders.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'The maturity of a bond is:', 'The date when the principal is repaid', 'The first coupon payment date', 'The date the bond was issued', 'A', 'Maturity = the date the issuer repays the face value.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'A floating-rate note has:', 'A coupon that adjusts periodically based on a reference rate', 'A fixed coupon', 'No coupon payments', 'A', 'FRN coupons reset based on rates like SOFR plus a spread.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (12, 'Bonds with credit enhancements:', 'Have features that reduce credit risk for investors', 'Always have higher yields', 'Cannot default', 'A', 'Credit enhancements (guarantees, collateral) reduce perceived risk.', 2, 'qbank');
