INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (14, 'In the context of CFA Level I, the coupon rate on a new bond is primarily determined by:', 'Prevailing market interest rates and the issuer''s credit quality', 'Past coupon rates on similar bonds', 'The bond''s maturity only', 'A', 'Market rates and credit risk are the primary determinants of coupon rates.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (14, 'A financial analyst needs to determine: a bond with an original issue discount (OID):', 'Is issued above par value', 'Is issued below par value', 'Is issued at par', 'B', 'OID bonds are sold below face value; the discount accretes to par over time.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (14, 'Which of the following is most accurate? the primary market for bonds refers to:', 'The derivatives market', 'The market where bonds are traded after issuance', 'The market where new bonds are initially sold', 'C', 'Primary market = initial issuance; secondary market = subsequent trading.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (14, 'An analyst is evaluating a scenario. an underwriter in a bond issuance:', 'Buys bonds in the secondary market', 'Purchases bonds from the issuer and resells them to investors', 'Only advises the issuer', 'B', 'Underwriters bear the risk of distribution in firm commitment offerings.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (14, 'According to CFA curriculum, best efforts underwriting means:', 'The underwriter will try to sell the bonds but doesn''t guarantee all will be sold', 'The issuer sells directly to investors', 'The underwriter buys all bonds', 'A', 'Best efforts: underwriter acts as agent, no guarantee of full placement.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (14, 'In the context of CFA Level I, the secondary market for bonds is mostly:', 'Exchange-traded', 'Conducted through auctions', 'Over-the-counter (OTC)', 'C', 'Most bonds trade OTC through dealer networks, not on exchanges.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (14, 'A financial analyst needs to determine: a syndicate in bond issuance is:', 'A regulatory body', 'A group of underwriters that share the risk of distribution', 'A single dealer', 'B', 'Syndicates distribute the underwriting risk among multiple banks.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (14, 'Which of the following is most accurate? a shelf registration allows issuers to:', 'Avoid all regulatory requirements', 'Issue unlimited bonds', 'Register securities in advance for later issuance', 'C', 'Shelf registration enables flexible timing of issuance over a period.', 3, 'qbank');
