INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (14, 'According to CFA curriculum, bid-ask spread in bond trading represents:', 'The credit spread', 'The bond''s coupon', 'The dealer''s compensation for providing liquidity', 'C', 'Bid-ask spread = dealer profit = ask price - bid price.', 1, 'qbank');
