INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Secured corporate bonds have:', 'Specific assets pledged as collateral', 'No collateral backing', 'Government guarantee', 'A', 'Secured bonds have specific assets backing them, reducing credit risk.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'A mortgage bond is secured by:', 'Real estate or property', 'Accounts receivable', 'Inventory', 'A', 'Mortgage bonds are backed by a lien on real property.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Debentures are:', 'Unsecured corporate bonds backed only by general creditworthiness', 'Always secured by assets', 'Government bonds', 'A', 'Debentures are unsecured; they rely on the issuer''s credit quality.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'The priority of claims in bankruptcy (highest to lowest) is:', 'Secured debt, senior unsecured, subordinated, equity', 'Equity, subordinated, senior unsecured, secured', 'All claims are equal', 'A', 'Absolute priority: secured > senior unsecured > subordinated > equity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Commercial paper is:', 'Short-term unsecured corporate debt typically maturing in less than 270 days', 'Long-term corporate bonds', 'Government securities', 'A', 'CP is a money market instrument used for short-term financing.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'A credit spread represents:', 'The yield difference between a corporate bond and a comparable government bond', 'The coupon rate', 'The bid-ask spread', 'A', 'Credit spread = corporate yield - risk-free yield, compensating for default risk.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Bank loans differ from bonds primarily in:', 'Being typically negotiated with a smaller group of lenders', 'Having longer maturities', 'Being publicly traded', 'A', 'Bank loans are private, negotiated instruments; bonds are typically more standardized.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'A leveraged loan is:', 'A loan to a company with high levels of existing debt', 'A government-guaranteed loan', 'A loan at below-market rates', 'A', 'Leveraged loans are to highly indebted (often below investment grade) borrowers.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Collateralized loan obligations (CLOs) are:', 'Structured products backed by a pool of leveraged loans', 'Individual corporate bonds', 'Government securities', 'A', 'CLOs securitize pools of leveraged loans into tranches.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'The recovery rate on a defaulted bond is:', 'The percentage of par value recovered by bondholders', 'Always 100%', 'The coupon rate', 'A', 'Recovery rates vary by seniority; secured debt typically recovers more.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Investment-grade corporate bonds typically have:', 'Lower yields and lower default risk than high-yield bonds', 'Higher yields', 'No credit ratings', 'A', 'Higher credit quality = lower yield = lower default probability.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Fallen angels are bonds that:', 'Were originally investment grade but downgraded to high yield', 'Are newly issued high-yield bonds', 'Have been called', 'A', 'Fallen angels were downgraded from investment grade to speculative.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Rising stars are bonds that:', 'Were originally high yield but upgraded to investment grade', 'Are newly issued investment-grade bonds', 'Have increasing coupons', 'A', 'Rising stars are upgraded from high yield to investment grade.', 2, 'qbank');
