INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'According to CFA curriculum, rising stars are bonds that:', 'Are newly issued investment-grade bonds', 'Were originally high yield but upgraded to investment grade', 'Have increasing coupons', 'B', 'Rising stars are upgraded from high yield to investment grade.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'In the context of CFA Level I, cross-default provisions mean:', 'Defaults are limited to one jurisdiction', 'Only one bond can default at a time', 'Default on one obligation triggers default on other obligations', 'C', 'Cross-default: defaulting on any debt can trigger defaults across all debt.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'A financial analyst needs to determine: the yield on a corporate bond includes compensation for:', 'Only interest rate risk', 'Only credit risk', 'Credit risk, liquidity risk, and term premium', 'C', 'Corporate bond yields include multiple risk premiums above the risk-free rate.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Which of the following is most accurate? a make-whole call provision:', 'Requires the issuer to pay a premium based on present value of remaining cash flows', 'Gives bondholders a put option', 'Allows the issuer to call at par', 'A', 'Make-whole calls compensate bondholders for reinvestment risk when bonds are called.', 4, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'An analyst is evaluating a scenario. maintenance covenants:', 'Only apply at the time of issuance', 'Require the issuer to meet financial thresholds on an ongoing basis', 'Are found only in bonds, not loans', 'B', 'Maintenance covenants are tested regularly (common in loans).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'According to CFA curriculum, incurrence covenants:', 'Are triggered only when the issuer takes specific actions', 'Are stricter than maintenance covenants', 'Are tested regularly', 'A', 'Incurrence covenants only apply when the issuer proposes an action (common in bonds).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'In the context of CFA Level I, a credit facility:', 'Is an arrangement with a bank to provide funding', 'Has no credit risk', 'Is a type of bond', 'A', 'Credit facilities (revolvers, term loans) provide flexible bank financing.', 2, 'qbank');
