INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'In the context of CFA Level I, investment-grade corporate bonds typically have:', 'Higher yields', 'Lower yields and lower default risk than high-yield bonds', 'No credit ratings', 'B', 'Higher credit quality = lower yield = lower default probability.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'A financial analyst needs to determine: a mortgage bond is secured by:', 'Accounts receivable', 'Inventory', 'Real estate or property', 'C', 'Mortgage bonds are backed by a lien on real property.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Which of the following is most accurate? bank loans differ from bonds primarily in:', 'Being typically negotiated with a smaller group of lenders', 'Having longer maturities', 'Being publicly traded', 'A', 'Bank loans are private, negotiated instruments; bonds are typically more standardized.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'An analyst is evaluating a scenario. the yield on a corporate bond includes compensation for:', 'Only credit risk', 'Only interest rate risk', 'Credit risk, liquidity risk, and term premium', 'C', 'Corporate bond yields include multiple risk premiums above the risk-free rate.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'According to CFA curriculum, maintenance covenants:', 'Are found only in bonds, not loans', 'Only apply at the time of issuance', 'Require the issuer to meet financial thresholds on an ongoing basis', 'C', 'Maintenance covenants are tested regularly (common in loans).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'In the context of CFA Level I, a leveraged loan is:', 'A loan to a company with high levels of existing debt', 'A government-guaranteed loan', 'A loan at below-market rates', 'A', 'Leveraged loans are to highly indebted (often below investment grade) borrowers.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'A financial analyst needs to determine: a make-whole call provision:', 'Requires the issuer to pay a premium based on present value of remaining cash flows', 'Allows the issuer to call at par', 'Gives bondholders a put option', 'A', 'Make-whole calls compensate bondholders for reinvestment risk when bonds are called.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Which of the following is most accurate? cross-default provisions mean:', 'Defaults are limited to one jurisdiction', 'Only one bond can default at a time', 'Default on one obligation triggers default on other obligations', 'C', 'Cross-default: defaulting on any debt can trigger defaults across all debt.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'An analyst is evaluating a scenario. covenants benefit bondholders by:', 'Restricting issuer actions that could increase risk', 'Guaranteeing principal repayment', 'Increasing the coupon rate', 'A', 'Covenants provide protective limits on issuer behavior.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'According to CFA curriculum, commercial paper is:', 'Long-term corporate bonds', 'Government securities', 'Short-term unsecured corporate debt typically maturing in less than 270 days', 'C', 'CP is a money market instrument used for short-term financing.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'In the context of CFA Level I, secured corporate bonds have:', 'Specific assets pledged as collateral', 'No collateral backing', 'Government guarantee', 'A', 'Secured bonds have specific assets backing them, reducing credit risk.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'A financial analyst needs to determine: rising stars are bonds that:', 'Have increasing coupons', 'Were originally high yield but upgraded to investment grade', 'Are newly issued investment-grade bonds', 'B', 'Rising stars are upgraded from high yield to investment grade.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'Which of the following is most accurate? a credit facility:', 'Is a type of bond', 'Is an arrangement with a bank to provide funding', 'Has no credit risk', 'B', 'Credit facilities (revolvers, term loans) provide flexible bank financing.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'An analyst is evaluating a scenario. fallen angels are bonds that:', 'Are newly issued high-yield bonds', 'Were originally investment grade but downgraded to high yield', 'Have been called', 'B', 'Fallen angels were downgraded from investment grade to speculative.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'According to CFA curriculum, the priority of claims in bankruptcy (highest to lowest) is:', 'Secured debt, senior unsecured, subordinated, equity', 'All claims are equal', 'Equity, subordinated, senior unsecured, secured', 'A', 'Absolute priority: secured > senior unsecured > subordinated > equity.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'In the context of CFA Level I, the recovery rate on a defaulted bond is:', 'The percentage of par value recovered by bondholders', 'Always 100%', 'The coupon rate', 'A', 'Recovery rates vary by seniority; secured debt typically recovers more.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (15, 'A financial analyst needs to determine: a credit spread represents:', 'The coupon rate', 'The bid-ask spread', 'The yield difference between a corporate bond and a comparable government bond', 'C', 'Credit spread = corporate yield - risk-free yield, compensating for default risk.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (16, 'Treasury bills are:', 'Short-term government securities sold at a discount with no coupon', 'Long-term government bonds', 'Corporate securities', 'A', 'T-bills mature in one year or less, issued at a discount to face value.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (16, 'Treasury notes have maturities of:', '2 to 10 years', 'Less than 1 year', 'Over 30 years', 'A', 'T-notes: 2-10 year maturities with semiannual coupons.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (16, 'Treasury bonds have maturities of:', 'More than 10 years (typically 20 or 30 years)', '1 to 5 years', 'Less than 1 year', 'A', 'T-bonds are long-term government securities, usually 20-30 years.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (16, 'On-the-run securities are:', 'The most recently issued Treasury securities of a given maturity', 'Off-the-run older issues', 'Corporate bonds', 'A', 'On-the-run issues are the most liquid, recently auctioned Treasuries.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (16, 'Sovereign debt risk depends on:', 'The government''s ability and willingness to pay', 'Only the country''s GDP', 'The currency denomination only', 'A', 'Sovereign risk = capacity (economic) + willingness (political) to repay.', 2, 'qbank');
