INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'A bond''s price is the:', 'Present value of all future cash flows', 'Sum of all coupon payments', 'Future value at maturity', 'A', 'Bond price = PV of coupons + PV of par value.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'When market yield equals the coupon rate, the bond trades at:', 'Par', 'A premium', 'A discount', 'A', 'At par: coupon rate = market yield → price = face value.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'When market yield exceeds the coupon rate, the bond trades at:', 'A discount', 'A premium', 'Par', 'A', 'Discount bond: market yield > coupon rate → price < par.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'When market yield is below the coupon rate, the bond trades at:', 'A premium', 'A discount', 'Par', 'A', 'Premium bond: market yield < coupon rate → price > par.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'As a bond approaches maturity, its price:', 'Converges toward par value (pull to par effect)', 'Always increases', 'Always decreases', 'A', 'Regardless of premium or discount, price converges to par at maturity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'The relationship between bond price and yield is:', 'Inverse and convex', 'Direct and linear', 'Inverse and linear', 'A', 'Bond prices fall when yields rise, and the relationship is curved (convex).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'A bond''s full price (dirty price) includes:', 'Accrued interest plus the flat (clean) price', 'Only the clean price', 'Only accrued interest', 'A', 'Full/dirty price = clean price + accrued interest.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'The flat price (clean price) of a bond:', 'Does not include accrued interest', 'Includes accrued interest', 'Is always equal to par', 'A', 'Clean price = quoted price = dirty price - accrued interest.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'For a 10% coupon bond with face value $1,000, the annual coupon is:', '$100', '$10', '$1,000', 'A', 'Annual coupon = coupon rate × face value = 10% × $1,000 = $100.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'If yields increase, bond prices:', 'Decrease', 'Increase', 'Remain unchanged', 'A', 'Inverse relationship: higher yields → lower bond prices.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'The price of a zero-coupon bond equals:', 'The present value of the face value at maturity', 'The face value', 'The sum of coupon payments', 'A', 'Zero-coupon: price = par / (1+y)^n.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Matrix pricing is used to:', 'Estimate the price of an illiquid bond from comparable bonds', 'Calculate yield to maturity', 'Determine credit ratings', 'A', 'Matrix pricing uses yields of similar traded bonds to value illiquid ones.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Bond pricing using spot rates:', 'Discounts each cash flow at the appropriate zero-coupon rate', 'Uses a single yield for all cash flows', 'Ignores the term structure', 'A', 'Spot rate pricing matches each cash flow''s maturity to its specific rate.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'A par curve shows:', 'Yields on coupon bonds priced at par across maturities', 'Zero-coupon yields', 'Forward rates', 'A', 'Par curve: yields that make coupon bonds trade at par for each maturity.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Arbitrage-free bond pricing ensures:', 'No risk-free profit can be earned from price discrepancies', 'All bonds have the same price', 'Yields are always positive', 'A', 'Arbitrage-free pricing: bonds are valued using no-arbitrage spot rates.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'For two bonds with the same maturity, the one with the higher coupon:', 'Has less price sensitivity to yield changes', 'Has more price sensitivity', 'Has the same sensitivity', 'A', 'Higher coupons = shorter duration = less price sensitivity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'The day count convention for US Treasury bonds is:', 'Actual/actual', '30/360', 'Actual/365', 'A', 'US Treasuries use actual/actual for accrued interest calculations.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'The price value of a basis point (PVBP):', 'Measures the price change for a 1 basis point yield change', 'Is the bond''s coupon', 'Is always $1', 'A', 'PVBP = price sensitivity to a 0.01% yield change.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'When a bond is between coupon dates, the buyer pays:', 'The full (dirty) price including accrued interest', 'Only the clean price', 'Only the next coupon', 'A', 'The buyer compensates the seller for interest earned since last coupon.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Reinvestment risk for a coupon bond is:', 'The risk that coupons are reinvested at lower rates', 'The risk the issuer defaults', 'The risk of inflation', 'A', 'Reinvestment risk: actual return may differ from YTM if reinvestment rates change.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Which of the following is most accurate? a bond''s price is the:', 'Future value at maturity', 'Sum of all coupon payments', 'Present value of all future cash flows', 'C', 'Bond price = PV of coupons + PV of par value.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'An analyst is evaluating a scenario. when market yield equals the coupon rate, the bond trades at:', 'A premium', 'A discount', 'Par', 'C', 'At par: coupon rate = market yield → price = face value.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'According to CFA curriculum, when market yield exceeds the coupon rate, the bond trades at:', 'A premium', 'A discount', 'Par', 'B', 'Discount bond: market yield > coupon rate → price < par.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'In the context of CFA Level I, when market yield is below the coupon rate, the bond trades at:', 'A premium', 'A discount', 'Par', 'A', 'Premium bond: market yield < coupon rate → price > par.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'A financial analyst needs to determine: as a bond approaches maturity, its price:', 'Always increases', 'Always decreases', 'Converges toward par value (pull to par effect)', 'C', 'Regardless of premium or discount, price converges to par at maturity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Which of the following is most accurate? the relationship between bond price and yield is:', 'Inverse and linear', 'Inverse and convex', 'Direct and linear', 'B', 'Bond prices fall when yields rise, and the relationship is curved (convex).', 3, 'qbank');
