INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Which of the following is most accurate? the price of a zero-coupon bond equals:', 'The face value', 'The sum of coupon payments', 'The present value of the face value at maturity', 'C', 'Zero-coupon: price = par / (1+y)^n.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'An analyst is evaluating a scenario. matrix pricing is used to:', 'Calculate yield to maturity', 'Estimate the price of an illiquid bond from comparable bonds', 'Determine credit ratings', 'B', 'Matrix pricing uses yields of similar traded bonds to value illiquid ones.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'According to CFA curriculum, bond pricing using spot rates:', 'Discounts each cash flow at the appropriate zero-coupon rate', 'Ignores the term structure', 'Uses a single yield for all cash flows', 'A', 'Spot rate pricing matches each cash flow''s maturity to its specific rate.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'In the context of CFA Level I, a par curve shows:', 'Yields on coupon bonds priced at par across maturities', 'Zero-coupon yields', 'Forward rates', 'A', 'Par curve: yields that make coupon bonds trade at par for each maturity.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'A financial analyst needs to determine: arbitrage-free bond pricing ensures:', 'Yields are always positive', 'No risk-free profit can be earned from price discrepancies', 'All bonds have the same price', 'B', 'Arbitrage-free pricing: bonds are valued using no-arbitrage spot rates.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Which of the following is most accurate? for two bonds with the same maturity, the one with the higher coupon:', 'Has the same sensitivity', 'Has more price sensitivity', 'Has less price sensitivity to yield changes', 'C', 'Higher coupons = shorter duration = less price sensitivity.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'An analyst is evaluating a scenario. the day count convention for US Treasury bonds is:', 'Actual/actual', 'Actual/365', '30/360', 'A', 'US Treasuries use actual/actual for accrued interest calculations.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'According to CFA curriculum, the price value of a basis point (PVBP):', 'Is the bond''s coupon', 'Is always $1', 'Measures the price change for a 1 basis point yield change', 'C', 'PVBP = price sensitivity to a 0.01% yield change.', 3, 'qbank');
