INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'According to CFA curriculum, the flat price (clean price) of a bond:', 'Is always equal to par', 'Includes accrued interest', 'Does not include accrued interest', 'C', 'Clean price = quoted price = dirty price - accrued interest.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'In the context of CFA Level I, when market yield is below the coupon rate, the bond trades at:', 'A discount', 'A premium', 'Par', 'B', 'Premium bond: market yield < coupon rate → price > par.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'A financial analyst needs to determine: the price value of a basis point (PVBP):', 'Measures the price change for a 1 basis point yield change', 'Is always $1', 'Is the bond''s coupon', 'A', 'PVBP = price sensitivity to a 0.01% yield change.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Which of the following is most accurate? for a 10% coupon bond with face value $1,000, the annual coupon is:', '$100', '$10', '$1,000', 'A', 'Annual coupon = coupon rate × face value = 10% × $1,000 = $100.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'An analyst is evaluating a scenario. the day count convention for US Treasury bonds is:', 'Actual/365', '30/360', 'Actual/actual', 'C', 'US Treasuries use actual/actual for accrued interest calculations.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'According to CFA curriculum, when a bond is between coupon dates, the buyer pays:', 'Only the next coupon', 'Only the clean price', 'The full (dirty) price including accrued interest', 'C', 'The buyer compensates the seller for interest earned since last coupon.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'In the context of CFA Level I, a bond''s price is the:', 'Present value of all future cash flows', 'Sum of all coupon payments', 'Future value at maturity', 'A', 'Bond price = PV of coupons + PV of par value.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'A financial analyst needs to determine: arbitrage-free bond pricing ensures:', 'No risk-free profit can be earned from price discrepancies', 'All bonds have the same price', 'Yields are always positive', 'A', 'Arbitrage-free pricing: bonds are valued using no-arbitrage spot rates.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Which of the following is most accurate? the relationship between bond price and yield is:', 'Inverse and linear', 'Inverse and convex', 'Direct and linear', 'B', 'Bond prices fall when yields rise, and the relationship is curved (convex).', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'An analyst is evaluating a scenario. when market yield equals the coupon rate, the bond trades at:', 'A discount', 'A premium', 'Par', 'C', 'At par: coupon rate = market yield → price = face value.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'According to CFA curriculum, reinvestment risk for a coupon bond is:', 'The risk the issuer defaults', 'The risk of inflation', 'The risk that coupons are reinvested at lower rates', 'C', 'Reinvestment risk: actual return may differ from YTM if reinvestment rates change.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'In the context of CFA Level I, as a bond approaches maturity, its price:', 'Always increases', 'Converges toward par value (pull to par effect)', 'Always decreases', 'B', 'Regardless of premium or discount, price converges to par at maturity.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'A financial analyst needs to determine: a par curve shows:', 'Yields on coupon bonds priced at par across maturities', 'Forward rates', 'Zero-coupon yields', 'A', 'Par curve: yields that make coupon bonds trade at par for each maturity.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'Which of the following is most accurate? if yields increase, bond prices:', 'Decrease', 'Increase', 'Remain unchanged', 'A', 'Inverse relationship: higher yields → lower bond prices.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'An analyst is evaluating a scenario. bond pricing using spot rates:', 'Uses a single yield for all cash flows', 'Ignores the term structure', 'Discounts each cash flow at the appropriate zero-coupon rate', 'C', 'Spot rate pricing matches each cash flow''s maturity to its specific rate.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'According to CFA curriculum, a bond''s full price (dirty price) includes:', 'Only accrued interest', 'Accrued interest plus the flat (clean) price', 'Only the clean price', 'B', 'Full/dirty price = clean price + accrued interest.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'In the context of CFA Level I, for two bonds with the same maturity, the one with the higher coupon:', 'Has the same sensitivity', 'Has less price sensitivity to yield changes', 'Has more price sensitivity', 'B', 'Higher coupons = shorter duration = less price sensitivity.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (17, 'A financial analyst needs to determine: the price of a zero-coupon bond equals:', 'The present value of the face value at maturity', 'The face value', 'The sum of coupon payments', 'A', 'Zero-coupon: price = par / (1+y)^n.', 2, 'mock');
