INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Yield to maturity (YTM) is:', 'The discount rate that equates bond price with PV of all cash flows', 'The current coupon rate', 'The annual income divided by price', 'A', 'YTM is the IRR of the bond''s cash flows given its market price.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Current yield is calculated as:', 'Annual coupon / Market price', 'Coupon / Par value', 'YTM / Price', 'A', 'Current yield = annual coupon income ÷ current market price.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'The spread over a benchmark yield is called a:', 'G-spread or benchmark spread', 'Current yield', 'Coupon rate', 'A', 'G-spread = corporate bond yield - government benchmark yield.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'The Z-spread is:', 'The constant spread added to each spot rate to equate price with PV of cash flows', 'The yield difference between two bonds', 'The zero-coupon yield', 'A', 'Z-spread is added to each point on the spot rate curve.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'The option-adjusted spread (OAS):', 'Removes the value of embedded options from the Z-spread', 'Includes option value', 'Is always greater than the Z-spread', 'A', 'OAS = Z-spread - option cost; it isolates credit/liquidity spread.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'For a callable bond, the OAS is:', 'Less than the Z-spread', 'Greater than the Z-spread', 'Equal to the Z-spread', 'A', 'OAS < Z-spread for callables because the call option benefits the issuer (positive option cost).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'For a putable bond, the OAS is:', 'Greater than the Z-spread', 'Less than the Z-spread', 'Equal to the Z-spread', 'A', 'OAS > Z-spread for putables because the put option benefits the holder (negative option cost).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Yield to call is:', 'The yield assuming the bond is called at the first call date', 'The yield assuming the bond is held to maturity', 'The coupon rate', 'A', 'YTC uses the call price and call date instead of par and maturity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Yield to worst is:', 'The lowest of YTM, YTC, and other possible yields', 'The highest possible yield', 'The average of all yields', 'A', 'YTW = the minimum yield across all possible call/put scenarios.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A bond equivalent yield (BEY) converts:', 'Non-semiannual yields to a semiannual basis', 'Annual yields to monthly', 'Nominal to real yields', 'A', 'BEY standardizes yields to semiannual compounding for comparison.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'The I-spread is:', 'The yield spread over the swap rate curve', 'The yield spread over Treasuries', 'The inflation-adjusted spread', 'A', 'I-spread = bond yield - interpolated swap rate for same maturity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A nominal spread is the difference between:', 'A bond''s YTM and a benchmark bond''s YTM', 'Two coupon rates', 'The bid and ask yield', 'A', 'Nominal/G-spread = YTM(corporate) - YTM(government benchmark).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'The credit spread on a corporate bond compensates for:', 'Default risk and loss given default', 'Interest rate risk only', 'Liquidity risk only', 'A', 'Credit spread reflects expected loss from default.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Yield spreads tend to widen during:', 'Economic recessions and financial stress', 'Economic expansions', 'Central bank easing', 'A', 'Credit spreads increase during downturns as default risk rises.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'The term structure of credit spreads:', 'Generally slopes upward for investment-grade bonds', 'Is always flat', 'Slopes downward for all bonds', 'A', 'IG credit spreads typically increase with maturity (more time = more uncertainty).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A basis point is equal to:', '0.01%', '0.1%', '1%', 'A', '1 bp = 0.01% = 0.0001.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'For a discount bond, the ranking from lowest to highest is:', 'Coupon rate < current yield < YTM', 'YTM < current yield < coupon rate', 'Current yield < coupon rate < YTM', 'A', 'Discount bond: coupon rate < current yield < YTM.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'For a premium bond, the ranking from lowest to highest is:', 'YTM < current yield < coupon rate', 'Coupon rate < current yield < YTM', 'Current yield < YTM < coupon rate', 'A', 'Premium bond: YTM < current yield < coupon rate.', 2, 'qbank');
