INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'In the context of CFA Level I, the Z-spread is:', 'The zero-coupon yield', 'The yield difference between two bonds', 'The constant spread added to each spot rate to equate price with PV of cash flows', 'C', 'Z-spread is added to each point on the spot rate curve.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A financial analyst needs to determine: the option-adjusted spread (OAS):', 'Removes the value of embedded options from the Z-spread', 'Is always greater than the Z-spread', 'Includes option value', 'A', 'OAS = Z-spread - option cost; it isolates credit/liquidity spread.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Which of the following is most accurate? for a callable bond, the OAS is:', 'Less than the Z-spread', 'Greater than the Z-spread', 'Equal to the Z-spread', 'A', 'OAS < Z-spread for callables because the call option benefits the issuer (positive option cost).', 4, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'An analyst is evaluating a scenario. for a putable bond, the OAS is:', 'Greater than the Z-spread', 'Less than the Z-spread', 'Equal to the Z-spread', 'A', 'OAS > Z-spread for putables because the put option benefits the holder (negative option cost).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'According to CFA curriculum, yield to call is:', 'The coupon rate', 'The yield assuming the bond is held to maturity', 'The yield assuming the bond is called at the first call date', 'C', 'YTC uses the call price and call date instead of par and maturity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'In the context of CFA Level I, yield to worst is:', 'The lowest of YTM, YTC, and other possible yields', 'The average of all yields', 'The highest possible yield', 'A', 'YTW = the minimum yield across all possible call/put scenarios.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A financial analyst needs to determine: a bond equivalent yield (BEY) converts:', 'Annual yields to monthly', 'Non-semiannual yields to a semiannual basis', 'Nominal to real yields', 'B', 'BEY standardizes yields to semiannual compounding for comparison.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Which of the following is most accurate? the I-spread is:', 'The yield spread over Treasuries', 'The yield spread over the swap rate curve', 'The inflation-adjusted spread', 'B', 'I-spread = bond yield - interpolated swap rate for same maturity.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'An analyst is evaluating a scenario. a nominal spread is the difference between:', 'A bond''s YTM and a benchmark bond''s YTM', 'The bid and ask yield', 'Two coupon rates', 'A', 'Nominal/G-spread = YTM(corporate) - YTM(government benchmark).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'According to CFA curriculum, the credit spread on a corporate bond compensates for:', 'Interest rate risk only', 'Liquidity risk only', 'Default risk and loss given default', 'C', 'Credit spread reflects expected loss from default.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'In the context of CFA Level I, yield spreads tend to widen during:', 'Central bank easing', 'Economic recessions and financial stress', 'Economic expansions', 'B', 'Credit spreads increase during downturns as default risk rises.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A financial analyst needs to determine: the term structure of credit spreads:', 'Slopes downward for all bonds', 'Generally slopes upward for investment-grade bonds', 'Is always flat', 'B', 'IG credit spreads typically increase with maturity (more time = more uncertainty).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Which of the following is most accurate? a basis point is equal to:', '1%', '0.01%', '0.1%', 'B', '1 bp = 0.01% = 0.0001.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'An analyst is evaluating a scenario. for a discount bond, the ranking from lowest to highest is:', 'YTM < current yield < coupon rate', 'Current yield < coupon rate < YTM', 'Coupon rate < current yield < YTM', 'C', 'Discount bond: coupon rate < current yield < YTM.', 2, 'qbank');
