INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A bond equivalent yield (BEY) converts:', 'Non-semiannual yields to a semiannual basis', 'Annual yields to monthly', 'Nominal to real yields', 'A', 'BEY standardizes yields to semiannual compounding for comparison.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'For a premium bond, the ranking from lowest to highest is:', 'YTM < current yield < coupon rate', 'Coupon rate < current yield < YTM', 'Current yield < YTM < coupon rate', 'A', 'Premium bond: YTM < current yield < coupon rate.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Yield to maturity (YTM) is:', 'The discount rate that equates bond price with PV of all cash flows', 'The current coupon rate', 'The annual income divided by price', 'A', 'YTM is the IRR of the bond''s cash flows given its market price.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Which of the following is most accurate? the term structure of credit spreads:', 'Is always flat', 'Generally slopes upward for investment-grade bonds', 'Slopes downward for all bonds', 'B', 'IG credit spreads typically increase with maturity (more time = more uncertainty).', 4, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'An analyst is evaluating a scenario. for a discount bond, the ranking from lowest to highest is:', 'Coupon rate < current yield < YTM', 'Current yield < coupon rate < YTM', 'YTM < current yield < coupon rate', 'A', 'Discount bond: coupon rate < current yield < YTM.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'According to CFA curriculum, for a putable bond, the OAS is:', 'Less than the Z-spread', 'Equal to the Z-spread', 'Greater than the Z-spread', 'C', 'OAS > Z-spread for putables because the put option benefits the holder (negative option cost).', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'In the context of CFA Level I, current yield is calculated as:', 'Annual coupon / Market price', 'Coupon / Par value', 'YTM / Price', 'A', 'Current yield = annual coupon income ÷ current market price.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A financial analyst needs to determine: yield to call is:', 'The yield assuming the bond is held to maturity', 'The yield assuming the bond is called at the first call date', 'The coupon rate', 'B', 'YTC uses the call price and call date instead of par and maturity.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Which of the following is most accurate? a basis point is equal to:', '1%', '0.1%', '0.01%', 'C', '1 bp = 0.01% = 0.0001.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'An analyst is evaluating a scenario. yield to worst is:', 'The average of all yields', 'The lowest of YTM, YTC, and other possible yields', 'The highest possible yield', 'B', 'YTW = the minimum yield across all possible call/put scenarios.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'According to CFA curriculum, the Z-spread is:', 'The yield difference between two bonds', 'The zero-coupon yield', 'The constant spread added to each spot rate to equate price with PV of cash flows', 'C', 'Z-spread is added to each point on the spot rate curve.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'In the context of CFA Level I, yield spreads tend to widen during:', 'Economic expansions', 'Economic recessions and financial stress', 'Central bank easing', 'B', 'Credit spreads increase during downturns as default risk rises.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A financial analyst needs to determine: a nominal spread is the difference between:', 'A bond''s YTM and a benchmark bond''s YTM', 'Two coupon rates', 'The bid and ask yield', 'A', 'Nominal/G-spread = YTM(corporate) - YTM(government benchmark).', 2, 'mock');
