INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Which of the following is most accurate? the spread over a benchmark yield is called a:', 'G-spread or benchmark spread', 'Current yield', 'Coupon rate', 'A', 'G-spread = corporate bond yield - government benchmark yield.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'An analyst is evaluating a scenario. a flattening yield curve suggests:', 'All rates are rising equally', 'Short-term rates are falling', 'Long-term rates are declining relative to short-term rates', 'C', 'Curve flattening: the spread between long and short yields narrows.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'According to CFA curriculum, for a callable bond, the OAS is:', 'Greater than the Z-spread', 'Equal to the Z-spread', 'Less than the Z-spread', 'C', 'OAS < Z-spread for callables because the call option benefits the issuer (positive option cost).', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'In the context of CFA Level I, the option-adjusted spread (OAS):', 'Includes option value', 'Removes the value of embedded options from the Z-spread', 'Is always greater than the Z-spread', 'B', 'OAS = Z-spread - option cost; it isolates credit/liquidity spread.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A financial analyst needs to determine: the credit spread on a corporate bond compensates for:', 'Liquidity risk only', 'Interest rate risk only', 'Default risk and loss given default', 'C', 'Credit spread reflects expected loss from default.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'Which of the following is most accurate? the I-spread is:', 'The inflation-adjusted spread', 'The yield spread over the swap rate curve', 'The yield spread over Treasuries', 'B', 'I-spread = bond yield - interpolated swap rate for same maturity.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'An analyst is evaluating a scenario. the benchmark yield curve is important because:', 'It serves as the basis for pricing all other fixed-income securities', 'It determines stock prices', 'It only applies to government bonds', 'A', 'Government yield curves are the foundation for pricing fixed-income assets.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'According to CFA curriculum, a bond equivalent yield (BEY) converts:', 'Nominal to real yields', 'Non-semiannual yields to a semiannual basis', 'Annual yields to monthly', 'B', 'BEY standardizes yields to semiannual compounding for comparison.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'In the context of CFA Level I, for a premium bond, the ranking from lowest to highest is:', 'YTM < current yield < coupon rate', 'Coupon rate < current yield < YTM', 'Current yield < YTM < coupon rate', 'A', 'Premium bond: YTM < current yield < coupon rate.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (18, 'A financial analyst needs to determine: yield to maturity (YTM) is:', 'The annual income divided by price', 'The discount rate that equates bond price with PV of all cash flows', 'The current coupon rate', 'B', 'YTM is the IRR of the bond''s cash flows given its market price.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A mortgage-backed security (MBS) is:', 'A bond backed by a pool of residential or commercial mortgages', 'An unsecured corporate bond', 'A government bill', 'A', 'MBS derive cash flows from underlying mortgage loan payments.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Prepayment risk in MBS refers to:', 'Borrowers paying off mortgages early, reducing expected cash flows', 'The risk of late payments', 'Interest rate risk only', 'A', 'Prepayment risk: homeowners refinance or sell, returning principal early.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Extension risk occurs when:', 'Interest rates rise and prepayments slow, extending the MBS''s life', 'Interest rates fall', 'Borrowers default', 'A', 'Rising rates → fewer refinancings → longer effective maturity for MBS.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Contraction risk occurs when:', 'Interest rates fall and prepayments increase, shortening the MBS''s life', 'Interest rates rise', 'The pool defaults', 'A', 'Falling rates → more refinancings → shorter effective maturity for MBS.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A pass-through MBS:', 'Distributes mortgage payments to investors on a pro-rata basis', 'Has separate tranches', 'Is a derivative instrument', 'A', 'Pass-throughs give each investor a proportional share of all cash flows.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A collateralized mortgage obligation (CMO) is created to:', 'Redistribute prepayment risk among different tranches', 'Eliminate all risk', 'Increase prepayment risk', 'A', 'CMOs tranche MBS cash flows to meet different investor risk preferences.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Sequential-pay CMO tranches receive principal:', 'In a specific order, with the shortest tranche paid first', 'All at the same time', 'In reverse maturity order', 'A', 'Sequential: Tranche A gets all principal first, then B, then C, etc.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A planned amortization class (PAC) tranche:', 'Has more predictable cash flows within a specified prepayment range', 'Bears all prepayment risk', 'Has no support tranche', 'A', 'PAC tranches have priority; companion tranches absorb prepayment variability.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A support (companion) tranche:', 'Absorbs excess prepayment risk to protect PAC tranches', 'Has the most stable cash flows', 'Is the safest tranche', 'A', 'Companion tranches bear higher prepayment variability to stabilize PAC cash flows.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'The Public Securities Association (PSA) model:', 'Provides a benchmark for mortgage prepayment speeds', 'Sets mortgage interest rates', 'Rates credit quality of MBS', 'A', 'PSA model: 100% PSA assumes prepayment rates increase linearly then plateau.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Weighted average maturity (WAM) of an MBS pool:', 'Is the weighted average of remaining maturities of underlying mortgages', 'Is always 30 years', 'Ignores prepayments', 'A', 'WAM reflects the time-weighted remaining term of the mortgage pool.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Weighted average coupon (WAC) is:', 'The weighted average interest rate of mortgages in the pool', 'The MBS coupon paid to investors', 'The servicing fee', 'A', 'WAC = weighted average of mortgage rates in the pool.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Mortgage servicing involves:', 'Collecting payments, managing escrow, and processing defaults', 'Issuing new mortgages', 'Trading MBS in the secondary market', 'A', 'Servicers handle day-to-day mortgage administration for a fee.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Agency MBS carry:', 'Implicit or explicit government guarantee against credit risk', 'No credit protection', 'Only corporate guarantee', 'A', 'Ginnie Mae (explicit), Fannie/Freddie (implicit/conservatorship) provide credit guarantees.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Non-agency MBS:', 'Do not have government credit guarantees', 'Are always risk-free', 'Can only be issued by banks', 'A', 'Private-label MBS rely on credit enhancements rather than government backing.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A stripped MBS separates cash flows into:', 'Interest-only (IO) and principal-only (PO) components', 'Senior and junior tranches', 'Fixed and floating portions', 'A', 'IO strips receive interest; PO strips receive principal payments.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'An IO strip increases in value when:', 'Prepayments slow (higher rates)', 'Prepayments accelerate', 'Interest rates decrease', 'A', 'Slower prepayments mean IO receives interest payments for longer.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A PO strip increases in value when:', 'Prepayments accelerate (lower rates)', 'Prepayments slow', 'Interest rates increase', 'A', 'Faster prepayments return principal sooner, increasing PO''s present value.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Credit enhancement for non-agency MBS includes:', 'Overcollateralization, subordination, and insurance', 'Government guarantees only', 'No enhancement is used', 'A', 'Private MBS use structural and external credit enhancements.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'The single monthly mortality (SMM) rate:', 'Measures the percentage of the pool that prepays in a month', 'Is the annual default rate', 'Is the coupon rate divided by 12', 'A', 'SMM = fraction of outstanding principal that prepays each month.', 3, 'qbank');
