INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A financial analyst needs to determine: a pass-through MBS:', 'Is a derivative instrument', 'Has separate tranches', 'Distributes mortgage payments to investors on a pro-rata basis', 'C', 'Pass-throughs give each investor a proportional share of all cash flows.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Which of the following is most accurate? a collateralized mortgage obligation (CMO) is created to:', 'Eliminate all risk', 'Increase prepayment risk', 'Redistribute prepayment risk among different tranches', 'C', 'CMOs tranche MBS cash flows to meet different investor risk preferences.', 4, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'An analyst is evaluating a scenario. sequential-pay CMO tranches receive principal:', 'In reverse maturity order', 'All at the same time', 'In a specific order, with the shortest tranche paid first', 'C', 'Sequential: Tranche A gets all principal first, then B, then C, etc.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'According to CFA curriculum, a planned amortization class (PAC) tranche:', 'Bears all prepayment risk', 'Has no support tranche', 'Has more predictable cash flows within a specified prepayment range', 'C', 'PAC tranches have priority; companion tranches absorb prepayment variability.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'In the context of CFA Level I, a support (companion) tranche:', 'Is the safest tranche', 'Absorbs excess prepayment risk to protect PAC tranches', 'Has the most stable cash flows', 'B', 'Companion tranches bear higher prepayment variability to stabilize PAC cash flows.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A financial analyst needs to determine: the Public Securities Association (PSA) model:', 'Sets mortgage interest rates', 'Provides a benchmark for mortgage prepayment speeds', 'Rates credit quality of MBS', 'B', 'PSA model: 100% PSA assumes prepayment rates increase linearly then plateau.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Which of the following is most accurate? weighted average maturity (WAM) of an MBS pool:', 'Is always 30 years', 'Is the weighted average of remaining maturities of underlying mortgages', 'Ignores prepayments', 'B', 'WAM reflects the time-weighted remaining term of the mortgage pool.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'An analyst is evaluating a scenario. weighted average coupon (WAC) is:', 'The weighted average interest rate of mortgages in the pool', 'The servicing fee', 'The MBS coupon paid to investors', 'A', 'WAC = weighted average of mortgage rates in the pool.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'According to CFA curriculum, mortgage servicing involves:', 'Trading MBS in the secondary market', 'Issuing new mortgages', 'Collecting payments, managing escrow, and processing defaults', 'C', 'Servicers handle day-to-day mortgage administration for a fee.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'In the context of CFA Level I, agency MBS carry:', 'Only corporate guarantee', 'Implicit or explicit government guarantee against credit risk', 'No credit protection', 'B', 'Ginnie Mae (explicit), Fannie/Freddie (implicit/conservatorship) provide credit guarantees.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A financial analyst needs to determine: non-agency MBS:', 'Do not have government credit guarantees', 'Can only be issued by banks', 'Are always risk-free', 'A', 'Private-label MBS rely on credit enhancements rather than government backing.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Which of the following is most accurate? a stripped MBS separates cash flows into:', 'Fixed and floating portions', 'Interest-only (IO) and principal-only (PO) components', 'Senior and junior tranches', 'B', 'IO strips receive interest; PO strips receive principal payments.', 4, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'An analyst is evaluating a scenario. an IO strip increases in value when:', 'Prepayments slow (higher rates)', 'Prepayments accelerate', 'Interest rates decrease', 'A', 'Slower prepayments mean IO receives interest payments for longer.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'According to CFA curriculum, a PO strip increases in value when:', 'Interest rates increase', 'Prepayments accelerate (lower rates)', 'Prepayments slow', 'B', 'Faster prepayments return principal sooner, increasing PO''s present value.', 3, 'qbank');
