INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'In the context of CFA Level I, the single monthly mortality (SMM) rate:', 'Is the coupon rate divided by 12', 'Is the annual default rate', 'Measures the percentage of the pool that prepays in a month', 'C', 'SMM = fraction of outstanding principal that prepays each month.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A financial analyst needs to determine: a pass-through MBS:', 'Distributes mortgage payments to investors on a pro-rata basis', 'Is a derivative instrument', 'Has separate tranches', 'A', 'Pass-throughs give each investor a proportional share of all cash flows.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Which of the following is most accurate? a PO strip increases in value when:', 'Prepayments slow', 'Interest rates increase', 'Prepayments accelerate (lower rates)', 'C', 'Faster prepayments return principal sooner, increasing PO''s present value.', 4, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'An analyst is evaluating a scenario. an IO strip increases in value when:', 'Interest rates decrease', 'Prepayments accelerate', 'Prepayments slow (higher rates)', 'C', 'Slower prepayments mean IO receives interest payments for longer.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'According to CFA curriculum, weighted average coupon (WAC) is:', 'The weighted average interest rate of mortgages in the pool', 'The MBS coupon paid to investors', 'The servicing fee', 'A', 'WAC = weighted average of mortgage rates in the pool.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'In the context of CFA Level I, mortgage servicing involves:', 'Collecting payments, managing escrow, and processing defaults', 'Trading MBS in the secondary market', 'Issuing new mortgages', 'A', 'Servicers handle day-to-day mortgage administration for a fee.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A financial analyst needs to determine: non-agency MBS:', 'Do not have government credit guarantees', 'Are always risk-free', 'Can only be issued by banks', 'A', 'Private-label MBS rely on credit enhancements rather than government backing.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Which of the following is most accurate? a planned amortization class (PAC) tranche:', 'Bears all prepayment risk', 'Has no support tranche', 'Has more predictable cash flows within a specified prepayment range', 'C', 'PAC tranches have priority; companion tranches absorb prepayment variability.', 4, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'An analyst is evaluating a scenario. a support (companion) tranche:', 'Is the safest tranche', 'Absorbs excess prepayment risk to protect PAC tranches', 'Has the most stable cash flows', 'B', 'Companion tranches bear higher prepayment variability to stabilize PAC cash flows.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'According to CFA curriculum, agency MBS carry:', 'Implicit or explicit government guarantee against credit risk', 'No credit protection', 'Only corporate guarantee', 'A', 'Ginnie Mae (explicit), Fannie/Freddie (implicit/conservatorship) provide credit guarantees.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'In the context of CFA Level I, sequential-pay CMO tranches receive principal:', 'In a specific order, with the shortest tranche paid first', 'In reverse maturity order', 'All at the same time', 'A', 'Sequential: Tranche A gets all principal first, then B, then C, etc.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'A financial analyst needs to determine: contraction risk occurs when:', 'The pool defaults', 'Interest rates rise', 'Interest rates fall and prepayments increase, shortening the MBS''s life', 'C', 'Falling rates → more refinancings → shorter effective maturity for MBS.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'Which of the following is most accurate? a mortgage-backed security (MBS) is:', 'A bond backed by a pool of residential or commercial mortgages', 'An unsecured corporate bond', 'A government bill', 'A', 'MBS derive cash flows from underlying mortgage loan payments.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'An analyst is evaluating a scenario. a stripped MBS separates cash flows into:', 'Fixed and floating portions', 'Senior and junior tranches', 'Interest-only (IO) and principal-only (PO) components', 'C', 'IO strips receive interest; PO strips receive principal payments.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (19, 'According to CFA curriculum, prepayment risk in MBS refers to:', 'The risk of late payments', 'Interest rate risk only', 'Borrowers paying off mortgages early, reducing expected cash flows', 'C', 'Prepayment risk: homeowners refinance or sell, returning principal early.', 2, 'mock');
