INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Duration measures a bond''s:', 'Sensitivity of price to changes in yield', 'Time to maturity', 'Coupon rate', 'A', 'Duration = approximate percentage price change for a 1% yield change.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Macaulay duration is:', 'The weighted average time to receive a bond''s cash flows', 'The same as modified duration', 'Always less than maturity', 'A', 'Macaulay duration weights cash flow timing by PV of each payment.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Modified duration equals:', 'Macaulay duration / (1 + yield per period)', 'Macaulay duration × yield', 'Price / Coupon', 'A', 'ModDur = MacDur / (1 + y/n), measuring price sensitivity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A bond with higher duration has:', 'Greater price sensitivity to yield changes', 'Lower price sensitivity', 'Higher credit risk', 'A', 'Higher duration = larger price change for a given yield movement.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Factors that increase duration include:', 'Lower coupon rate, longer maturity, lower yield', 'Higher coupon, shorter maturity', 'Higher yield only', 'A', 'Lower coupons/yields and longer maturities increase duration.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Convexity measures:', 'The curvature of the price-yield relationship', 'The linear price sensitivity', 'The credit spread', 'A', 'Convexity captures how duration changes as yields change.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Positive convexity means:', 'Price increases more when yields fall than decreases when yields rise', 'Price moves symmetrically', 'Price doesn''t change with yields', 'A', 'Positive convexity benefits the bondholder: gains > losses for equal yield moves.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'For a callable bond, effective convexity can be:', 'Negative at low yields', 'Always positive', 'Zero', 'A', 'Callable bonds exhibit negative convexity when yields fall (price is capped by call).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Effective duration is preferred for bonds with embedded options because:', 'It accounts for how cash flows change with yield changes', 'It''s simpler to calculate', 'It ignores optionality', 'A', 'Effective duration uses actual price changes from yield shifts, capturing option effects.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'The duration of a zero-coupon bond equals:', 'Its maturity', 'Zero', 'Half its maturity', 'A', 'Zero-coupon bond: Macaulay duration = maturity (all cash flow at maturity).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Key rate duration measures:', 'Sensitivity to changes in specific maturity points on the yield curve', 'Overall duration', 'Credit risk sensitivity', 'A', 'Key rate duration isolates price sensitivity to specific tenor yield changes.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Portfolio duration is:', 'The weighted average of individual bond durations', 'The duration of the longest bond', 'The sum of all durations', 'A', 'Portfolio duration = Σ wi × Di, where wi = market value weights.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Money duration is:', 'Modified duration × Market value', 'Duration / Price', 'Duration × Par value', 'A', 'Money duration = dollar price change per unit yield change.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'The approximate percentage price change using duration is:', '-Duration × Change in yield', 'Duration + Convexity', 'Duration / Change in yield', 'A', '%ΔP ≈ -D × Δy (first-order approximation).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Including convexity improves the price estimate by:', 'Adding a second-order correction to the duration estimate', 'Replacing duration', 'Eliminating all estimation error', 'A', '%ΔP ≈ -D × Δy + 0.5 × C × (Δy)², improving accuracy for large yield changes.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A barbell portfolio has:', 'Concentrations at short and long maturities', 'Concentrations at intermediate maturities', 'Equal distribution across all maturities', 'A', 'Barbell: weights in short and long bonds, little in the middle.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A bullet portfolio has:', 'Concentrations at a single maturity point', 'Weights at the extremes', 'No bonds', 'A', 'Bullet: investments clustered around one target maturity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Immunization aims to:', 'Protect a portfolio from interest rate risk by matching duration to the investment horizon', 'Maximize returns', 'Eliminate all risk', 'A', 'Immunization: set portfolio duration = liability duration.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'When yields change, the reinvestment effect and price effect:', 'Partially offset each other', 'Move in the same direction', 'Are unrelated', 'A', 'Rising yields: price falls but reinvestment income rises (and vice versa).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'For a bond investor with a fixed horizon, the optimal strategy is:', 'Match the portfolio duration to the investment horizon', 'Buy the highest-yielding bond', 'Buy the shortest-duration bond', 'A', 'Duration matching immunizes against interest rate changes over the horizon.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Which of the following is most accurate? duration measures a bond''s:', 'Time to maturity', 'Coupon rate', 'Sensitivity of price to changes in yield', 'C', 'Duration = approximate percentage price change for a 1% yield change.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'An analyst is evaluating a scenario. macaulay duration is:', 'The weighted average time to receive a bond''s cash flows', 'Always less than maturity', 'The same as modified duration', 'A', 'Macaulay duration weights cash flow timing by PV of each payment.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'According to CFA curriculum, modified duration equals:', 'Macaulay duration × yield', 'Macaulay duration / (1 + yield per period)', 'Price / Coupon', 'B', 'ModDur = MacDur / (1 + y/n), measuring price sensitivity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'In the context of CFA Level I, a bond with higher duration has:', 'Lower price sensitivity', 'Greater price sensitivity to yield changes', 'Higher credit risk', 'B', 'Higher duration = larger price change for a given yield movement.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A financial analyst needs to determine: factors that increase duration include:', 'Higher coupon, shorter maturity', 'Lower coupon rate, longer maturity, lower yield', 'Higher yield only', 'B', 'Lower coupons/yields and longer maturities increase duration.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Which of the following is most accurate? convexity measures:', 'The linear price sensitivity', 'The credit spread', 'The curvature of the price-yield relationship', 'C', 'Convexity captures how duration changes as yields change.', 4, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'An analyst is evaluating a scenario. positive convexity means:', 'Price moves symmetrically', 'Price increases more when yields fall than decreases when yields rise', 'Price doesn''t change with yields', 'B', 'Positive convexity benefits the bondholder: gains > losses for equal yield moves.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'According to CFA curriculum, for a callable bond, effective convexity can be:', 'Negative at low yields', 'Always positive', 'Zero', 'A', 'Callable bonds exhibit negative convexity when yields fall (price is capped by call).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'In the context of CFA Level I, effective duration is preferred for bonds with embedded options because:', 'It accounts for how cash flows change with yield changes', 'It ignores optionality', 'It''s simpler to calculate', 'A', 'Effective duration uses actual price changes from yield shifts, capturing option effects.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A financial analyst needs to determine: the duration of a zero-coupon bond equals:', 'Zero', 'Its maturity', 'Half its maturity', 'B', 'Zero-coupon bond: Macaulay duration = maturity (all cash flow at maturity).', 2, 'qbank');
