INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A financial analyst needs to determine: the duration of a zero-coupon bond equals:', 'Half its maturity', 'Its maturity', 'Zero', 'B', 'Zero-coupon bond: Macaulay duration = maturity (all cash flow at maturity).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Which of the following is most accurate? key rate duration measures:', 'Credit risk sensitivity', 'Overall duration', 'Sensitivity to changes in specific maturity points on the yield curve', 'C', 'Key rate duration isolates price sensitivity to specific tenor yield changes.', 4, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'An analyst is evaluating a scenario. portfolio duration is:', 'The weighted average of individual bond durations', 'The sum of all durations', 'The duration of the longest bond', 'A', 'Portfolio duration = Σ wi × Di, where wi = market value weights.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'According to CFA curriculum, money duration is:', 'Duration / Price', 'Duration × Par value', 'Modified duration × Market value', 'C', 'Money duration = dollar price change per unit yield change.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'In the context of CFA Level I, the approximate percentage price change using duration is:', 'Duration / Change in yield', '-Duration × Change in yield', 'Duration + Convexity', 'B', '%ΔP ≈ -D × Δy (first-order approximation).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A financial analyst needs to determine: including convexity improves the price estimate by:', 'Adding a second-order correction to the duration estimate', 'Replacing duration', 'Eliminating all estimation error', 'A', '%ΔP ≈ -D × Δy + 0.5 × C × (Δy)², improving accuracy for large yield changes.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Which of the following is most accurate? a barbell portfolio has:', 'Equal distribution across all maturities', 'Concentrations at short and long maturities', 'Concentrations at intermediate maturities', 'B', 'Barbell: weights in short and long bonds, little in the middle.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'An analyst is evaluating a scenario. a bullet portfolio has:', 'Weights at the extremes', 'Concentrations at a single maturity point', 'No bonds', 'B', 'Bullet: investments clustered around one target maturity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'According to CFA curriculum, immunization aims to:', 'Eliminate all risk', 'Maximize returns', 'Protect a portfolio from interest rate risk by matching duration to the investment horizon', 'C', 'Immunization: set portfolio duration = liability duration.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'In the context of CFA Level I, when yields change, the reinvestment effect and price effect:', 'Move in the same direction', 'Are unrelated', 'Partially offset each other', 'C', 'Rising yields: price falls but reinvestment income rises (and vice versa).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A financial analyst needs to determine: for a bond investor with a fixed horizon, the optimal strategy is:', 'Buy the highest-yielding bond', 'Buy the shortest-duration bond', 'Match the portfolio duration to the investment horizon', 'C', 'Duration matching immunizes against interest rate changes over the horizon.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Immunization aims to:', 'Protect a portfolio from interest rate risk by matching duration to the investment horizon', 'Maximize returns', 'Eliminate all risk', 'A', 'Immunization: set portfolio duration = liability duration.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Duration measures a bond''s:', 'Sensitivity of price to changes in yield', 'Time to maturity', 'Coupon rate', 'A', 'Duration = approximate percentage price change for a 1% yield change.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'For a callable bond, effective convexity can be:', 'Negative at low yields', 'Always positive', 'Zero', 'A', 'Callable bonds exhibit negative convexity when yields fall (price is capped by call).', 3, 'mock');
