INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'According to CFA curriculum, a bond with higher duration has:', 'Lower price sensitivity', 'Greater price sensitivity to yield changes', 'Higher credit risk', 'B', 'Higher duration = larger price change for a given yield movement.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'In the context of CFA Level I, positive convexity means:', 'Price moves symmetrically', 'Price increases more when yields fall than decreases when yields rise', 'Price doesn''t change with yields', 'B', 'Positive convexity benefits the bondholder: gains > losses for equal yield moves.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A financial analyst needs to determine: convexity measures:', 'The credit spread', 'The curvature of the price-yield relationship', 'The linear price sensitivity', 'B', 'Convexity captures how duration changes as yields change.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Which of the following is most accurate? a bullet portfolio has:', 'No bonds', 'Weights at the extremes', 'Concentrations at a single maturity point', 'C', 'Bullet: investments clustered around one target maturity.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'An analyst is evaluating a scenario. money duration is:', 'Duration / Price', 'Modified duration × Market value', 'Duration × Par value', 'B', 'Money duration = dollar price change per unit yield change.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'According to CFA curriculum, for a bond investor with a fixed horizon, the optimal strategy is:', 'Buy the highest-yielding bond', 'Buy the shortest-duration bond', 'Match the portfolio duration to the investment horizon', 'C', 'Duration matching immunizes against interest rate changes over the horizon.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'In the context of CFA Level I, the duration of a zero-coupon bond equals:', 'Half its maturity', 'Its maturity', 'Zero', 'B', 'Zero-coupon bond: Macaulay duration = maturity (all cash flow at maturity).', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A financial analyst needs to determine: including convexity improves the price estimate by:', 'Adding a second-order correction to the duration estimate', 'Eliminating all estimation error', 'Replacing duration', 'A', '%ΔP ≈ -D × Δy + 0.5 × C × (Δy)², improving accuracy for large yield changes.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Which of the following is most accurate? the approximate percentage price change using duration is:', 'Duration / Change in yield', '-Duration × Change in yield', 'Duration + Convexity', 'B', '%ΔP ≈ -D × Δy (first-order approximation).', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'An analyst is evaluating a scenario. effective duration is preferred for bonds with embedded options because:', 'It''s simpler to calculate', 'It ignores optionality', 'It accounts for how cash flows change with yield changes', 'C', 'Effective duration uses actual price changes from yield shifts, capturing option effects.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'According to CFA curriculum, macaulay duration is:', 'The weighted average time to receive a bond''s cash flows', 'The same as modified duration', 'Always less than maturity', 'A', 'Macaulay duration weights cash flow timing by PV of each payment.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'In the context of CFA Level I, modified duration equals:', 'Price / Coupon', 'Macaulay duration / (1 + yield per period)', 'Macaulay duration × yield', 'B', 'ModDur = MacDur / (1 + y/n), measuring price sensitivity.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'A financial analyst needs to determine: a barbell portfolio has:', 'Concentrations at intermediate maturities', 'Concentrations at short and long maturities', 'Equal distribution across all maturities', 'B', 'Barbell: weights in short and long bonds, little in the middle.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'Which of the following is most accurate? immunization aims to:', 'Eliminate all risk', 'Protect a portfolio from interest rate risk by matching duration to the investment horizon', 'Maximize returns', 'B', 'Immunization: set portfolio duration = liability duration.', 4, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'An analyst is evaluating a scenario. duration measures a bond''s:', 'Coupon rate', 'Sensitivity of price to changes in yield', 'Time to maturity', 'B', 'Duration = approximate percentage price change for a 1% yield change.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'According to CFA curriculum, for a callable bond, effective convexity can be:', 'Zero', 'Negative at low yields', 'Always positive', 'B', 'Callable bonds exhibit negative convexity when yields fall (price is capped by call).', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (20, 'In the context of CFA Level I, when yields change, the reinvestment effect and price effect:', 'Partially offset each other', 'Move in the same direction', 'Are unrelated', 'A', 'Rising yields: price falls but reinvestment income rises (and vice versa).', 2, 'mock');
