INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Credit risk is the risk that:', 'A borrower fails to make promised payments', 'Interest rates rise', 'Inflation increases', 'A', 'Credit risk = default risk + loss severity risk.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'The probability of default (POD) measures:', 'The likelihood that a borrower will fail to pay', 'The recovery amount after default', 'The credit spread', 'A', 'POD is the estimated probability of a credit event occurring.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Loss given default (LGD) is:', 'The percentage of exposure lost when default occurs', 'The probability of default', 'The total amount owed', 'A', 'LGD = 1 - Recovery rate.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Expected loss equals:', 'Probability of default × Loss given default × Exposure', 'Credit spread × Duration', 'Default rate × Interest rate', 'A', 'EL = PD × LGD × EAD.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Credit ratings are assigned by:', 'Independent rating agencies like Moody''s, S&P, and Fitch', 'Central banks', 'The issuers themselves', 'A', 'Rating agencies provide independent assessments of creditworthiness.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'An upgrade in credit rating typically:', 'Reduces the bond''s yield spread', 'Increases the yield spread', 'Has no effect on price', 'A', 'Better credit → lower perceived risk → lower required yield.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Credit migration risk is:', 'The risk of a credit rating change', 'The risk of default', 'Interest rate risk', 'A', 'Migration risk: downgrades increase yields and reduce prices.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Structural models of credit risk:', 'Model default based on the firm''s asset value falling below debt value', 'Use only historical default rates', 'Ignore firm value', 'A', 'Structural models (Merton): default occurs when assets < liabilities.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Reduced-form models:', 'Model default as a statistical process with a hazard rate', 'Require knowledge of firm''s balance sheet', 'Are based on option pricing', 'A', 'Reduced-form: default is modeled statistically using hazard/intensity rates.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'A credit default swap (CDS):', 'Transfers credit risk from the protection buyer to the seller', 'Eliminates interest rate risk', 'Is an equity derivative', 'A', 'CDS: buyer pays periodic premiums; seller pays if credit event occurs.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'High-yield bonds have:', 'Higher credit risk and higher yields', 'Lower credit risk', 'Government guarantees', 'A', 'Below investment grade: higher default probability → higher yield.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'The recovery rate:', 'Varies by seniority and collateral', 'Is always 40%', 'Is the same for all bonds', 'A', 'Secured senior debt typically recovers more than subordinated unsecured.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Spread risk is:', 'The risk that credit spreads widen, reducing bond prices', 'Only related to government bonds', 'The bid-ask spread risk', 'A', 'Credit spread widening → price decline for corporate bonds.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Credit analysis includes:', 'Evaluating capacity, collateral, covenants, and character', 'Only reviewing financial statements', 'Only checking the credit rating', 'A', 'The 4 C''s of credit analysis provide a comprehensive assessment.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Capacity in credit analysis refers to:', 'The borrower''s ability to make payments from cash flows', 'The value of pledged assets', 'The quality of management', 'A', 'Capacity = cash flow generation ability to service debt obligations.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'A credit event includes:', 'Default, bankruptcy, or restructuring', 'A credit upgrade', 'An interest rate change', 'A', 'Credit events trigger CDS payments and are defined in credit documentation.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'The credit spread puzzle refers to:', 'Corporate bond spreads being wider than expected from default losses alone', 'Spreads always being too narrow', 'Government bonds having credit risk', 'A', 'Actual spreads exceed what default probabilities alone justify.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Cross-default provisions in bond covenants:', 'Allow bondholders to accelerate payment if the issuer defaults on other obligations', 'Prevent default on other bonds', 'Are never included in covenants', 'A', 'Cross-default protects bondholders by triggering default across all obligations.', 2, 'qbank');
