INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Sovereign credit risk assessment considers:', 'Economic strength, institutional framework, and fiscal position', 'Only GDP growth', 'Only political stability', 'A', 'Sovereign analysis integrates economic, institutional, fiscal, and external factors.', 2, 'qbank');
