INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Which of the following is most accurate? an upgrade in credit rating typically:', 'Increases the yield spread', 'Has no effect on price', 'Reduces the bond''s yield spread', 'C', 'Better credit → lower perceived risk → lower required yield.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'An analyst is evaluating a scenario. credit migration risk is:', 'The risk of default', 'Interest rate risk', 'The risk of a credit rating change', 'C', 'Migration risk: downgrades increase yields and reduce prices.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'According to CFA curriculum, structural models of credit risk:', 'Model default based on the firm''s asset value falling below debt value', 'Use only historical default rates', 'Ignore firm value', 'A', 'Structural models (Merton): default occurs when assets < liabilities.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'In the context of CFA Level I, reduced-form models:', 'Are based on option pricing', 'Model default as a statistical process with a hazard rate', 'Require knowledge of firm''s balance sheet', 'B', 'Reduced-form: default is modeled statistically using hazard/intensity rates.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'A financial analyst needs to determine: a credit default swap (CDS):', 'Transfers credit risk from the protection buyer to the seller', 'Is an equity derivative', 'Eliminates interest rate risk', 'A', 'CDS: buyer pays periodic premiums; seller pays if credit event occurs.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Which of the following is most accurate? high-yield bonds have:', 'Lower credit risk', 'Higher credit risk and higher yields', 'Government guarantees', 'B', 'Below investment grade: higher default probability → higher yield.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'An analyst is evaluating a scenario. the recovery rate:', 'Is always 40%', 'Varies by seniority and collateral', 'Is the same for all bonds', 'B', 'Secured senior debt typically recovers more than subordinated unsecured.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'According to CFA curriculum, spread risk is:', 'Only related to government bonds', 'The risk that credit spreads widen, reducing bond prices', 'The bid-ask spread risk', 'B', 'Credit spread widening → price decline for corporate bonds.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'In the context of CFA Level I, credit analysis includes:', 'Only checking the credit rating', 'Evaluating capacity, collateral, covenants, and character', 'Only reviewing financial statements', 'B', 'The 4 C''s of credit analysis provide a comprehensive assessment.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'A financial analyst needs to determine: capacity in credit analysis refers to:', 'The quality of management', 'The value of pledged assets', 'The borrower''s ability to make payments from cash flows', 'C', 'Capacity = cash flow generation ability to service debt obligations.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Which of the following is most accurate? a credit event includes:', 'Default, bankruptcy, or restructuring', 'An interest rate change', 'A credit upgrade', 'A', 'Credit events trigger CDS payments and are defined in credit documentation.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'An analyst is evaluating a scenario. the credit spread puzzle refers to:', 'Government bonds having credit risk', 'Spreads always being too narrow', 'Corporate bond spreads being wider than expected from default losses alone', 'C', 'Actual spreads exceed what default probabilities alone justify.', 3, 'qbank');
