INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'In the context of CFA Level I, credit risk is the risk that:', 'A borrower fails to make promised payments', 'Interest rates rise', 'Inflation increases', 'A', 'Credit risk = default risk + loss severity risk.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'A financial analyst needs to determine: credit migration risk is:', 'The risk of a credit rating change', 'Interest rate risk', 'The risk of default', 'A', 'Migration risk: downgrades increase yields and reduce prices.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Which of the following is most accurate? credit analysis includes:', 'Evaluating capacity, collateral, covenants, and character', 'Only checking the credit rating', 'Only reviewing financial statements', 'A', 'The 4 C''s of credit analysis provide a comprehensive assessment.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'An analyst is evaluating a scenario. counter-party credit risk in derivatives:', 'Only applies to exchange-traded derivatives', 'Is the risk that the other party fails to honor the contract', 'Is eliminated by collateral', 'B', 'OTC derivatives carry counterparty risk; exchanges mitigate this via clearing.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'According to CFA curriculum, sovereign credit risk assessment considers:', 'Only political stability', 'Only GDP growth', 'Economic strength, institutional framework, and fiscal position', 'C', 'Sovereign analysis integrates economic, institutional, fiscal, and external factors.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'In the context of CFA Level I, cross-default provisions in bond covenants:', 'Are never included in covenants', 'Prevent default on other bonds', 'Allow bondholders to accelerate payment if the issuer defaults on other obligations', 'C', 'Cross-default protects bondholders by triggering default across all obligations.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'A financial analyst needs to determine: structural models of credit risk:', 'Use only historical default rates', 'Model default based on the firm''s asset value falling below debt value', 'Ignore firm value', 'B', 'Structural models (Merton): default occurs when assets < liabilities.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Which of the following is most accurate? reduced-form models:', 'Require knowledge of firm''s balance sheet', 'Are based on option pricing', 'Model default as a statistical process with a hazard rate', 'C', 'Reduced-form: default is modeled statistically using hazard/intensity rates.', 4, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'An analyst is evaluating a scenario. the recovery rate:', 'Is the same for all bonds', 'Is always 40%', 'Varies by seniority and collateral', 'C', 'Secured senior debt typically recovers more than subordinated unsecured.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'According to CFA curriculum, a credit event includes:', 'Default, bankruptcy, or restructuring', 'An interest rate change', 'A credit upgrade', 'A', 'Credit events trigger CDS payments and are defined in credit documentation.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'In the context of CFA Level I, a credit default swap (CDS):', 'Eliminates interest rate risk', 'Transfers credit risk from the protection buyer to the seller', 'Is an equity derivative', 'B', 'CDS: buyer pays periodic premiums; seller pays if credit event occurs.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'A financial analyst needs to determine: capacity in credit analysis refers to:', 'The borrower''s ability to make payments from cash flows', 'The quality of management', 'The value of pledged assets', 'A', 'Capacity = cash flow generation ability to service debt obligations.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Which of the following is most accurate? an upgrade in credit rating typically:', 'Has no effect on price', 'Reduces the bond''s yield spread', 'Increases the yield spread', 'B', 'Better credit → lower perceived risk → lower required yield.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'An analyst is evaluating a scenario. spread risk is:', 'Only related to government bonds', 'The risk that credit spreads widen, reducing bond prices', 'The bid-ask spread risk', 'B', 'Credit spread widening → price decline for corporate bonds.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'According to CFA curriculum, high-yield bonds have:', 'Lower credit risk', 'Higher credit risk and higher yields', 'Government guarantees', 'B', 'Below investment grade: higher default probability → higher yield.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'In the context of CFA Level I, the credit spread puzzle refers to:', 'Spreads always being too narrow', 'Corporate bond spreads being wider than expected from default losses alone', 'Government bonds having credit risk', 'B', 'Actual spreads exceed what default probabilities alone justify.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'A financial analyst needs to determine: expected loss equals:', 'Probability of default × Loss given default × Exposure', 'Credit spread × Duration', 'Default rate × Interest rate', 'A', 'EL = PD × LGD × EAD.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (21, 'Which of the following is most accurate? loss given default (LGD) is:', 'The percentage of exposure lost when default occurs', 'The probability of default', 'The total amount owed', 'A', 'LGD = 1 - Recovery rate.', 3, 'mock');
