INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'Which of the following is most accurate? a profession is distinguished from an occupation by:', 'Higher pay only', 'Specialized knowledge, a code of ethics, and service to society', 'Government regulation only', 'B', 'Professions have specialized knowledge, ethical standards, and societal responsibility.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'An analyst is evaluating a scenario. the CFA Institute Code of Ethics requires members to:', 'Follow employer instructions without question', 'Maximize personal profit', 'Act with integrity, competence, and respect', 'C', 'The Code emphasizes integrity, competence, diligence, and respect.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'According to CFA curriculum, ethical conduct in the investment industry promotes:', 'Higher transaction costs', 'Reduced market participation', 'Trust and confidence in financial markets', 'C', 'Ethics fosters trust, which is essential for functioning financial markets.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'In the context of CFA Level I, a fiduciary duty requires:', 'Placing client interests ahead of personal interests', 'Equal treatment of all stakeholders', 'Maximizing firm profits', 'A', 'Fiduciary duty: client interests come first.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'A financial analyst needs to determine: the concept of ethical behavior most accurately includes:', 'Maximizing shareholder returns', 'Conduct beyond mere compliance with laws and regulations', 'Only following legal requirements', 'B', 'Ethics goes beyond legal compliance to include moral principles.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'Which of the following is most accurate? an ethical framework helps professionals:', 'Always choose the profitable option', 'Avoid all difficult decisions', 'Analyze and resolve ethical dilemmas systematically', 'C', 'Ethical frameworks provide structured approaches to moral reasoning.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'An analyst is evaluating a scenario. situational influences on ethical behavior include:', 'Only personal values', 'Pressure from supervisors and organizational culture', 'Legal requirements exclusively', 'B', 'Context, incentives, and social pressures affect ethical choices.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'According to CFA curriculum, trust in investment professionals is important because:', 'All investments are risk-free', 'Regulations eliminate all conflicts', 'Clients cannot easily verify investment advice quality', 'C', 'Information asymmetry makes trust essential between advisors and clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'In the context of CFA Level I, which is NOT one of the six components of the Code of Ethics?', 'Maximize employer profits at all costs', 'Act with integrity and competence', 'Place client interests above own', 'A', 'The Code does not include maximizing employer profits at any cost.', 1, 'qbank');
