INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'Which of the following is most accurate? when facing an ethical conflict, the recommended first step is:', 'Consult only with your supervisor', 'Resign immediately', 'Identify the relevant facts and stakeholders', 'C', 'Systematic ethical analysis starts with fact-gathering and stakeholder identification.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'An analyst is evaluating a scenario. an ethical framework helps professionals:', 'Avoid all difficult decisions', 'Analyze and resolve ethical dilemmas systematically', 'Always choose the profitable option', 'B', 'Ethical frameworks provide structured approaches to moral reasoning.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'According to CFA curriculum, self-regulation in a profession means:', 'No oversight is needed', 'Government sets all rules', 'Members establish and enforce their own standards', 'C', 'Self-regulating professions create and police their own standards.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'In the context of CFA Level I, a challenge to ethical behavior in investment is:', 'Too few investment options', 'Excessive regulation', 'Conflicts of interest between personal and client interests', 'C', 'Conflicts of interest are a primary ethical challenge in the industry.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'A financial analyst needs to determine: the difference between a code of ethics and standards of practice is:', 'A code provides principles; standards give specific guidance', 'They are identical', 'Standards are less binding', 'A', 'Code = broad principles; Standards = specific, actionable rules.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'Which of the following is most accurate? a fiduciary duty requires:', 'Placing client interests ahead of personal interests', 'Maximizing firm profits', 'Equal treatment of all stakeholders', 'A', 'Fiduciary duty: client interests come first.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'An analyst is evaluating a scenario. the concept of ethical behavior most accurately includes:', 'Conduct beyond mere compliance with laws and regulations', 'Maximizing shareholder returns', 'Only following legal requirements', 'A', 'Ethics goes beyond legal compliance to include moral principles.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'According to CFA curriculum, situational influences on ethical behavior include:', 'Only personal values', 'Pressure from supervisors and organizational culture', 'Legal requirements exclusively', 'B', 'Context, incentives, and social pressures affect ethical choices.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'In the context of CFA Level I, a profession is distinguished from an occupation by:', 'Higher pay only', 'Government regulation only', 'Specialized knowledge, a code of ethics, and service to society', 'C', 'Professions have specialized knowledge, ethical standards, and societal responsibility.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'A financial analyst needs to determine: which is NOT one of the six components of the Code of Ethics?', 'Act with integrity and competence', 'Place client interests above own', 'Maximize employer profits at all costs', 'C', 'The Code does not include maximizing employer profits at any cost.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'Which of the following is most accurate? the CFA Institute Code of Ethics requires members to:', 'Maximize personal profit', 'Act with integrity, competence, and respect', 'Follow employer instructions without question', 'B', 'The Code emphasizes integrity, competence, diligence, and respect.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'An analyst is evaluating a scenario. high ethical standards benefit the investment industry by:', 'Increasing regulatory burden', 'Reducing the number of participants', 'Attracting more capital and lowering the cost of capital', 'C', 'Trust and ethics attract capital, benefiting markets and the economy.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'According to CFA curriculum, which best describes the duty of loyalty?', 'Obligation to act in the client''s best interest', 'Following personal investment preferences', 'Maximizing trading volume', 'A', 'Loyalty requires prioritizing client interests.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'In the context of CFA Level I, an investment professional should disclose:', 'No conflicts if they are minor', 'All potential conflicts of interest', 'Only conflicts that affect compensation', 'B', 'Full disclosure of conflicts is required regardless of size.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'A financial analyst needs to determine: an ethical dilemma occurs when:', 'The law is clear', 'Two or more ethical principles conflict', 'There is only one option', 'B', 'Dilemmas arise when valid ethical principles point in different directions.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'Which of the following is most accurate? professionalism in investment management includes:', 'Avoiding all risky investments', 'Following only profitable strategies', 'Continuous learning and adherence to ethical standards', 'C', 'Professionalism requires ongoing education and ethical conduct.', 2, 'mock');
