INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (22, 'A financial analyst needs to determine: trust in investment professionals is important because:', 'Regulations eliminate all conflicts', 'All investments are risk-free', 'Clients cannot easily verify investment advice quality', 'C', 'Information asymmetry makes trust essential between advisors and clients.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard I(A) Knowledge of the Law requires members to:', 'Understand and comply with applicable laws and regulations', 'Follow only CFA Institute rules', 'Ignore foreign laws', 'A', 'Members must know and comply with all applicable laws, following the stricter of CFA standards or local law.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard I(B) Independence and Objectivity requires that:', 'Investment recommendations not be influenced by external pressures', 'All research be positive', 'Clients always agree with recommendations', 'A', 'Members must maintain independent judgment free from conflicts.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Under Standard II(A) Material Nonpublic Information, a member who possesses insider information must:', 'Not act on or share the information', 'Trade immediately before the information becomes public', 'Share it only with senior management', 'A', 'Members must not trade on or disseminate MNPI.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard III(A) Loyalty, Prudence, and Care requires members to:', 'Act in the best interest of clients', 'Maximize firm revenue', 'Follow personal investment preferences', 'A', 'Fiduciary duty: client interests come first.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard III(B) Fair Dealing requires:', 'Treating all clients fairly when disseminating recommendations', 'Giving priority to the largest clients', 'Sharing information only with institutional clients', 'A', 'Fair dealing means equitable (not necessarily identical) treatment of all clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard III(C) Suitability requires that:', 'Investment recommendations be appropriate for the client''s situation', 'All clients receive the same recommendations', 'Only low-risk investments be recommended', 'A', 'Suitability: recommendations must match client objectives, risk tolerance, and constraints.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard IV(A) Loyalty to Employer requires members to:', 'Act for the benefit of their employer', 'Share proprietary information with competitors', 'Prioritize personal interests', 'A', 'Members owe loyalty to their employer, though client interests supersede.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard V(A) Diligence and Reasonable Basis requires:', 'A thorough analysis before making recommendations', 'Quick decisions without research', 'Following market consensus only', 'A', 'Members must have a reasonable and adequate basis for investment actions.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard V(B) Communication with Clients requires:', 'Disclosing the basic characteristics and risks of investments', 'Providing only positive information', 'Limiting communication to written reports', 'A', 'Members must communicate clearly about risks, limitations, and methodologies.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard VI(A) Disclosure of Conflicts requires members to:', 'Disclose all conflicts of interest to clients and employer', 'Ignore minor conflicts', 'Only disclose if asked', 'A', 'Full and fair disclosure of all conflicts of interest is required.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard VI(B) Priority of Transactions states that:', 'Client transactions take priority over personal transactions', 'Personal trades are unrestricted', 'Employer trades come first', 'A', 'Order: client transactions → employer → personal.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard VII(A) Conduct as Participants in CFA Institute Programs requires:', 'Not compromising the integrity of the CFA designation', 'Sharing exam questions', 'Misrepresenting CFA candidacy', 'A', 'Members must not engage in conduct that compromises the CFA Program''s reputation.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard VII(B) Reference to CFA Institute states:', 'Members must not misrepresent their CFA status', 'Anyone can claim CFA designation', 'CFA can be used as a noun', 'A', 'CFA is an adjective (e.g., ''CFA charterholder''), never a noun. Must be accurate about status.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Mosaic theory allows analysts to:', 'Combine public and non-material nonpublic information to form conclusions', 'Use material nonpublic information', 'Ignore insider information regulations', 'A', 'Mosaic theory: combining public info and non-material non-public info is permissible.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'If local law and CFA standards conflict, a member should:', 'Follow the stricter of the two', 'Always follow local law', 'Always follow CFA standards', 'A', 'Members must comply with the more restrictive requirement.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'A CFA member discovers their firm is violating securities law. They should:', 'Dissociate from the activity and consider reporting', 'Participate to maintain employment', 'Ignore it as it''s the firm''s responsibility', 'A', 'Members must not participate in violations and should consider appropriate reporting.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Soft dollar arrangements must:', 'Benefit the client', 'Only benefit the investment manager', 'Be kept secret from clients', 'A', 'Soft dollar commissions must be used for research that benefits clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Record retention under the Standards requires:', 'Maintaining records to support investment actions and recommendations', 'Destroying records after one year', 'Keeping only profitable trade records', 'A', 'Members must maintain records that support their investment processes.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard III(D) Performance Presentation requires:', 'Fair, accurate, and complete presentation of performance', 'Showing only the best-performing periods', 'Presenting gross returns only', 'A', 'Performance must be presented fairly, without cherry-picking favorable periods.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'The duty of care under fiduciary standards means:', 'Acting with the care a prudent person would exercise', 'Taking maximum risk for maximum return', 'Minimizing all costs regardless of quality', 'A', 'Prudent person rule: act with reasonable care, skill, and caution.', 2, 'qbank');
