INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'An analyst is evaluating a scenario. soft dollar arrangements must:', 'Only benefit the investment manager', 'Be kept secret from clients', 'Benefit the client', 'C', 'Soft dollar commissions must be used for research that benefits clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'According to CFA curriculum, record retention under the Standards requires:', 'Maintaining records to support investment actions and recommendations', 'Keeping only profitable trade records', 'Destroying records after one year', 'A', 'Members must maintain records that support their investment processes.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'In the context of CFA Level I, standard III(D) Performance Presentation requires:', 'Showing only the best-performing periods', 'Fair, accurate, and complete presentation of performance', 'Presenting gross returns only', 'B', 'Performance must be presented fairly, without cherry-picking favorable periods.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'A financial analyst needs to determine: the duty of care under fiduciary standards means:', 'Taking maximum risk for maximum return', 'Acting with the care a prudent person would exercise', 'Minimizing all costs regardless of quality', 'B', 'Prudent person rule: act with reasonable care, skill, and caution.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Which of the following is most accurate? standard I(A) Knowledge of the Law requires members to:', 'Ignore foreign laws', 'Follow only CFA Institute rules', 'Understand and comply with applicable laws and regulations', 'C', 'Members must know and comply with all applicable laws, following the stricter of CFA standards or local law.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'An analyst is evaluating a scenario. standard I(B) Independence and Objectivity requires that:', 'All research be positive', 'Clients always agree with recommendations', 'Investment recommendations not be influenced by external pressures', 'C', 'Members must maintain independent judgment free from conflicts.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'According to CFA curriculum, under Standard II(A) Material Nonpublic Information, a member who possesses insider information must:', 'Trade immediately before the information becomes public', 'Share it only with senior management', 'Not act on or share the information', 'C', 'Members must not trade on or disseminate MNPI.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'In the context of CFA Level I, standard III(A) Loyalty, Prudence, and Care requires members to:', 'Follow personal investment preferences', 'Act in the best interest of clients', 'Maximize firm revenue', 'B', 'Fiduciary duty: client interests come first.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'A financial analyst needs to determine: standard III(B) Fair Dealing requires:', 'Sharing information only with institutional clients', 'Giving priority to the largest clients', 'Treating all clients fairly when disseminating recommendations', 'C', 'Fair dealing means equitable (not necessarily identical) treatment of all clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Which of the following is most accurate? standard III(C) Suitability requires that:', 'All clients receive the same recommendations', 'Investment recommendations be appropriate for the client''s situation', 'Only low-risk investments be recommended', 'B', 'Suitability: recommendations must match client objectives, risk tolerance, and constraints.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'An analyst is evaluating a scenario. standard IV(A) Loyalty to Employer requires members to:', 'Prioritize personal interests', 'Share proprietary information with competitors', 'Act for the benefit of their employer', 'C', 'Members owe loyalty to their employer, though client interests supersede.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'According to CFA curriculum, standard V(A) Diligence and Reasonable Basis requires:', 'A thorough analysis before making recommendations', 'Quick decisions without research', 'Following market consensus only', 'A', 'Members must have a reasonable and adequate basis for investment actions.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'In the context of CFA Level I, standard V(B) Communication with Clients requires:', 'Providing only positive information', 'Limiting communication to written reports', 'Disclosing the basic characteristics and risks of investments', 'C', 'Members must communicate clearly about risks, limitations, and methodologies.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'A financial analyst needs to determine: standard VI(A) Disclosure of Conflicts requires members to:', 'Ignore minor conflicts', 'Only disclose if asked', 'Disclose all conflicts of interest to clients and employer', 'C', 'Full and fair disclosure of all conflicts of interest is required.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Which of the following is most accurate? standard VI(B) Priority of Transactions states that:', 'Employer trades come first', 'Client transactions take priority over personal transactions', 'Personal trades are unrestricted', 'B', 'Order: client transactions → employer → personal.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'An analyst is evaluating a scenario. standard VII(A) Conduct as Participants in CFA Institute Programs requires:', 'Misrepresenting CFA candidacy', 'Not compromising the integrity of the CFA designation', 'Sharing exam questions', 'B', 'Members must not engage in conduct that compromises the CFA Program''s reputation.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'According to CFA curriculum, standard VII(B) Reference to CFA Institute states:', 'CFA can be used as a noun', 'Members must not misrepresent their CFA status', 'Anyone can claim CFA designation', 'B', 'CFA is an adjective (e.g., ''CFA charterholder''), never a noun. Must be accurate about status.', 1, 'qbank');
