INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard VI(B) Priority of Transactions states that:', 'Client transactions take priority over personal transactions', 'Personal trades are unrestricted', 'Employer trades come first', 'A', 'Order: client transactions → employer → personal.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard IV(A) Loyalty to Employer requires members to:', 'Act for the benefit of their employer', 'Share proprietary information with competitors', 'Prioritize personal interests', 'A', 'Members owe loyalty to their employer, though client interests supersede.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard III(C) Suitability requires that:', 'Investment recommendations be appropriate for the client''s situation', 'All clients receive the same recommendations', 'Only low-risk investments be recommended', 'A', 'Suitability: recommendations must match client objectives, risk tolerance, and constraints.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard III(D) Performance Presentation requires:', 'Fair, accurate, and complete presentation of performance', 'Showing only the best-performing periods', 'Presenting gross returns only', 'A', 'Performance must be presented fairly, without cherry-picking favorable periods.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Mosaic theory allows analysts to:', 'Combine public and non-material nonpublic information to form conclusions', 'Use material nonpublic information', 'Ignore insider information regulations', 'A', 'Mosaic theory: combining public info and non-material non-public info is permissible.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard III(A) Loyalty, Prudence, and Care requires members to:', 'Act in the best interest of clients', 'Maximize firm revenue', 'Follow personal investment preferences', 'A', 'Fiduciary duty: client interests come first.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard I(B) Independence and Objectivity requires that:', 'Investment recommendations not be influenced by external pressures', 'All research be positive', 'Clients always agree with recommendations', 'A', 'Members must maintain independent judgment free from conflicts.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard VII(A) Conduct as Participants in CFA Institute Programs requires:', 'Not compromising the integrity of the CFA designation', 'Sharing exam questions', 'Misrepresenting CFA candidacy', 'A', 'Members must not engage in conduct that compromises the CFA Program''s reputation.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'A CFA member discovers their firm is violating securities law. They should:', 'Dissociate from the activity and consider reporting', 'Participate to maintain employment', 'Ignore it as it''s the firm''s responsibility', 'A', 'Members must not participate in violations and should consider appropriate reporting.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'The duty of care under fiduciary standards means:', 'Acting with the care a prudent person would exercise', 'Taking maximum risk for maximum return', 'Minimizing all costs regardless of quality', 'A', 'Prudent person rule: act with reasonable care, skill, and caution.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'If local law and CFA standards conflict, a member should:', 'Follow the stricter of the two', 'Always follow local law', 'Always follow CFA standards', 'A', 'Members must comply with the more restrictive requirement.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Standard I(A) Knowledge of the Law requires members to:', 'Understand and comply with applicable laws and regulations', 'Follow only CFA Institute rules', 'Ignore foreign laws', 'A', 'Members must know and comply with all applicable laws, following the stricter of CFA standards or local law.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Which of the following is most accurate? record retention under the Standards requires:', 'Destroying records after one year', 'Keeping only profitable trade records', 'Maintaining records to support investment actions and recommendations', 'C', 'Members must maintain records that support their investment processes.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'An analyst is evaluating a scenario. standard V(A) Diligence and Reasonable Basis requires:', 'Quick decisions without research', 'A thorough analysis before making recommendations', 'Following market consensus only', 'B', 'Members must have a reasonable and adequate basis for investment actions.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'According to CFA curriculum, standard VII(B) Reference to CFA Institute states:', 'Members must not misrepresent their CFA status', 'CFA can be used as a noun', 'Anyone can claim CFA designation', 'A', 'CFA is an adjective (e.g., ''CFA charterholder''), never a noun. Must be accurate about status.', 1, 'mock');
