INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'An analyst is evaluating a scenario. standard V(A) Diligence and Reasonable Basis requires:', 'A thorough analysis before making recommendations', 'Following market consensus only', 'Quick decisions without research', 'A', 'Members must have a reasonable and adequate basis for investment actions.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'According to CFA curriculum, standard VII(B) Reference to CFA Institute states:', 'Members must not misrepresent their CFA status', 'CFA can be used as a noun', 'Anyone can claim CFA designation', 'A', 'CFA is an adjective (e.g., ''CFA charterholder''), never a noun. Must be accurate about status.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'In the context of CFA Level I, standard III(B) Fair Dealing requires:', 'Sharing information only with institutional clients', 'Treating all clients fairly when disseminating recommendations', 'Giving priority to the largest clients', 'B', 'Fair dealing means equitable (not necessarily identical) treatment of all clients.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'A financial analyst needs to determine: standard VI(A) Disclosure of Conflicts requires members to:', 'Only disclose if asked', 'Disclose all conflicts of interest to clients and employer', 'Ignore minor conflicts', 'B', 'Full and fair disclosure of all conflicts of interest is required.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Which of the following is most accurate? under Standard II(A) Material Nonpublic Information, a member who possesses insider information must:', 'Trade immediately before the information becomes public', 'Share it only with senior management', 'Not act on or share the information', 'C', 'Members must not trade on or disseminate MNPI.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'An analyst is evaluating a scenario. standard V(B) Communication with Clients requires:', 'Limiting communication to written reports', 'Disclosing the basic characteristics and risks of investments', 'Providing only positive information', 'B', 'Members must communicate clearly about risks, limitations, and methodologies.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'According to CFA curriculum, soft dollar arrangements must:', 'Benefit the client', 'Only benefit the investment manager', 'Be kept secret from clients', 'A', 'Soft dollar commissions must be used for research that benefits clients.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'In the context of CFA Level I, standard VI(B) Priority of Transactions states that:', 'Employer trades come first', 'Client transactions take priority over personal transactions', 'Personal trades are unrestricted', 'B', 'Order: client transactions → employer → personal.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'A financial analyst needs to determine: standard IV(A) Loyalty to Employer requires members to:', 'Prioritize personal interests', 'Act for the benefit of their employer', 'Share proprietary information with competitors', 'B', 'Members owe loyalty to their employer, though client interests supersede.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Which of the following is most accurate? standard III(C) Suitability requires that:', 'All clients receive the same recommendations', 'Investment recommendations be appropriate for the client''s situation', 'Only low-risk investments be recommended', 'B', 'Suitability: recommendations must match client objectives, risk tolerance, and constraints.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'An analyst is evaluating a scenario. standard III(D) Performance Presentation requires:', 'Showing only the best-performing periods', 'Fair, accurate, and complete presentation of performance', 'Presenting gross returns only', 'B', 'Performance must be presented fairly, without cherry-picking favorable periods.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'According to CFA curriculum, mosaic theory allows analysts to:', 'Combine public and non-material nonpublic information to form conclusions', 'Use material nonpublic information', 'Ignore insider information regulations', 'A', 'Mosaic theory: combining public info and non-material non-public info is permissible.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'In the context of CFA Level I, standard III(A) Loyalty, Prudence, and Care requires members to:', 'Act in the best interest of clients', 'Maximize firm revenue', 'Follow personal investment preferences', 'A', 'Fiduciary duty: client interests come first.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'A financial analyst needs to determine: standard I(B) Independence and Objectivity requires that:', 'Clients always agree with recommendations', 'All research be positive', 'Investment recommendations not be influenced by external pressures', 'C', 'Members must maintain independent judgment free from conflicts.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'Which of the following is most accurate? standard VII(A) Conduct as Participants in CFA Institute Programs requires:', 'Not compromising the integrity of the CFA designation', 'Misrepresenting CFA candidacy', 'Sharing exam questions', 'A', 'Members must not engage in conduct that compromises the CFA Program''s reputation.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'An analyst is evaluating a scenario. a CFA member discovers their firm is violating securities law. They should:', 'Dissociate from the activity and consider reporting', 'Participate to maintain employment', 'Ignore it as it''s the firm''s responsibility', 'A', 'Members must not participate in violations and should consider appropriate reporting.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'According to CFA curriculum, the duty of care under fiduciary standards means:', 'Taking maximum risk for maximum return', 'Acting with the care a prudent person would exercise', 'Minimizing all costs regardless of quality', 'B', 'Prudent person rule: act with reasonable care, skill, and caution.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'In the context of CFA Level I, if local law and CFA standards conflict, a member should:', 'Follow the stricter of the two', 'Always follow CFA standards', 'Always follow local law', 'A', 'Members must comply with the more restrictive requirement.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (23, 'A financial analyst needs to determine: standard I(A) Knowledge of the Law requires members to:', 'Ignore foreign laws', 'Understand and comply with applicable laws and regulations', 'Follow only CFA Institute rules', 'B', 'Members must know and comply with all applicable laws, following the stricter of CFA standards or local law.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst receives a gift from a company she covers. Under the Standards, she should:', 'Disclose the gift to her employer and assess any conflict of interest', 'Accept it without disclosure', 'Reject all gifts regardless of value', 'A', 'Disclosure is required; gifts that could impair objectivity must be refused or disclosed.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A portfolio manager trades ahead of a client order. This violates:', 'Standard VI(B) Priority of Transactions (front-running)', 'Standard III(B) Fair Dealing', 'Both Standards VI(B) and III(B)', 'C', 'Front-running violates both priority of transactions and fair dealing.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst uses a quantitative model from a third party. Under Standard V(A), she must:', 'Understand the model''s assumptions and limitations', 'Use it without question since it''s from an expert', 'Disclose only the model''s name', 'A', 'Reasonable basis requires understanding any model used, even third-party ones.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Selective disclosure of investment recommendations violates:', 'Standard III(B) Fair Dealing', 'Standard I(A) Knowledge of the Law', 'Standard IV(A) Loyalty to Employer', 'A', 'Fair dealing requires equitable dissemination to all clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Material information is information that:', 'Would likely affect an investment decision or security price', 'Is already known to all market participants', 'Is only relevant to insiders', 'A', 'Material information can influence investment decisions or market prices.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst changes firms. She can:', 'Use general knowledge and skills at the new firm', 'Take proprietary research from the old firm', 'Contact old firm clients using stolen lists', 'A', 'General skills and knowledge are portable; proprietary materials are not.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Whistle-blowing under the Standards:', 'May be appropriate when internal reporting fails', 'Is never permitted', 'Always violates employer loyalty', 'A', 'Reporting violations externally may be necessary when internal channels fail.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A member managing a pension fund must:', 'Consider the fund beneficiaries as the client', 'Consider the plan sponsor as the sole client', 'Prioritize personal interest', 'A', 'For pension funds, the beneficiaries are the ultimate clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Performance presentation should include:', 'All representative accounts and relevant disclosures', 'Only the best-performing accounts', 'Only institutional accounts', 'A', 'Cherry-picking favorable accounts violates fair presentation standards.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'The firewall between investment banking and research departments serves to:', 'Prevent conflicts of interest and protect information', 'Increase revenue', 'Allow information sharing', 'A', 'Information barriers (Chinese walls) protect against MNPI sharing and conflicts.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst''s personal investment in a company she covers:', 'Must be disclosed', 'Is never permitted', 'Requires no disclosure if the position is small', 'A', 'Any personal ownership in covered securities must be disclosed.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Under the Standards, investment recommendations should be:', 'Suitable for the specific client', 'The same for all clients', 'Based solely on past performance', 'A', 'Suitability requires tailoring recommendations to each client''s circumstances.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A member discovers an error in a previous report. She should:', 'Promptly correct and disclose the error', 'Ignore it if it was unintentional', 'Wait until the next report to fix it', 'A', 'Errors must be corrected promptly and transparently.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Referral fees must be:', 'Disclosed to clients', 'Kept confidential', 'Shared with regulators only', 'A', 'Standard VI(C) requires disclosure of referral fees to affected clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Plagiarism under the Standards includes:', 'Using others'' work without attribution', 'Only copying entire documents', 'Properly citing sources', 'A', 'Any use of others'' analysis without credit constitutes plagiarism.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A supervised analyst provides misleading research. The supervisor:', 'May also be in violation if they failed to supervise adequately', 'Is never responsible', 'Is only responsible if they signed the report', 'A', 'Supervisors must establish and enforce compliance procedures.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'When managing client assets, the prudent investor rule requires:', 'Considering the portfolio as a whole rather than individual securities', 'Minimizing all risk', 'Investing only in government bonds', 'A', 'Prudent investor: evaluate each investment in the context of the total portfolio.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst recommends a stock to generate commissions. This violates:', 'Standard III(A) Loyalty, Prudence, and Care', 'Standard VII(A) CFA Program integrity', 'No standard if the stock is suitable', 'A', 'Churning or recommending for commissions rather than client benefit violates fiduciary duty.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Pre-dissemination of investment recommendations to select clients:', 'Violates Standard III(B) Fair Dealing', 'Is permitted for large clients', 'Is standard practice', 'A', 'Selective early dissemination is unfair to other clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Under the CFA Standards, the use of ''CFA'' must:', 'Follow specific usage guidelines as an adjective', 'Be used freely as a noun', 'Only appear on business cards', 'A', 'CFA is always an adjective: ''CFA charterholder'' or ''CFA Program'', never ''a CFA''.', 1, 'qbank');
