INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Which of the following is most accurate? a supervised analyst provides misleading research. The supervisor:', 'Is never responsible', 'Is only responsible if they signed the report', 'May also be in violation if they failed to supervise adequately', 'C', 'Supervisors must establish and enforce compliance procedures.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst is evaluating a scenario. when managing client assets, the prudent investor rule requires:', 'Minimizing all risk', 'Investing only in government bonds', 'Considering the portfolio as a whole rather than individual securities', 'C', 'Prudent investor: evaluate each investment in the context of the total portfolio.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'According to CFA curriculum, an analyst recommends a stock to generate commissions. This violates:', 'No standard if the stock is suitable', 'Standard III(A) Loyalty, Prudence, and Care', 'Standard VII(A) CFA Program integrity', 'B', 'Churning or recommending for commissions rather than client benefit violates fiduciary duty.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'In the context of CFA Level I, pre-dissemination of investment recommendations to select clients:', 'Violates Standard III(B) Fair Dealing', 'Is permitted for large clients', 'Is standard practice', 'A', 'Selective early dissemination is unfair to other clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A financial analyst needs to determine: under the CFA Standards, the use of ''CFA'' must:', 'Follow specific usage guidelines as an adjective', 'Be used freely as a noun', 'Only appear on business cards', 'A', 'CFA is always an adjective: ''CFA charterholder'' or ''CFA Program'', never ''a CFA''.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Which of the following is most accurate? an analyst receives a gift from a company she covers. Under the Standards, she should:', 'Accept it without disclosure', 'Reject all gifts regardless of value', 'Disclose the gift to her employer and assess any conflict of interest', 'C', 'Disclosure is required; gifts that could impair objectivity must be refused or disclosed.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst is evaluating a scenario. a portfolio manager trades ahead of a client order. This violates:', 'Standard III(B) Fair Dealing', 'Both Standards VI(B) and III(B)', 'Standard VI(B) Priority of Transactions (front-running)', 'B', 'Front-running violates both priority of transactions and fair dealing.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'According to CFA curriculum, an analyst uses a quantitative model from a third party. Under Standard V(A), she must:', 'Use it without question since it''s from an expert', 'Understand the model''s assumptions and limitations', 'Disclose only the model''s name', 'B', 'Reasonable basis requires understanding any model used, even third-party ones.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'In the context of CFA Level I, selective disclosure of investment recommendations violates:', 'Standard III(B) Fair Dealing', 'Standard I(A) Knowledge of the Law', 'Standard IV(A) Loyalty to Employer', 'A', 'Fair dealing requires equitable dissemination to all clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A financial analyst needs to determine: material information is information that:', 'Would likely affect an investment decision or security price', 'Is already known to all market participants', 'Is only relevant to insiders', 'A', 'Material information can influence investment decisions or market prices.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Which of the following is most accurate? an analyst changes firms. She can:', 'Use general knowledge and skills at the new firm', 'Contact old firm clients using stolen lists', 'Take proprietary research from the old firm', 'A', 'General skills and knowledge are portable; proprietary materials are not.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst is evaluating a scenario. whistle-blowing under the Standards:', 'Is never permitted', 'May be appropriate when internal reporting fails', 'Always violates employer loyalty', 'B', 'Reporting violations externally may be necessary when internal channels fail.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'According to CFA curriculum, a member managing a pension fund must:', 'Consider the fund beneficiaries as the client', 'Prioritize personal interest', 'Consider the plan sponsor as the sole client', 'A', 'For pension funds, the beneficiaries are the ultimate clients.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'In the context of CFA Level I, performance presentation should include:', 'Only the best-performing accounts', 'Only institutional accounts', 'All representative accounts and relevant disclosures', 'C', 'Cherry-picking favorable accounts violates fair presentation standards.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A financial analyst needs to determine: the firewall between investment banking and research departments serves to:', 'Prevent conflicts of interest and protect information', 'Increase revenue', 'Allow information sharing', 'A', 'Information barriers (Chinese walls) protect against MNPI sharing and conflicts.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Which of the following is most accurate? an analyst''s personal investment in a company she covers:', 'Requires no disclosure if the position is small', 'Is never permitted', 'Must be disclosed', 'C', 'Any personal ownership in covered securities must be disclosed.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst is evaluating a scenario. under the Standards, investment recommendations should be:', 'The same for all clients', 'Based solely on past performance', 'Suitable for the specific client', 'C', 'Suitability requires tailoring recommendations to each client''s circumstances.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'According to CFA curriculum, a member discovers an error in a previous report. She should:', 'Wait until the next report to fix it', 'Ignore it if it was unintentional', 'Promptly correct and disclose the error', 'C', 'Errors must be corrected promptly and transparently.', 2, 'qbank');
