INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A financial analyst needs to determine: plagiarism under the Standards includes:', 'Only copying entire documents', 'Using others'' work without attribution', 'Properly citing sources', 'B', 'Any use of others'' analysis without credit constitutes plagiarism.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Which of the following is most accurate? an analyst changes firms. She can:', 'Contact old firm clients using stolen lists', 'Use general knowledge and skills at the new firm', 'Take proprietary research from the old firm', 'B', 'General skills and knowledge are portable; proprietary materials are not.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst is evaluating a scenario. material information is information that:', 'Is already known to all market participants', 'Would likely affect an investment decision or security price', 'Is only relevant to insiders', 'B', 'Material information can influence investment decisions or market prices.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'According to CFA curriculum, a member discovers an error in a previous report. She should:', 'Ignore it if it was unintentional', 'Promptly correct and disclose the error', 'Wait until the next report to fix it', 'B', 'Errors must be corrected promptly and transparently.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'In the context of CFA Level I, under the CFA Standards, the use of ''CFA'' must:', 'Only appear on business cards', 'Be used freely as a noun', 'Follow specific usage guidelines as an adjective', 'C', 'CFA is always an adjective: ''CFA charterholder'' or ''CFA Program'', never ''a CFA''.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A financial analyst needs to determine: referral fees must be:', 'Disclosed to clients', 'Kept confidential', 'Shared with regulators only', 'A', 'Standard VI(C) requires disclosure of referral fees to affected clients.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Which of the following is most accurate? when managing client assets, the prudent investor rule requires:', 'Investing only in government bonds', 'Minimizing all risk', 'Considering the portfolio as a whole rather than individual securities', 'C', 'Prudent investor: evaluate each investment in the context of the total portfolio.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst is evaluating a scenario. an analyst''s personal investment in a company she covers:', 'Must be disclosed', 'Requires no disclosure if the position is small', 'Is never permitted', 'A', 'Any personal ownership in covered securities must be disclosed.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'According to CFA curriculum, a portfolio manager trades ahead of a client order. This violates:', 'Standard VI(B) Priority of Transactions (front-running)', 'Both Standards VI(B) and III(B)', 'Standard III(B) Fair Dealing', 'B', 'Front-running violates both priority of transactions and fair dealing.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'In the context of CFA Level I, selective disclosure of investment recommendations violates:', 'Standard III(B) Fair Dealing', 'Standard I(A) Knowledge of the Law', 'Standard IV(A) Loyalty to Employer', 'A', 'Fair dealing requires equitable dissemination to all clients.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A financial analyst needs to determine: pre-dissemination of investment recommendations to select clients:', 'Is standard practice', 'Violates Standard III(B) Fair Dealing', 'Is permitted for large clients', 'B', 'Selective early dissemination is unfair to other clients.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Which of the following is most accurate? the firewall between investment banking and research departments serves to:', 'Increase revenue', 'Allow information sharing', 'Prevent conflicts of interest and protect information', 'C', 'Information barriers (Chinese walls) protect against MNPI sharing and conflicts.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst is evaluating a scenario. an analyst uses a quantitative model from a third party. Under Standard V(A), she must:', 'Understand the model''s assumptions and limitations', 'Use it without question since it''s from an expert', 'Disclose only the model''s name', 'A', 'Reasonable basis requires understanding any model used, even third-party ones.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'According to CFA curriculum, under the Standards, investment recommendations should be:', 'Suitable for the specific client', 'Based solely on past performance', 'The same for all clients', 'A', 'Suitability requires tailoring recommendations to each client''s circumstances.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'In the context of CFA Level I, whistle-blowing under the Standards:', 'Is never permitted', 'May be appropriate when internal reporting fails', 'Always violates employer loyalty', 'B', 'Reporting violations externally may be necessary when internal channels fail.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'A financial analyst needs to determine: an analyst receives a gift from a company she covers. Under the Standards, she should:', 'Disclose the gift to her employer and assess any conflict of interest', 'Accept it without disclosure', 'Reject all gifts regardless of value', 'A', 'Disclosure is required; gifts that could impair objectivity must be refused or disclosed.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'Which of the following is most accurate? an analyst recommends a stock to generate commissions. This violates:', 'Standard III(A) Loyalty, Prudence, and Care', 'Standard VII(A) CFA Program integrity', 'No standard if the stock is suitable', 'A', 'Churning or recommending for commissions rather than client benefit violates fiduciary duty.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (24, 'An analyst is evaluating a scenario. a supervised analyst provides misleading research. The supervisor:', 'Is only responsible if they signed the report', 'Is never responsible', 'May also be in violation if they failed to supervise adequately', 'C', 'Supervisors must establish and enforce compliance procedures.', 2, 'mock');
