INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'GIPS are global standards for:', 'Investment performance presentation', 'Financial reporting', 'Tax compliance', 'A', 'GIPS ensure fair, comparable investment performance presentation.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'GIPS compliance is:', 'Voluntary for investment firms', 'Required by law', 'Required only for public firms', 'A', 'GIPS adoption is voluntary but demonstrates commitment to fair reporting.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Under GIPS, returns must be calculated using:', 'Time-weighted returns', 'Money-weighted returns only', 'Simple returns', 'A', 'GIPS requires time-weighted returns to minimize cash flow timing effects.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'A composite under GIPS is:', 'A group of portfolios managed with a similar strategy', 'A single portfolio', 'A benchmark index', 'A', 'Composites aggregate portfolios with similar investment mandates.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'GIPS requires performance to be presented for a minimum of:', '5 years or since inception', '1 year', '10 years', 'A', 'GIPS: 5 years initially, building to 10 years.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Under GIPS, firms must:', 'Include all actual fee-paying discretionary portfolios in composites', 'Exclude poor-performing portfolios', 'Only include institutional portfolios', 'A', 'All fee-paying discretionary accounts must be in at least one composite (no cherry-picking).', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'GIPS verification is:', 'Performed by an independent third party', 'Self-verified by the firm', 'Required by regulators', 'A', 'Verification is voluntary and performed by independent verifiers.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Returns must be presented on a:', 'After-fees basis at minimum, with gross also recommended', 'Before-fees basis only', 'Net of all expenses basis', 'A', 'GIPS recommends both gross and net; net is minimum requirement.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Portability under GIPS refers to:', 'Taking performance records when professionals change firms', 'Moving client accounts between firms', 'Transferring software', 'A', 'Portability: conditions for linking track records when personnel move.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Terminated portfolios must:', 'Be included in composite history through the last full period', 'Be removed from all historical records', 'Be excluded from reporting', 'A', 'Survivorship bias is avoided by keeping terminated accounts in historical composites.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'GIPS applies to:', 'Investment management firms', 'Individual analysts', 'Regulatory bodies', 'A', 'GIPS is a firm-level standard for investment managers.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'The purpose of composites is to:', 'Prevent cherry-picking of favorable portfolios', 'Simplify reporting', 'Reduce the number of portfolios', 'A', 'Composites ensure all similar portfolios are represented, preventing selection bias.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'New portfolios must be added to composites:', 'Within a reasonable timeframe, typically at the start of the next full period', 'After one year of performance', 'Only if they outperform', 'A', 'New accounts enter composites promptly, not selectively.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'GIPS-compliant firms must disclose:', 'Their definition of the firm and list of composites', 'Only total firm assets', 'Nothing beyond returns', 'A', 'Disclosure requirements include firm definition, composite descriptions, and policies.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Simulated or model performance:', 'Must not be linked to actual performance', 'Can replace actual results', 'Is treated the same as actual', 'A', 'GIPS prohibits mixing hypothetical/model results with actual performance.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Benchmarks in GIPS presentations should be:', 'Appropriate to the composite strategy', 'The highest-returning index available', 'Optional and not required', 'A', 'Benchmark selection should reflect the composite''s investment strategy.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Trade date accounting under GIPS means:', 'Recording transactions on the date they are executed', 'Recording on settlement date', 'Recording on the month-end date', 'A', 'GIPS requires trade-date (not settlement-date) accounting.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Real estate and private equity have:', 'Separate GIPS provisions due to their unique characteristics', 'The same provisions as equity composites', 'No GIPS guidance', 'A', 'GIPS has specific provisions for alternative asset classes.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'A firm claiming GIPS compliance must:', 'Comply with all applicable requirements', 'Comply with only key provisions', 'Partially comply and disclose non-compliance', 'A', 'GIPS requires full compliance; partial compliance claims are not allowed.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'The dispersion of returns within a composite is reported to:', 'Show the range of portfolio returns within the composite', 'Demonstrate superior performance', 'Replace benchmark comparisons', 'A', 'Dispersion measures how individual portfolio returns vary within the composite.', 2, 'qbank');
