INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'An analyst is evaluating a scenario. gIPS compliance is:', 'Required by law', 'Required only for public firms', 'Voluntary for investment firms', 'C', 'GIPS adoption is voluntary but demonstrates commitment to fair reporting.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'According to CFA curriculum, under GIPS, returns must be calculated using:', 'Simple returns', 'Time-weighted returns', 'Money-weighted returns only', 'B', 'GIPS requires time-weighted returns to minimize cash flow timing effects.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'In the context of CFA Level I, a composite under GIPS is:', 'A group of portfolios managed with a similar strategy', 'A benchmark index', 'A single portfolio', 'A', 'Composites aggregate portfolios with similar investment mandates.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'A financial analyst needs to determine: gIPS requires performance to be presented for a minimum of:', '5 years or since inception', '10 years', '1 year', 'A', 'GIPS: 5 years initially, building to 10 years.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Which of the following is most accurate? under GIPS, firms must:', 'Include all actual fee-paying discretionary portfolios in composites', 'Only include institutional portfolios', 'Exclude poor-performing portfolios', 'A', 'All fee-paying discretionary accounts must be in at least one composite (no cherry-picking).', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'An analyst is evaluating a scenario. gIPS verification is:', 'Required by regulators', 'Self-verified by the firm', 'Performed by an independent third party', 'C', 'Verification is voluntary and performed by independent verifiers.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'According to CFA curriculum, returns must be presented on a:', 'Before-fees basis only', 'Net of all expenses basis', 'After-fees basis at minimum, with gross also recommended', 'C', 'GIPS recommends both gross and net; net is minimum requirement.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'In the context of CFA Level I, portability under GIPS refers to:', 'Taking performance records when professionals change firms', 'Moving client accounts between firms', 'Transferring software', 'A', 'Portability: conditions for linking track records when personnel move.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'A financial analyst needs to determine: terminated portfolios must:', 'Be excluded from reporting', 'Be removed from all historical records', 'Be included in composite history through the last full period', 'C', 'Survivorship bias is avoided by keeping terminated accounts in historical composites.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Which of the following is most accurate? gIPS applies to:', 'Individual analysts', 'Regulatory bodies', 'Investment management firms', 'C', 'GIPS is a firm-level standard for investment managers.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'An analyst is evaluating a scenario. the purpose of composites is to:', 'Reduce the number of portfolios', 'Prevent cherry-picking of favorable portfolios', 'Simplify reporting', 'B', 'Composites ensure all similar portfolios are represented, preventing selection bias.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'According to CFA curriculum, new portfolios must be added to composites:', 'Only if they outperform', 'Within a reasonable timeframe, typically at the start of the next full period', 'After one year of performance', 'B', 'New accounts enter composites promptly, not selectively.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'In the context of CFA Level I, gIPS-compliant firms must disclose:', 'Their definition of the firm and list of composites', 'Only total firm assets', 'Nothing beyond returns', 'A', 'Disclosure requirements include firm definition, composite descriptions, and policies.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'A financial analyst needs to determine: simulated or model performance:', 'Must not be linked to actual performance', 'Can replace actual results', 'Is treated the same as actual', 'A', 'GIPS prohibits mixing hypothetical/model results with actual performance.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Which of the following is most accurate? benchmarks in GIPS presentations should be:', 'Appropriate to the composite strategy', 'Optional and not required', 'The highest-returning index available', 'A', 'Benchmark selection should reflect the composite''s investment strategy.', 3, 'qbank');
