INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Which of the following is most accurate? gIPS applies to:', 'Investment management firms', 'Individual analysts', 'Regulatory bodies', 'A', 'GIPS is a firm-level standard for investment managers.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'An analyst is evaluating a scenario. benchmarks in GIPS presentations should be:', 'Appropriate to the composite strategy', 'Optional and not required', 'The highest-returning index available', 'A', 'Benchmark selection should reflect the composite''s investment strategy.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'According to CFA curriculum, trade date accounting under GIPS means:', 'Recording on settlement date', 'Recording on the month-end date', 'Recording transactions on the date they are executed', 'C', 'GIPS requires trade-date (not settlement-date) accounting.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'In the context of CFA Level I, a composite under GIPS is:', 'A single portfolio', 'A benchmark index', 'A group of portfolios managed with a similar strategy', 'C', 'Composites aggregate portfolios with similar investment mandates.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'A financial analyst needs to determine: a firm claiming GIPS compliance must:', 'Comply with only key provisions', 'Partially comply and disclose non-compliance', 'Comply with all applicable requirements', 'C', 'GIPS requires full compliance; partial compliance claims are not allowed.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Which of the following is most accurate? new portfolios must be added to composites:', 'After one year of performance', 'Only if they outperform', 'Within a reasonable timeframe, typically at the start of the next full period', 'C', 'New accounts enter composites promptly, not selectively.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'An analyst is evaluating a scenario. real estate and private equity have:', 'The same provisions as equity composites', 'No GIPS guidance', 'Separate GIPS provisions due to their unique characteristics', 'C', 'GIPS has specific provisions for alternative asset classes.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'According to CFA curriculum, gIPS compliance is:', 'Voluntary for investment firms', 'Required only for public firms', 'Required by law', 'A', 'GIPS adoption is voluntary but demonstrates commitment to fair reporting.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'In the context of CFA Level I, terminated portfolios must:', 'Be included in composite history through the last full period', 'Be removed from all historical records', 'Be excluded from reporting', 'A', 'Survivorship bias is avoided by keeping terminated accounts in historical composites.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'A financial analyst needs to determine: simulated or model performance:', 'Can replace actual results', 'Must not be linked to actual performance', 'Is treated the same as actual', 'B', 'GIPS prohibits mixing hypothetical/model results with actual performance.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Which of the following is most accurate? under GIPS, firms must:', 'Exclude poor-performing portfolios', 'Include all actual fee-paying discretionary portfolios in composites', 'Only include institutional portfolios', 'B', 'All fee-paying discretionary accounts must be in at least one composite (no cherry-picking).', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'An analyst is evaluating a scenario. gIPS-compliant firms must disclose:', 'Nothing beyond returns', 'Only total firm assets', 'Their definition of the firm and list of composites', 'C', 'Disclosure requirements include firm definition, composite descriptions, and policies.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'According to CFA curriculum, gIPS verification is:', 'Performed by an independent third party', 'Required by regulators', 'Self-verified by the firm', 'A', 'Verification is voluntary and performed by independent verifiers.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'In the context of CFA Level I, gIPS requires performance to be presented for a minimum of:', '10 years', '1 year', '5 years or since inception', 'C', 'GIPS: 5 years initially, building to 10 years.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'A financial analyst needs to determine: the purpose of composites is to:', 'Prevent cherry-picking of favorable portfolios', 'Reduce the number of portfolios', 'Simplify reporting', 'A', 'Composites ensure all similar portfolios are represented, preventing selection bias.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'Which of the following is most accurate? under GIPS, returns must be calculated using:', 'Time-weighted returns', 'Simple returns', 'Money-weighted returns only', 'A', 'GIPS requires time-weighted returns to minimize cash flow timing effects.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'An analyst is evaluating a scenario. the dispersion of returns within a composite is reported to:', 'Show the range of portfolio returns within the composite', 'Demonstrate superior performance', 'Replace benchmark comparisons', 'A', 'Dispersion measures how individual portfolio returns vary within the composite.', 2, 'mock');
