INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (25, 'A financial analyst needs to determine: returns must be presented on a:', 'After-fees basis at minimum, with gross also recommended', 'Net of all expenses basis', 'Before-fees basis only', 'A', 'GIPS recommends both gross and net; net is minimum requirement.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst recommends a stock she personally owns. She is most likely required to:', 'Disclose the ownership to clients', 'Sell her position before recommending', 'Not recommend stocks she owns', 'A', 'Disclosure of conflicts (personal holdings) is required.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A manager allocates hot IPO shares to his personal account first. This violates:', 'Standard VI(B) Priority of Transactions', 'Standard I(A) Knowledge of the Law', 'Standard V(B) Communication', 'A', 'Personal accounts cannot take priority over client accounts.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Adjusting model assumptions to match a desired conclusion violates:', 'Standard V(A) Diligence and Reasonable Basis', 'Standard VII(B) Reference to CFA', 'No standard if the conclusion is correct', 'A', 'Manipulating inputs to produce a predetermined result lacks reasonable basis.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A CFA candidate discusses specific exam questions online. This violates:', 'Standard VII(A) Conduct as Participants in CFA Institute Programs', 'Standard I(B) Independence', 'No standard since the exam is over', 'A', 'Sharing exam content compromises CFA Program integrity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst copies a model from another firm without attribution. This violates:', 'Standard I(C) Misrepresentation (plagiarism)', 'Standard IV(A) Loyalty', 'Standard III(C) Suitability', 'A', 'Using others'' work without attribution is plagiarism.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A portfolio manager simultaneously trades a thinly traded stock for her account and a client. She should:', 'Ensure the client''s order is executed first', 'Execute both simultaneously', 'Trade her personal account first', 'A', 'Client trades take priority; front-running is prohibited.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst learns material nonpublic information at a social event. She should:', 'Refrain from trading or sharing the information', 'Trade before the information becomes public', 'Share only with her portfolio manager', 'A', 'MNPI must not be acted upon or shared until publicly disseminated.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A member is pressured by his employer to issue a favorable recommendation. He should:', 'Maintain objectivity regardless of pressure', 'Comply with the employer''s request', 'Issue a neutral recommendation as a compromise', 'A', 'Standard I(B) Independence and Objectivity must be maintained.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Backdating trade confirmations to show better performance violates:', 'Standard I(C) Misrepresentation', 'Standard IV(B) Additional Compensation', 'Standard III(D) Performance Presentation', 'C', 'Backdating misrepresents actual performance.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A CFA charterholder states ''I am a CFA.'' This:', 'Violates Standard VII(B) Reference to CFA Institute', 'Is acceptable usage', 'Is only wrong on business cards', 'A', 'CFA must be used as an adjective (''CFA charterholder''), not a noun.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst writes a report largely based on another analyst''s work. She attributes it to herself. This violates:', 'Standard I(C) Misrepresentation', 'Standard V(A) Diligence', 'Standard III(B) Fair Dealing', 'A', 'Claiming others'' work as your own is misrepresentation/plagiarism.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A compliance officer discovers suspicious trading patterns but takes no action. This may violate:', 'Standard IV(C) Responsibilities of Supervisors', 'Standard I(B) Independence', 'No standard applies', 'A', 'Supervisors must act on compliance red flags.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A manager invests client funds in a friend''s startup without proper analysis. This violates:', 'Standard V(A) Diligence and Reasonable Basis', 'Standard VII(B) Reference to CFA', 'Standard IV(B) Additional Compensation', 'A', 'Investing without thorough analysis violates the reasonable basis requirement.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst provides different recommendations to different clients solely based on fee size. This violates:', 'Standard III(B) Fair Dealing', 'Standard VI(A) Disclosure of Conflicts', 'Standard I(A) Knowledge of the Law', 'A', 'Fair dealing prohibits discriminatory treatment based on fees.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A member receives compensation from a third party for referrals. Under the Standards:', 'This must be disclosed to affected clients and the employer', 'This is prohibited in all cases', 'This requires only employer disclosure', 'A', 'Both client and employer disclosure is required for referral arrangements.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A member on a company''s board receives MNPI during a board meeting. She:', 'Must restrict trading in that company''s securities', 'Can trade since she''s a board member', 'Should resign from the board', 'A', 'Board membership doesn''t exempt from MNPI trading restrictions.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst issues a buy recommendation on a stock his firm is underwriting. This most likely violates:', 'Standard I(B) Independence and Objectivity', 'Standard VII(A) CFA Program conduct', 'No standard if the analysis supports it', 'A', 'Investment banking relationships create conflicts that threaten objectivity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Using misleading benchmarks in performance reports violates:', 'Standard III(D) Performance Presentation', 'Standard IV(A) Loyalty', 'Standard II(A) MNPI', 'A', 'Performance must be presented fairly with appropriate benchmarks.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A CFA candidate states ''I expect to receive the CFA charter next year.'' This:', 'May violate Standard VII(B) if it implies guaranteed passage', 'Is always acceptable', 'Is never acceptable', 'A', 'Members must not imply guaranteed completion of the CFA Program.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'When there is a conflict between employer interests and client interests:', 'Client interests take precedence', 'Employer interests take precedence', 'The member should resign', 'A', 'Standard III(A): Clients'' interests always come first.', 1, 'qbank');
