INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'According to CFA curriculum, a manager invests client funds in a friend''s startup without proper analysis. This violates:', 'Standard V(A) Diligence and Reasonable Basis', 'Standard IV(B) Additional Compensation', 'Standard VII(B) Reference to CFA', 'A', 'Investing without thorough analysis violates the reasonable basis requirement.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'In the context of CFA Level I, an analyst provides different recommendations to different clients solely based on fee size. This violates:', 'Standard VI(A) Disclosure of Conflicts', 'Standard III(B) Fair Dealing', 'Standard I(A) Knowledge of the Law', 'B', 'Fair dealing prohibits discriminatory treatment based on fees.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A financial analyst needs to determine: a member receives compensation from a third party for referrals. Under the Standards:', 'This must be disclosed to affected clients and the employer', 'This requires only employer disclosure', 'This is prohibited in all cases', 'A', 'Both client and employer disclosure is required for referral arrangements.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Which of the following is most accurate? a member on a company''s board receives MNPI during a board meeting. She:', 'Must restrict trading in that company''s securities', 'Can trade since she''s a board member', 'Should resign from the board', 'A', 'Board membership doesn''t exempt from MNPI trading restrictions.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst is evaluating a scenario. an analyst issues a buy recommendation on a stock his firm is underwriting. This most likely violates:', 'Standard I(B) Independence and Objectivity', 'Standard VII(A) CFA Program conduct', 'No standard if the analysis supports it', 'A', 'Investment banking relationships create conflicts that threaten objectivity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'According to CFA curriculum, using misleading benchmarks in performance reports violates:', 'Standard IV(A) Loyalty', 'Standard II(A) MNPI', 'Standard III(D) Performance Presentation', 'C', 'Performance must be presented fairly with appropriate benchmarks.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'In the context of CFA Level I, a CFA candidate states ''I expect to receive the CFA charter next year.'' This:', 'Is always acceptable', 'Is never acceptable', 'May violate Standard VII(B) if it implies guaranteed passage', 'C', 'Members must not imply guaranteed completion of the CFA Program.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A financial analyst needs to determine: when there is a conflict between employer interests and client interests:', 'Employer interests take precedence', 'Client interests take precedence', 'The member should resign', 'B', 'Standard III(A): Clients'' interests always come first.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Which of the following is most accurate? an analyst recommends a stock she personally owns. She is most likely required to:', 'Disclose the ownership to clients', 'Not recommend stocks she owns', 'Sell her position before recommending', 'A', 'Disclosure of conflicts (personal holdings) is required.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst is evaluating a scenario. a manager allocates hot IPO shares to his personal account first. This violates:', 'Standard I(A) Knowledge of the Law', 'Standard V(B) Communication', 'Standard VI(B) Priority of Transactions', 'C', 'Personal accounts cannot take priority over client accounts.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'According to CFA curriculum, adjusting model assumptions to match a desired conclusion violates:', 'Standard V(A) Diligence and Reasonable Basis', 'Standard VII(B) Reference to CFA', 'No standard if the conclusion is correct', 'A', 'Manipulating inputs to produce a predetermined result lacks reasonable basis.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'In the context of CFA Level I, a CFA candidate discusses specific exam questions online. This violates:', 'Standard I(B) Independence', 'Standard VII(A) Conduct as Participants in CFA Institute Programs', 'No standard since the exam is over', 'B', 'Sharing exam content compromises CFA Program integrity.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A financial analyst needs to determine: an analyst copies a model from another firm without attribution. This violates:', 'Standard I(C) Misrepresentation (plagiarism)', 'Standard III(C) Suitability', 'Standard IV(A) Loyalty', 'A', 'Using others'' work without attribution is plagiarism.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Which of the following is most accurate? a portfolio manager simultaneously trades a thinly traded stock for her account and a client. She should:', 'Execute both simultaneously', 'Trade her personal account first', 'Ensure the client''s order is executed first', 'C', 'Client trades take priority; front-running is prohibited.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst is evaluating a scenario. an analyst learns material nonpublic information at a social event. She should:', 'Share only with her portfolio manager', 'Refrain from trading or sharing the information', 'Trade before the information becomes public', 'B', 'MNPI must not be acted upon or shared until publicly disseminated.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'According to CFA curriculum, a member is pressured by his employer to issue a favorable recommendation. He should:', 'Issue a neutral recommendation as a compromise', 'Maintain objectivity regardless of pressure', 'Comply with the employer''s request', 'B', 'Standard I(B) Independence and Objectivity must be maintained.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'In the context of CFA Level I, backdating trade confirmations to show better performance violates:', 'Standard I(C) Misrepresentation', 'Standard IV(B) Additional Compensation', 'Standard III(D) Performance Presentation', 'C', 'Backdating misrepresents actual performance.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A financial analyst needs to determine: a CFA charterholder states ''I am a CFA.'' This:', 'Is acceptable usage', 'Is only wrong on business cards', 'Violates Standard VII(B) Reference to CFA Institute', 'C', 'CFA must be used as an adjective (''CFA charterholder''), not a noun.', 1, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Which of the following is most accurate? an analyst writes a report largely based on another analyst''s work. She attributes it to herself. This violates:', 'Standard I(C) Misrepresentation', 'Standard V(A) Diligence', 'Standard III(B) Fair Dealing', 'A', 'Claiming others'' work as your own is misrepresentation/plagiarism.', 3, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst is evaluating a scenario. a compliance officer discovers suspicious trading patterns but takes no action. This may violate:', 'Standard IV(C) Responsibilities of Supervisors', 'Standard I(B) Independence', 'No standard applies', 'A', 'Supervisors must act on compliance red flags.', 2, 'qbank');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'According to CFA curriculum, a manager invests client funds in a friend''s startup without proper analysis. This violates:', 'Standard IV(B) Additional Compensation', 'Standard VII(B) Reference to CFA', 'Standard V(A) Diligence and Reasonable Basis', 'C', 'Investing without thorough analysis violates the reasonable basis requirement.', 2, 'qbank');
