INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'In the context of CFA Level I, using misleading benchmarks in performance reports violates:', 'Standard II(A) MNPI', 'Standard III(D) Performance Presentation', 'Standard IV(A) Loyalty', 'B', 'Performance must be presented fairly with appropriate benchmarks.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A financial analyst needs to determine: a member on a company''s board receives MNPI during a board meeting. She:', 'Can trade since she''s a board member', 'Should resign from the board', 'Must restrict trading in that company''s securities', 'C', 'Board membership doesn''t exempt from MNPI trading restrictions.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Which of the following is most accurate? an analyst issues a buy recommendation on a stock his firm is underwriting. This most likely violates:', 'Standard I(B) Independence and Objectivity', 'No standard if the analysis supports it', 'Standard VII(A) CFA Program conduct', 'A', 'Investment banking relationships create conflicts that threaten objectivity.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst is evaluating a scenario. an analyst learns material nonpublic information at a social event. She should:', 'Share only with her portfolio manager', 'Trade before the information becomes public', 'Refrain from trading or sharing the information', 'C', 'MNPI must not be acted upon or shared until publicly disseminated.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'According to CFA curriculum, a manager allocates hot IPO shares to his personal account first. This violates:', 'Standard V(B) Communication', 'Standard I(A) Knowledge of the Law', 'Standard VI(B) Priority of Transactions', 'C', 'Personal accounts cannot take priority over client accounts.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'In the context of CFA Level I, a manager invests client funds in a friend''s startup without proper analysis. This violates:', 'Standard IV(B) Additional Compensation', 'Standard V(A) Diligence and Reasonable Basis', 'Standard VII(B) Reference to CFA', 'B', 'Investing without thorough analysis violates the reasonable basis requirement.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A financial analyst needs to determine: when there is a conflict between employer interests and client interests:', 'Client interests take precedence', 'Employer interests take precedence', 'The member should resign', 'A', 'Standard III(A): Clients'' interests always come first.', 1, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Which of the following is most accurate? backdating trade confirmations to show better performance violates:', 'Standard III(D) Performance Presentation', 'Standard IV(B) Additional Compensation', 'Standard I(C) Misrepresentation', 'A', 'Backdating misrepresents actual performance.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst is evaluating a scenario. a compliance officer discovers suspicious trading patterns but takes no action. This may violate:', 'No standard applies', 'Standard I(B) Independence', 'Standard IV(C) Responsibilities of Supervisors', 'C', 'Supervisors must act on compliance red flags.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'According to CFA curriculum, a member is pressured by his employer to issue a favorable recommendation. He should:', 'Maintain objectivity regardless of pressure', 'Comply with the employer''s request', 'Issue a neutral recommendation as a compromise', 'A', 'Standard I(B) Independence and Objectivity must be maintained.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'In the context of CFA Level I, an analyst recommends a stock she personally owns. She is most likely required to:', 'Not recommend stocks she owns', 'Disclose the ownership to clients', 'Sell her position before recommending', 'B', 'Disclosure of conflicts (personal holdings) is required.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A financial analyst needs to determine: an analyst provides different recommendations to different clients solely based on fee size. This violates:', 'Standard III(B) Fair Dealing', 'Standard I(A) Knowledge of the Law', 'Standard VI(A) Disclosure of Conflicts', 'A', 'Fair dealing prohibits discriminatory treatment based on fees.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Which of the following is most accurate? adjusting model assumptions to match a desired conclusion violates:', 'Standard VII(B) Reference to CFA', 'Standard V(A) Diligence and Reasonable Basis', 'No standard if the conclusion is correct', 'B', 'Manipulating inputs to produce a predetermined result lacks reasonable basis.', 3, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst is evaluating a scenario. a member receives compensation from a third party for referrals. Under the Standards:', 'This must be disclosed to affected clients and the employer', 'This requires only employer disclosure', 'This is prohibited in all cases', 'A', 'Both client and employer disclosure is required for referral arrangements.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'According to CFA curriculum, a portfolio manager simultaneously trades a thinly traded stock for her account and a client. She should:', 'Execute both simultaneously', 'Trade her personal account first', 'Ensure the client''s order is executed first', 'C', 'Client trades take priority; front-running is prohibited.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'In the context of CFA Level I, a CFA candidate discusses specific exam questions online. This violates:', 'No standard since the exam is over', 'Standard VII(A) Conduct as Participants in CFA Institute Programs', 'Standard I(B) Independence', 'B', 'Sharing exam content compromises CFA Program integrity.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'A financial analyst needs to determine: a CFA candidate states ''I expect to receive the CFA charter next year.'' This:', 'May violate Standard VII(B) if it implies guaranteed passage', 'Is always acceptable', 'Is never acceptable', 'A', 'Members must not imply guaranteed completion of the CFA Program.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'Which of the following is most accurate? a CFA charterholder states ''I am a CFA.'' This:', 'Violates Standard VII(B) Reference to CFA Institute', 'Is only wrong on business cards', 'Is acceptable usage', 'A', 'CFA must be used as an adjective (''CFA charterholder''), not a noun.', 2, 'mock');
INSERT INTO questions (module_id, stem, choice_a, choice_b, choice_c, correct_answer, explanation, difficulty, question_type) VALUES (26, 'An analyst is evaluating a scenario. an analyst copies a model from another firm without attribution. This violates:', 'Standard III(C) Suitability', 'Standard IV(A) Loyalty', 'Standard I(C) Misrepresentation (plagiarism)', 'C', 'Using others'' work without attribution is plagiarism.', 2, 'mock');
